// Atualiza o contador na guia mesmo fora do painel (apenas logística)
let envioBadgeTimer = null;
let envioBadgeVisibilityBound = false;

function _rolesDoUsuario() {
  const rawRoles = window.userRoles ?? window.__sessionUser?.roles ?? [];
  if (Array.isArray(rawRoles)) return rawRoles;
  return String(rawRoles || '')
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
}

function usuarioEhAdminSistema() {
  return _rolesDoUsuario().some((role) => String(role || '').trim().toLowerCase() === 'admin');
}

function _atualizarTituloEnvio() {
  if (!envioMercadoriaTabelaBodyPane) return;
  carregarSacSolicitacoes(envioMercadoriaTabelaBodyPane, { hideDone: true, titleOnly: true });
}

function _pararBadgeEnvio() {
  if (envioBadgeTimer) {
    clearInterval(envioBadgeTimer);
    envioBadgeTimer = null;
  }
  document.title = 'SGF';
}

function garantirBadgeEnvioParaLogistica() {
  if (!envioMercadoriaTabelaBodyPane) return;

  const userRoles = _rolesDoUsuario();
  const setorNome = String(window.__sessionUser?.setor || window.__sessionUser?.sector || '').toLowerCase();
  const isLogistica =
    userRoles.some(r => String(r || '').toLowerCase() === 'logistica') ||
    setorNome.includes('logist');

  if (!isLogistica) {
    _pararBadgeEnvio();
    return;
  }

  // evita múltiplos timers
  if (!envioBadgeTimer) {
    const PING_INTERVAL_MS = 15000;
    envioBadgeTimer = setInterval(_atualizarTituloEnvio, PING_INTERVAL_MS);
    setTimeout(_atualizarTituloEnvio, 200);
  }

  if (!envioBadgeVisibilityBound) {
    document.addEventListener('visibilitychange', () => {
      if (document.visibilityState === 'visible') _atualizarTituloEnvio();
    });
    envioBadgeVisibilityBound = true;
  }
}

// roda no carregamento e quando a sessão mudar
garantirBadgeEnvioParaLogistica();

// ========== BADGE DE COMPRAS NO TÍTULO DA ABA ==========
// Atualiza o contador de compras na guia (apenas usuários do departamento de compras)
let comprasBadgeTimer = null;
let comprasBadgeVisibilityBound = false;

async function _atualizarTituloCompras() {
  try {
    const resp = await fetch('/api/compras/todas', { credentials: 'include' });
    if (!resp.ok) return;
    const data = await resp.json();
    const listaCompleta = Array.isArray(data.solicitacoes) ? data.solicitacoes : [];
    
    // Conta itens por status
    const aguardandoCompra = listaCompleta.filter(item => 
      (item.status || '').toLowerCase() === 'aguardando compra'
    ).length;
    
    const aguardandoCotacao = listaCompleta.filter(item => 
      (item.status || '').toLowerCase() === 'aguardando cotação'
    ).length;
    
    const baseTitle = 'SGF';
    
    // Atualiza título apenas se houver itens pendentes
    if (aguardandoCompra > 0 || aguardandoCotacao > 0) {
      document.title = `${baseTitle} (${aguardandoCompra}) - (${aguardandoCotacao})`;
    } else {
      document.title = baseTitle;
    }
  } catch (err) {
    console.error('[COMPRAS] Erro ao atualizar título:', err);
  }
}

function _pararBadgeCompras() {
  if (comprasBadgeTimer) {
    clearInterval(comprasBadgeTimer);
    comprasBadgeTimer = null;
  }
  document.title = 'SGF';
}

function garantirBadgeComprasParaCompras() {
  const userRoles = _rolesDoUsuario();
  const setorNome = String(window.__sessionUser?.setor || window.__sessionUser?.sector || '').toLowerCase();
  const isCompras =
    userRoles.some(r => String(r || '').toLowerCase() === 'compras') ||
    setorNome.includes('compra');

  if (!isCompras) {
    _pararBadgeCompras();
    return;
  }

  // evita múltiplos timers
  if (!comprasBadgeTimer) {
    const PING_INTERVAL_MS = 15000; // atualiza a cada 15 segundos
    comprasBadgeTimer = setInterval(_atualizarTituloCompras, PING_INTERVAL_MS);
    setTimeout(_atualizarTituloCompras, 200); // atualiza imediatamente
  }

  if (!comprasBadgeVisibilityBound) {
    document.addEventListener('visibilitychange', () => {
      if (document.visibilityState === 'visible') _atualizarTituloCompras();
    });
    comprasBadgeVisibilityBound = true;
  }
}

// roda no carregamento e quando a sessão mudar
garantirBadgeComprasParaCompras();
// ========== FIM BADGE DE COMPRAS ==========

// Impressão dos anexos (etiqueta/declaração) a partir dos botões da tabela
function setupPrintButtons(container) {
  if (!container) return;
  container.addEventListener('click', (ev) => {
    const btn = ev.target.closest('.btn-print-etiqueta, .btn-print-declaracao');
    if (!btn) return;
    ev.preventDefault();
    const url = btn.getAttribute('data-print-url');
    if (!url) return;
    try {
      const w = window.open(url, '_blank');
      if (!w) return;
      setTimeout(() => {
        try { w.focus(); } catch {}
        try { w.print(); } catch {}
      }, 800);
    } catch (err) {
      console.error('[SAC] erro ao abrir para impressão', err);
    }
  });
}

setupPrintButtons(sacTabelaBody);
setupPrintButtons(envioMercadoriaTabelaBodyPane);

// Persistência de status diretamente pela tabela
document.addEventListener('focusin', (ev) => {
  const sel = ev.target.closest('.sac-status-select');
  if (sel) sel.dataset.prev = sel.value;
});

document.addEventListener('change', async (ev) => {
  const sel = ev.target.closest('.sac-status-select');
  if (!sel) return;

  const id = sel.getAttribute('data-id');
  if (!id) return;

  const novoStatus = normalizeSacStatus(sel.value);
  const anterior = sel.dataset.prev || sel.value;

  sel.disabled = true;
  sel.value = novoStatus;

  try {
    const resp = await fetch(`/api/sac/solicitacoes/${id}/status`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: novoStatus })
    });
    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || data.ok === false) throw new Error(data.error || 'Falha ao atualizar');
    sel.dataset.prev = novoStatus;

    // Se mudou para Enviado ou Finalizado, remove a linha da tabela imediatamente
    if (['Enviado', 'Finalizado'].includes(novoStatus)) {
      const row = sel.closest('tr');
      if (row) row.remove();
    }
  } catch (err) {
    console.error('[SAC] erro ao atualizar status', err);
    alert('Não foi possível atualizar o status. ' + (err?.message || ''));
    sel.value = anterior;
  } finally {
    sel.disabled = false;
  }
});

// ========== MODAL DE EDIÇÃO DE ENVIO SAC ==========
const sacEditModal = document.getElementById('sacEditModal');
const sacEditModalClose = document.getElementById('sacEditModalClose');
const sacEditCancelBtn = document.getElementById('sacEditCancelBtn');
const sacEditSaveBtn = document.getElementById('sacEditSaveBtn');
const sacEditId = document.getElementById('sacEditId');
const sacEditObservacao = document.getElementById('sacEditObservacao');
const sacEditStatus = document.getElementById('sacEditStatus');
const sacEditConteudoOriginal = document.getElementById('sacEditConteudoOriginal');
const sacEditQuantidadeContainer = document.getElementById('sacEditQuantidadeContainer');

// Função para abrir o modal de edição
function abrirModalEdicaoSAC(id, observacao, status, conteudoRaw) {
  sacEditId.value = id;
  sacEditObservacao.value = observacao === '—' ? '' : observacao;
  sacEditStatus.value = status;
  sacEditConteudoOriginal.value = conteudoRaw;
  
  // Parse do conteúdo JSON para criar os campos de quantidade
  sacEditQuantidadeContainer.innerHTML = '';
  
  if (conteudoRaw && conteudoRaw !== '—') {
    try {
      const items = JSON.parse(conteudoRaw);
      if (Array.isArray(items) && items.length > 0) {
        items.forEach((item, idx) => {
          const div = document.createElement('div');
          div.style.cssText = 'display:flex;align-items:center;gap:8px;padding:6px;border:1px solid var(--border-color);border-radius:8px;background:var(--content-bg);';
          div.innerHTML = `
            <label style="flex:1;font-size:13px;color:var(--inactive-color);">${item.conteudo}</label>
            <input type="number" min="1" class="sac-qtd-input" data-idx="${idx}" value="${item.quantidade}" style="width:80px;padding:6px;border:1px solid var(--border-color);border-radius:6px;background:var(--content-bg);color:var(--content-title-color);text-align:center;" />
          `;
          sacEditQuantidadeContainer.appendChild(div);
        });
      }
    } catch (err) {
      console.warn('[SAC] Erro ao parsear conteúdo:', err);
      sacEditQuantidadeContainer.innerHTML = '<div style="color:var(--inactive-color);font-size:13px;">Formato de conteúdo inválido para edição.</div>';
    }
  } else {
    sacEditQuantidadeContainer.innerHTML = '<div style="color:var(--inactive-color);font-size:13px;">Nenhum item disponível.</div>';
  }
  
  sacEditModal.style.display = 'flex';
}

// Função para fechar o modal de edição
function fecharModalEdicaoSAC() {
  sacEditModal.style.display = 'none';
}

// Event listeners para fechar o modal
sacEditModalClose?.addEventListener('click', fecharModalEdicaoSAC);
sacEditCancelBtn?.addEventListener('click', fecharModalEdicaoSAC);
sacEditModal?.addEventListener('click', (e) => {
  if (e.target === sacEditModal) fecharModalEdicaoSAC();
});

// Event listener para salvar as edições
sacEditSaveBtn?.addEventListener('click', async () => {
  const id = sacEditId.value;
  if (!id) return;
  
  const novaObservacao = sacEditObservacao.value.trim();
  const novoStatus = sacEditStatus.value.trim();
  const conteudoOriginalStr = sacEditConteudoOriginal.value;
  
  // Coleta as novas quantidades
  const qtdInputs = document.querySelectorAll('.sac-qtd-input');
  let novoConteudo = null;
  
  if (conteudoOriginalStr && conteudoOriginalStr !== '—') {
    try {
      const items = JSON.parse(conteudoOriginalStr);
      if (Array.isArray(items)) {
        qtdInputs.forEach(input => {
          const idx = parseInt(input.dataset.idx);
          const novaQtd = input.value.trim();
          if (items[idx]) {
            items[idx].quantidade = novaQtd;
          }
        });
        novoConteudo = JSON.stringify(items);
      }
    } catch (err) {
      console.warn('[SAC] Erro ao processar conteúdo:', err);
    }
  }
  
  sacEditSaveBtn.disabled = true;
  
  try {
    // 1. Atualizar observação
    const respObs = await fetch(`/api/sac/solicitacoes/${id}/observacao`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ observacao: novaObservacao })
    });
    if (!respObs.ok) throw new Error('Erro ao atualizar observação');
    
    // 2. Atualizar status livre
    const respStatus = await fetch(`/api/sac/solicitacoes/${id}/status-livre`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: novoStatus })
    });
    if (!respStatus.ok) throw new Error('Erro ao atualizar status');
    
    // 3. Atualizar quantidade (se houver conteúdo)
    if (novoConteudo) {
      const respQtd = await fetch(`/api/sac/solicitacoes/${id}/quantidade`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ conteudo: novoConteudo })
      });
      if (!respQtd.ok) throw new Error('Erro ao atualizar quantidade');
    }
    
    alert('Registro atualizado com sucesso!');
    fecharModalEdicaoSAC();
    
    // Recarrega a tabela
    carregarSacSolicitacoes(sacTabelaBody, { hideDone: false, filterByUser: true });
  } catch (err) {
    console.error('[SAC] Erro ao salvar edição:', err);
    alert('Não foi possível salvar as alterações. ' + (err?.message || ''));
  } finally {
    sacEditSaveBtn.disabled = false;
  }
});

// Event listener para os botões "Editar"
document.addEventListener('click', (e) => {
  const btnEditar = e.target.closest('.btn-sac-editar');
  if (btnEditar) {
    e.preventDefault();
    const id = btnEditar.dataset.id;
    const obs = btnEditar.dataset.obs.replace(/&quot;/g, '"');
    const status = btnEditar.dataset.status;
    const conteudo = btnEditar.dataset.conteudo.replace(/&quot;/g, '"');
    abrirModalEdicaoSAC(id, obs, status, conteudo);
  }
});

// Event listener para os botões "Excluir"
document.addEventListener('click', async (e) => {
  const btnExcluir = e.target.closest('.btn-sac-excluir');
  if (btnExcluir) {
    e.preventDefault();
    const id = btnExcluir.dataset.id;
    
    if (!confirm('Tem certeza que deseja excluir este registro? O status será alterado para "Excluído".')) {
      return;
    }
    
    btnExcluir.disabled = true;
    
    try {
      const resp = await fetch(`/api/sac/solicitacoes/${id}`, {
        method: 'DELETE'
      });
      const data = await resp.json().catch(() => ({}));
      
      if (!resp.ok || data.ok === false) {
        throw new Error(data.error || 'Falha ao excluir');
      }
      
      alert('Registro excluído com sucesso!');
      
      // Remove a linha da tabela
      const row = btnExcluir.closest('tr');
      if (row) row.remove();
    } catch (err) {
      console.error('[SAC] Erro ao excluir registro:', err);
      alert('Não foi possível excluir o registro. ' + (err?.message || ''));
    } finally {
      btnExcluir.disabled = false;
    }
  }
});

