// Carrega configurações existentes
async function carregarConfiguracoes() {
  const container = document.getElementById('listaConfigsResponsavel');
  if (!container) return;
  
  try {
    const resp = await fetch('/api/compras/config-responsavel-categoria');
    const data = await resp.json();
    
    if (data.ok && Array.isArray(data.configuracoes)) {
      window.configResponsavelCategoria = data.configuracoes;
      
      if (data.configuracoes.length === 0) {
        container.innerHTML = `
          <div style="text-align:center;padding:40px;color:#9ca3af;">
            <i class="fa-solid fa-cog" style="font-size:32px;opacity:0.3;display:block;margin-bottom:12px;"></i>
            Nenhuma configuração cadastrada
          </div>
        `;
      } else {
        container.innerHTML = data.configuracoes.map(config => `
          <div style="display:flex;align-items:center;justify-content:space-between;padding:12px;background:white;border:1px solid #e5e7eb;border-radius:6px;">
            <div style="display:flex;align-items:center;gap:12px;flex:1;">
              <i class="fa-solid fa-link" style="color:#3b82f6;"></i>
              <div style="flex:1;">
                <div style="font-weight:600;font-size:13px;color:#1f2937;">${window.escapeHtml(config.categoria_compra_nome)}</div>
                <div style="font-size:12px;color:#6b7280;margin-top:2px;">
                  <i class="fa-solid fa-user" style="color:#10b981;"></i>
                  ${window.escapeHtml(config.responsavel_username)}
                </div>
              </div>
            </div>
            <button class="btn-remover-config content-button" data-config-id="${config.id}" style="background:#ef4444;color:white;padding:8px 12px;" title="Remover configuração">
              <i class="fa-solid fa-trash"></i>
            </button>
          </div>
        `).join('');
        
        // Adiciona event listeners aos botões de remover usando delegação de eventos
        container.querySelectorAll('.btn-remover-config').forEach(btn => {
          btn.addEventListener('click', () => {
            const configId = parseInt(btn.dataset.configId);
            removerConfigResponsavel(configId);
          });
        });
      }
    }
  } catch (err) {
    console.error('[Config] Erro ao carregar configurações:', err);
  }
}

// Adiciona nova configuração
async function adicionarConfigResponsavel() {
  const selectCategoria = document.getElementById('configCategoriaCompra');
  const selectResponsavel = document.getElementById('configResponsavel');
  
  if (!selectCategoria || !selectResponsavel) return;
  
  const categoriaCodigo = selectCategoria.value;
  const categoriaNome = selectCategoria.selectedOptions[0]?.dataset.nome || selectCategoria.selectedOptions[0]?.text || '';
  const responsavelUsername = selectResponsavel.value;
  
  if (!categoriaCodigo || !responsavelUsername) {
    alert('Selecione a categoria e o responsável');
    return;
  }
  
  try {
    const resp = await fetch('/api/compras/config-responsavel-categoria', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        categoria_compra_codigo: categoriaCodigo,
        categoria_compra_nome: categoriaNome,
        responsavel_username: responsavelUsername
      })
    });
    
    const data = await resp.json();
    
    if (data.ok) {
      // Recarrega lista
      await carregarConfiguracoes();
      
      // Limpa campos
      selectCategoria.value = '';
      selectResponsavel.value = '';
      
      // Feedback visual
      const btn = document.getElementById('btnAdicionarConfig');
      if (btn) {
        const originalHTML = btn.innerHTML;
        btn.innerHTML = '<i class="fa-solid fa-check"></i> Salvo!';
        btn.style.background = '#10b981';
        setTimeout(() => {
          btn.innerHTML = originalHTML;
          btn.style.background = 'linear-gradient(135deg,#22c55e 0%,#16a34a 100%)';
        }, 2000);
      }
    } else {
      alert('Erro ao salvar: ' + (data.error || 'Erro desconhecido'));
    }
  } catch (err) {
    console.error('[Config] Erro ao adicionar configuração:', err);
    alert('Erro ao salvar configuração');
  }
}

// Remove configuração
async function removerConfigResponsavel(id) {
  if (!confirm('Deseja remover esta configuração?')) return;
  
  try {
    const resp = await fetch(`/api/compras/config-responsavel-categoria/${id}`, {
      method: 'DELETE'
    });
    
    const data = await resp.json();
    
    if (data.ok) {
      await carregarConfiguracoes();
    } else {
      alert('Erro ao remover: ' + (data.error || 'Erro desconhecido'));
    }
  } catch (err) {
    console.error('[Config] Erro ao remover configuração:', err);
    alert('Erro ao remover configuração');
  }
}

// Aplica responsável padrão baseado na categoria selecionada
function aplicarResponsavelPadrao() {
  const selectCategoria = document.getElementById('modalComprasCategoriaCompra');
  const selectResponsavel = document.getElementById('modalComprasResponsavelCompra');
  
  if (!selectCategoria || !selectResponsavel) return;
  
  const categoriaSelecionada = selectCategoria.value;
  
  if (!categoriaSelecionada) return;
  
  // Busca configuração para esta categoria
  const config = window.configResponsavelCategoria.find(c => c.categoria_compra_codigo === categoriaSelecionada);
  
  if (config) {
    // Aplica responsável padrão
    selectResponsavel.value = config.responsavel_username;
    console.log(`[Config] Responsável padrão aplicado: ${config.responsavel_username} para categoria ${config.categoria_compra_nome}`);
  }
}

// Expõe funções globalmente para serem acessíveis via onclick (se necessário)
window.abrirModalConfigResponsavel = abrirModalConfigResponsavel;
window.fecharModalConfigResponsavel = fecharModalConfigResponsavel;

// ========== CONFIGURAÇÃO DE ACESSO AOS BOTÕES ==========

// Carrega departamentos
async function carregarDepartamentos() {
  try {
    const resp = await fetch('/api/compras/departamentos', { credentials: 'include' });
    const data = await resp.json();
    
    if (data.ok) {
      const select = document.getElementById('configDepartamento');
      if (select) {
        const optionsHTML = '<option value="">Selecione...</option>' +
          data.departamentos.map(d => `<option value="${escapeHtml(d.nome)}">${escapeHtml(d.nome)}</option>`).join('');
        select.innerHTML = optionsHTML;
      }
    }
  } catch (err) {
    console.error('[Config] Erro ao carregar departamentos:', err);
  }
}

// Carrega permissões de acesso
async function carregarPermissoesAcesso() {
  try {
    const resp = await fetch('/api/compras/config-acesso-botoes', { credentials: 'include' });
    const data = await resp.json();
    
    if (data.ok) {
      window.permissoesAcessoBotoes = data.permissoes || [];
      renderizarListaPermissoes();
    }
  } catch (err) {
    console.error('[Config] Erro ao carregar permissões:', err);
  }
}

// Renderiza lista de permissões
function renderizarListaPermissoes() {
  const lista = document.getElementById('listaPermissoesAcesso');
  if (!lista) return;
  
  const permissoes = window.permissoesAcessoBotoes || [];
  
  if (permissoes.length === 0) {
    lista.innerHTML = `
      <div style="text-align:center;padding:40px;color:#9ca3af;">
        <i class="fa-solid fa-shield-halved" style="font-size:32px;opacity:0.3;display:block;margin-bottom:12px;"></i>
        Nenhuma permissão cadastrada
      </div>`;
    return;
  }
  
  lista.innerHTML = permissoes.map(p => {
    const tipoBotaoLabel = p.tipo_botao === 'aprovacao' ? 'Aprovação' : 'Pedido de Compra';
    const corBotao = p.tipo_botao === 'aprovacao' ? '#9333ea' : '#10b981';
    
    return `
      <div style="
        background:white;
        padding:16px;
        border-radius:6px;
        border:1px solid #e5e7eb;
        display:grid;
        grid-template-columns:150px 1fr 1fr auto;
        gap:16px;
        align-items:center;
      ">
        <div style="display:flex;align-items:center;gap:8px;">
          <div style="width:4px;height:40px;background:${corBotao};border-radius:4px;"></div>
          <div>
            <div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:0.5px;font-weight:600;">Tipo</div>
            <div style="font-size:13px;color:#1f2937;font-weight:700;">${tipoBotaoLabel}</div>
          </div>
        </div>
        <div>
          <div style="font-size:11px;color:#6b7280;margin-bottom:2px;">Responsável</div>
          <div style="font-size:13px;color:#1f2937;font-weight:600;">${escapeHtml(p.responsavel_username)}</div>
        </div>
        <div>
          <div style="font-size:11px;color:#6b7280;margin-bottom:2px;">Departamento</div>
          <div style="font-size:13px;color:#1f2937;font-weight:600;">${escapeHtml(p.departamento_nome)}</div>
        </div>
        <button 
          onclick="removerPermissaoAcesso(${p.id})"
          style="
            background:#ef4444;
            color:white;
            border:none;
            padding:8px 12px;
            border-radius:6px;
            cursor:pointer;
            font-size:12px;
            transition:all 0.2s;
          "
          onmouseover="this.style.background='#dc2626'"
          onmouseout="this.style.background='#ef4444'">
          <i class="fa-solid fa-trash"></i>
        </button>
      </div>
    `;
  }).join('');
}

// Adiciona nova permissão
async function adicionarPermissaoAcesso() {
  const selectTipo = document.getElementById('configTipoBotao');
  const selectResponsavel = document.getElementById('configResponsavelBotao');
  const selectDepartamento = document.getElementById('configDepartamento');
  
  const tipo = selectTipo?.value;
  const responsavel = selectResponsavel?.value;
  const departamento = selectDepartamento?.value;
  
  if (!tipo || !responsavel || !departamento) {
    alert('Preencha todos os campos');
    return;
  }
  
  try {
    const resp = await fetch('/api/compras/config-acesso-botoes', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        tipo_botao: tipo,
        responsavel_username: responsavel,
        departamento_nome: departamento
      })
    });
    
    const data = await resp.json();
    
    if (data.ok) {
      await carregarPermissoesAcesso();
      
      // Limpa campos
      selectTipo.value = '';
      selectResponsavel.value = '';
      selectDepartamento.value = '';
      
      // Feedback
      const btn = document.getElementById('btnAdicionarPermissao');
      if (btn) {
        const originalHTML = btn.innerHTML;
        btn.innerHTML = '<i class="fa-solid fa-check"></i> Salvo!';
        btn.style.background = '#10b981';
        setTimeout(() => {
          btn.innerHTML = originalHTML;
          btn.style.background = 'linear-gradient(135deg,#3b82f6 0%,#2563eb 100%)';
        }, 2000);
      }
    } else {
      alert('Erro ao salvar: ' + (data.error || 'Erro desconhecido'));
    }
  } catch (err) {
    console.error('[Config] Erro ao adicionar permissão:', err);
    alert('Erro ao salvar permissão');
  }
}

// Remove permissão
async function removerPermissaoAcesso(id) {
  if (!confirm('Deseja remover esta permissão?')) return;
  
  try {
    const resp = await fetch(`/api/compras/config-acesso-botoes/${id}`, {
      method: 'DELETE'
    });
    
    const data = await resp.json();
    
    if (data.ok) {
      await carregarPermissoesAcesso();
    } else {
      alert('Erro ao remover: ' + (data.error || 'Erro desconhecido'));
    }
  } catch (err) {
    console.error('[Config] Erro ao remover permissão:', err);
    alert('Erro ao remover permissão');
  }
}

