// Controla exibição dos campos condicionais baseado em "Possui cadastro na Omie?"
function toggleCamposCatalogoOmie() {
  console.log('[Catálogo] toggleCamposCatalogoOmie() CHAMADA');
  
  const selectCadastro = document.getElementById('catalogoPossuiCadastroOmie');
  const campoDescricao = document.getElementById('catalogoCampoDescricao');
  const campoQuantidade = document.getElementById('catalogoCampoQuantidade');
  const secaoFiltros = document.getElementById('catalogoSecaoFiltros');
  const botaoAdicionar = document.getElementById('catalogoBotaoAdicionarNaoCadastrado');
  
  console.log('[Catálogo] selectCadastro:', selectCadastro);
  console.log('[Catálogo] selectCadastro.value:', selectCadastro?.value);
  console.log('[Catálogo] campoDescricao:', campoDescricao);
  console.log('[Catálogo] campoQuantidade:', campoQuantidade);
  console.log('[Catálogo] secaoFiltros:', secaoFiltros);
  console.log('[Catálogo] botaoAdicionar:', botaoAdicionar);
  
  if (!selectCadastro || !campoDescricao) {
    console.log('[Catálogo] ERRO: Elementos não encontrados!');
    return;
  }
  
  if (selectCadastro.value === 'nao') {
    // Mostra campo de descrição
    campoDescricao.style.display = 'block';
    
    // Mostra campo de quantidade
    if (campoQuantidade) {
      campoQuantidade.style.display = 'block';
    }
    
    // Mostra botão de adicionar ao carrinho
    if (botaoAdicionar) {
      botaoAdicionar.style.display = 'block';
    }
    
    // Oculta seção de filtros
    if (secaoFiltros) {
      secaoFiltros.style.display = 'none';
    }
    
    // Adiciona foco no campo de descrição
    const descricao = document.getElementById('catalogoDescricaoNaoCadastrado');
    if (descricao) {
      setTimeout(() => {
        descricao.focus();
      }, 100);
    }
    
    // Limpa lista de produtos (não precisa carregar para produtos não cadastrados)
    const lista = document.getElementById('listaProdutosCatalogo');
    if (lista) {
      lista.innerHTML = '';
    }
    
    console.log('[Catálogo] Campo descrição: VISÍVEL + Quantidade: VISÍVEL + Botão: VISÍVEL + Filtros: OCULTOS + Lista produtos: OCULTA');
  } else {
    // Oculta campo de descrição
    campoDescricao.style.display = 'none';
    
    // Oculta campo de quantidade
    if (campoQuantidade) {
      campoQuantidade.style.display = 'none';
    }
    
    // Oculta botão de adicionar ao carrinho
    if (botaoAdicionar) {
      botaoAdicionar.style.display = 'none';
    }
    
    // Mostra seção de filtros
    if (secaoFiltros) {
      secaoFiltros.style.display = 'block';
    }
    
    // Limpa campo ao ocultar
    const descricao = document.getElementById('catalogoDescricaoNaoCadastrado');
    if (descricao) descricao.value = '';
    
    // Carrega produtos do catálogo Omie
    carregarProdutosCatalogoOmie();
    
    console.log('[Catálogo] Campo descrição: OCULTO + Quantidade: OCULTO + Botão: OCULTO + Filtros: VISÍVEIS + Carregando produtos...');
  }
}

// Carrega produtos do catálogo Omie (chamada quando usuário seleciona "Sim")
async function carregarProdutosCatalogoOmie() {
  const lista = document.getElementById('listaProdutosCatalogo');
  if (!lista) return;
  
  lista.innerHTML = '<div style="text-align:center;padding:40px;"><i class="fa-solid fa-spinner fa-spin" style="font-size:32px;color:#3b82f6;"></i><br><br>Carregando catálogo...</div>';
  
  try {
    const respProdutos = await fetch('/api/compras/catalogo-omie', { credentials: 'include' });
    
    if (!respProdutos.ok) throw new Error('Erro ao carregar catálogo');
    
    const data = await respProdutos.json();
    window.produtosCatalogoOmie = data.produtos || [];
    
    // Popula select de famílias
    const selectFamilia = document.getElementById('catalogoFamilia');
    if (selectFamilia) {
      const familias = [...new Set(window.produtosCatalogoOmie.map(p => p.descricao_familia).filter(f => f))].sort();
      selectFamilia.innerHTML = '<option value="">Todas as Famílias</option>' + 
        familias.map(f => `<option value="${escapeHtml(f)}">${escapeHtml(f)}</option>`).join('');
    }
    
    // Renderiza produtos
    renderizarCatalogoOmie(window.produtosCatalogoOmie);
    
    console.log('[Catálogo] Produtos carregados:', window.produtosCatalogoOmie.length);
    
  } catch (err) {
    console.error('[Catálogo] Erro ao carregar produtos:', err);
    lista.innerHTML = '<div style="text-align:center;padding:40px;color:#ef4444;">Erro ao carregar catálogo de produtos</div>';
  }
}

// Gerencia mudança de anexo no catálogo (acumula múltiplos arquivos)
function handleCatalogoAnexoChange(input) {
  if (!input || !input.files || input.files.length === 0) return;
  
  const preview = document.getElementById('catalogoAnexoPreview');
  const label = document.getElementById('catalogoAnexoLabel');
  
  if (!preview || !label) return;
  
  // Inicializa array se não existir
  if (!window.catalogoAnexosAcumulados) {
    window.catalogoAnexosAcumulados = [];
  }
  
  // Valida e ACUMULA cada arquivo novo
  let novosAdicionados = 0;
  for (let i = 0; i < input.files.length; i++) {
    const file = input.files[i];
    
    // Valida tamanho (máximo 5MB por arquivo)
    if (file.size > 5 * 1024 * 1024) {
      alert(`Arquivo "${file.name}" muito grande! Tamanho máximo: 5MB por arquivo.`);
      continue;
    }
    
    // Verifica se arquivo já existe na lista (por nome e tamanho)
    const jaExiste = window.catalogoAnexosAcumulados.some(
      f => f.name === file.name && f.size === file.size
    );
    
    if (jaExiste) {
      console.log(`[Catálogo] Arquivo "${file.name}" já está na lista, ignorando...`);
      continue;
    }
    
    // ACUMULA o arquivo
    window.catalogoAnexosAcumulados.push(file);
    novosAdicionados++;
  }
  
  // Limpa o input (para permitir selecionar o mesmo arquivo novamente se necessário)
  input.value = '';
  
  if (novosAdicionados === 0 && window.catalogoAnexosAcumulados.length === 0) {
    return;
  }
  
  // Monta HTML da lista de arquivos ACUMULADOS
  const listaHTML = window.catalogoAnexosAcumulados.map((file, index) => {
    // Define ícone baseado no tipo
    let iconClass = 'fa-file';
    let iconColor = '#10b981';
    if (file.type.startsWith('image/')) {
      iconClass = 'fa-file-image';
      iconColor = '#3b82f6';
    } else if (file.type === 'application/pdf') {
      iconClass = 'fa-file-pdf';
      iconColor = '#ef4444';
    } else if (file.type.includes('excel') || file.type.includes('spreadsheet')) {
      iconClass = 'fa-file-excel';
      iconColor = '#10b981';
    }
    
    const tamanhoMB = (file.size / 1024 / 1024).toFixed(2);
    
    return `
      <div style="display:flex;align-items:center;justify-content:space-between;padding:8px;background:white;border:2px solid ${iconColor};border-radius:6px;margin-bottom:6px;">
        <div style="display:flex;align-items:center;gap:8px;flex:1;">
          <i class="fa-solid ${iconClass}" style="color:${iconColor};font-size:16px;"></i>
          <div style="flex:1;">
            <div style="font-size:12px;font-weight:600;color:#065f46;">${escapeHtml(file.name)}</div>
            <div style="font-size:10px;color:#6b7280;">${tamanhoMB} MB</div>
          </div>
        </div>
        <button 
          type="button"
          onclick="removerCatalogoAnexoIndividual(${index})"
          style="background:#ef4444;color:white;border:none;padding:4px 8px;border-radius:4px;cursor:pointer;font-size:11px;">
          <i class="fa-solid fa-trash"></i>
        </button>
      </div>
    `;
  }).join('');
  
  preview.innerHTML = listaHTML + `
    <button 
      type="button"
      onclick="removerCatalogoAnexo()"
      style="width:100%;padding:8px;background:#ef4444;color:white;border:none;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;margin-top:4px;">
      <i class="fa-solid fa-trash"></i> Remover Todos
    </button>
  `;
  
  preview.style.display = 'block';
  label.textContent = `${window.catalogoAnexosAcumulados.length} arquivo(s) selecionado(s)`;
  
  if (novosAdicionados > 0) {
    console.log(`[Catálogo] ${novosAdicionados} novo(s) arquivo(s) adicionado(s). Total: ${window.catalogoAnexosAcumulados.length}`);
  }
}

// Gerencia links no catálogo (cache em memória e renderização)
function handleCatalogoLinkKeydown(event) {
  if (event.key !== 'Enter') return;
  event.preventDefault();

  const input = event.target;
  if (!input) return;

  const valor = String(input.value || '').trim();
  if (!valor) return;

  if (!window.catalogoLinksAcumulados) {
    window.catalogoLinksAcumulados = [];
  }

  // Evita duplicidade
  if (window.catalogoLinksAcumulados.includes(valor)) {
    input.value = '';
    return;
  }

  window.catalogoLinksAcumulados.push(valor);
  input.value = '';
  renderizarCatalogoLinks();
}

function removerCatalogoLink(index) {
  if (!window.catalogoLinksAcumulados || index < 0 || index >= window.catalogoLinksAcumulados.length) return;
  window.catalogoLinksAcumulados.splice(index, 1);
  renderizarCatalogoLinks();
}

function renderizarCatalogoLinks() {
  const preview = document.getElementById('catalogoLinkPreview');
  if (!preview) return;

  const links = window.catalogoLinksAcumulados || [];
  if (links.length === 0) {
    preview.style.display = 'none';
    preview.innerHTML = '';
    return;
  }

  const listaHTML = links.map((link, index) => {
    const linkSeguro = escapeHtml(link);
    return `
      <div style="display:flex;align-items:center;justify-content:space-between;padding:8px;background:white;border:2px solid #3b82f6;border-radius:6px;margin-bottom:6px;">
        <div style="display:flex;align-items:center;gap:8px;flex:1;min-width:0;">
          <i class="fa-solid fa-link" style="color:#3b82f6;font-size:16px;"></i>
          <div style="flex:1;min-width:0;">
            <div style="font-size:12px;font-weight:600;color:#1e3a8a;word-break:break-all;">${linkSeguro}</div>
          </div>
        </div>
        <button 
          type="button"
          onclick="removerCatalogoLink(${index})"
          style="background:#ef4444;color:white;border:none;padding:4px 8px;border-radius:4px;cursor:pointer;font-size:11px;">
          <i class="fa-solid fa-trash"></i>
        </button>
      </div>
    `;
  }).join('');

  preview.innerHTML = listaHTML;
  preview.style.display = 'block';
}

// Remove todos os anexos do catálogo
function removerCatalogoAnexo() {
  const input = document.getElementById('catalogoAnexo');
  const preview = document.getElementById('catalogoAnexoPreview');
  const label = document.getElementById('catalogoAnexoLabel');
  
  // Limpa array acumulado
  window.catalogoAnexosAcumulados = [];
  
  if (input) input.value = '';
  if (preview) {
    preview.style.display = 'none';
    preview.innerHTML = '';
  }
  if (label) label.textContent = 'Clique para selecionar arquivos';
  
  console.log('[Catálogo] Todos os anexos removidos');
}

// Remove anexo individual do catálogo (do array acumulado)
function removerCatalogoAnexoIndividual(index) {
  if (!window.catalogoAnexosAcumulados || index < 0 || index >= window.catalogoAnexosAcumulados.length) {
    return;
  }
  
  const arquivoRemovido = window.catalogoAnexosAcumulados[index].name;
  
  // Remove do array
  window.catalogoAnexosAcumulados.splice(index, 1);
  
  console.log(`[Catálogo] Anexo "${arquivoRemovido}" removido. Restam: ${window.catalogoAnexosAcumulados.length}`);
  
  // Atualiza preview
  if (window.catalogoAnexosAcumulados.length > 0) {
    // Re-renderiza a lista
    const input = document.getElementById('catalogoAnexo');
    if (input) {
      // Força atualização do preview sem adicionar novos arquivos
      const preview = document.getElementById('catalogoAnexoPreview');
      const label = document.getElementById('catalogoAnexoLabel');
      
      if (preview && label) {
        const listaHTML = window.catalogoAnexosAcumulados.map((file, idx) => {
          let iconClass = 'fa-file';
          let iconColor = '#10b981';
          if (file.type.startsWith('image/')) {
            iconClass = 'fa-file-image';
            iconColor = '#3b82f6';
          } else if (file.type === 'application/pdf') {
            iconClass = 'fa-file-pdf';
            iconColor = '#ef4444';
          } else if (file.type.includes('excel') || file.type.includes('spreadsheet')) {
            iconClass = 'fa-file-excel';
            iconColor = '#10b981';
          }
          
          const tamanhoMB = (file.size / 1024 / 1024).toFixed(2);
          
          return `
            <div style="display:flex;align-items:center;justify-content:space-between;padding:8px;background:white;border:2px solid ${iconColor};border-radius:6px;margin-bottom:6px;">
              <div style="display:flex;align-items:center;gap:8px;flex:1;">
                <i class="fa-solid ${iconClass}" style="color:${iconColor};font-size:16px;"></i>
                <div style="flex:1;">
                  <div style="font-size:12px;font-weight:600;color:#065f46;">${escapeHtml(file.name)}</div>
                  <div style="font-size:10px;color:#6b7280;">${tamanhoMB} MB</div>
                </div>
              </div>
              <button 
                type="button"
                onclick="removerCatalogoAnexoIndividual(${idx})"
                style="background:#ef4444;color:white;border:none;padding:4px 8px;border-radius:4px;cursor:pointer;font-size:11px;">
                <i class="fa-solid fa-trash"></i>
              </button>
            </div>
          `;
        }).join('');
        
        preview.innerHTML = listaHTML + `
          <button 
            type="button"
            onclick="removerCatalogoAnexo()"
            style="width:100%;padding:8px;background:#ef4444;color:white;border:none;border-radius:6px;cursor:pointer;font-size:12px;font-weight:600;margin-top:4px;">
            <i class="fa-solid fa-trash"></i> Remover Todos
          </button>
        `;
        
        label.textContent = `${window.catalogoAnexosAcumulados.length} arquivo(s) selecionado(s)`;
      }
    }
  } else {
    removerCatalogoAnexo();
  }
}

// Função para validar interação entre Requisição Direta e Não incluir quantidade
function inicializarValidacaoCatalogoCheckboxes() {
  const checkboxRequisicaoDireta = document.getElementById('catalogoRequisicaoDiretaGlobal');
  const checkboxNaoIncluirQuantidade = document.getElementById('catalogoNaoIncluirQuantidade');
  const labelNaoIncluirQuantidade = document.getElementById('labelNaoIncluirQuantidade');
  
  if (!checkboxRequisicaoDireta || !checkboxNaoIncluirQuantidade) return;
  
  // Event listener para Requisição Direta
  checkboxRequisicaoDireta.addEventListener('change', function() {
    if (this.checked) {
      // Se marcar Requisição Direta, desabilita e desmarca Não incluir quantidade
      checkboxNaoIncluirQuantidade.disabled = true;
      checkboxNaoIncluirQuantidade.checked = false;
      labelNaoIncluirQuantidade.style.opacity = '0.5';
      labelNaoIncluirQuantidade.style.cursor = 'not-allowed';
      labelNaoIncluirQuantidade.style.pointerEvents = 'none';
      console.log('[Catálogo] Requisição Direta ativada - Não incluir quantidade desabilitada');
    } else {
      // Se desmarcar Requisição Direta, habilita Não incluir quantidade
      checkboxNaoIncluirQuantidade.disabled = false;
      labelNaoIncluirQuantidade.style.opacity = '1';
      labelNaoIncluirQuantidade.style.cursor = 'pointer';
      labelNaoIncluirQuantidade.style.pointerEvents = 'auto';
      console.log('[Catálogo] Requisição Direta desativada - Não incluir quantidade habilitada');
    }
  });
  
  // Inicializa estado inicial baseado em Requisição Direta
  if (checkboxRequisicaoDireta.checked) {
    checkboxNaoIncluirQuantidade.disabled = true;
    checkboxNaoIncluirQuantidade.checked = false;
    labelNaoIncluirQuantidade.style.opacity = '0.5';
    labelNaoIncluirQuantidade.style.cursor = 'not-allowed';
    labelNaoIncluirQuantidade.style.pointerEvents = 'none';
  }
}

// Renderiza produtos do catálogo
function renderizarCatalogoOmie(produtos, options = {}) {
  const {
    containerId = 'listaProdutosCatalogo',
    atualizarContador = true,
    append = false
  } = options;

  const lista = document.getElementById(containerId);
  if (!lista) return;
  
  // Atualiza contador de produtos exibidos (apenas no modal)
  if (atualizarContador) {
    const contadorProdutos = document.getElementById('catalogoTotalProdutos');
    if (contadorProdutos) {
      contadorProdutos.textContent = produtos.length;
    }
  }
  
  if (produtos.length === 0) {
    if (!append) {
      lista.innerHTML = '<div style="text-align:center;padding:40px;color:#9ca3af;grid-column:1/-1;">Nenhum produto encontrado</div>';
    }
    return;
  }
  
  const html = produtos.map(produto => {
    // Valida se a URL da imagem é válida
    const temImagem = produto.url_imagem && 
                      produto.url_imagem.trim() && 
                      (produto.url_imagem.startsWith('http://') || produto.url_imagem.startsWith('https://'));
    
    // Verifica se URL está expirada (parâmetro Expires)
    let urlExpirada = false;
    if (temImagem && produto.url_imagem.includes('Expires=')) {
      const match = produto.url_imagem.match(/Expires=(\d+)/);
      if (match) {
        const expiresTimestamp = parseInt(match[1]);
        const agora = Math.floor(Date.now() / 1000);
        urlExpirada = expiresTimestamp < agora;
      }
    }
    
    // Prepara string para onclick ANTES de stringify
    const infoProdutoTexto = `${produto.codigo} - ${produto.descricao || ''}`;
    
    const imgHtml = temImagem && !urlExpirada ? 
      `<img 
        src="${produto.url_imagem}" 
        alt="${escapeHtml(produto.descricao)}"
        style="max-width:100%;max-height:100%;object-fit:contain;cursor:zoom-in;transition:transform 0.2s;"
        onclick='ampliarImagemProduto(${JSON.stringify(produto.url_imagem || '')}, ${JSON.stringify(infoProdutoTexto)});event.stopPropagation();'
        onmouseover="this.style.transform='scale(1.05)'"
        onmouseout="this.style.transform='scale(1)'"
        onerror="this.style.display='none';this.nextElementSibling.style.display='flex'"
      />
      <div style="display:none;width:100%;height:100%;align-items:center;justify-content:center;color:#9ca3af;">
        <i class="fa-solid fa-image" style="font-size:48px;"></i>
      </div>` :
      urlExpirada ? 
      `<div 
        id="img-expirada-${produto.codigo_produto}" 
        data-codigo-produto="${produto.codigo_produto}"
        data-codigo="${escapeHtml(produto.codigo)}"
        data-descricao="${escapeHtml(produto.descricao)}"
        style="display:flex;width:100%;height:100%;align-items:center;justify-content:center;color:#f59e0b;flex-direction:column;gap:8px;" 
        title="Atualizando imagem...">
        <i class="fa-solid fa-rotate fa-spin" style="font-size:32px;"></i>
        <span style="font-size:10px;text-align:center;">Atualizando...</span>
      </div>` :
      `<div style="display:flex;width:100%;height:100%;align-items:center;justify-content:center;color:#9ca3af;">
        <i class="fa-solid fa-image" style="font-size:48px;"></i>
      </div>`;
    
    return `
      <div style="
        background:white;
        border:1px solid #e5e7eb;
        border-radius:8px;
        overflow:hidden;
        transition:all 0.2s;
        cursor:pointer;
        display:flex;
        flex-direction:column;
      " 
      onmouseover="this.style.boxShadow='0 4px 12px rgba(0,0,0,0.1)';this.style.transform='translateY(-2px)'"
      onmouseout="this.style.boxShadow='none';this.style.transform='translateY(0)'">
        
        <!-- Imagem -->
        <div style="
          width:100%;
          height:140px;
          background:#f9fafb;
          display:flex;
          align-items:center;
          justify-content:center;
          overflow:hidden;
          position:relative;
        ">
          ${imgHtml}
        </div>
        
        <!-- Informações -->
        <div style="padding:10px;flex:1;display:flex;flex-direction:column;">
          <div style="font-size:12px;font-weight:700;color:#1f2937;margin-bottom:3px;">
            ${escapeHtml(produto.codigo)}
          </div>
          <div style="font-size:10px;font-weight:400;color:#4b5563;margin-bottom:6px;line-height:1.3;min-height:32px;">
            ${escapeHtml(produto.descricao)}
          </div>
          <div id="estoque-card-${escapeHtml(produto.codigo)}" data-codigo="${escapeHtml(produto.codigo)}" style="margin-bottom:6px;min-height:14px;"></div>
          
          <!-- Badges: Família e Estoque -->
          <div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:8px;">
            ${produto.descricao_familia ? `
            <span style="background:#dbeafe;color:#1e40af;padding:3px 6px;border-radius:4px;font-size:9px;font-weight:600;">
              ${escapeHtml(produto.descricao_familia)}
            </span>
            ` : ''}
            <span id="min-badge-${escapeHtml(produto.codigo)}" data-codigo="${escapeHtml(produto.codigo)}"></span>
            ${produto.abaixo_minimo ? `
            <span style="background:#fef3c7;color:#92400e;padding:3px 6px;border-radius:4px;font-size:9px;font-weight:600;display:flex;align-items:center;gap:3px;" title="Estoque: ${produto.saldo_estoque} | Mínimo: ${produto.estoque_minimo}">
              <i class="fa-solid fa-triangle-exclamation" style="font-size:8px;"></i>
              Est. ${Math.round(produto.saldo_estoque)}/${Math.round(produto.estoque_minimo)}
            </span>
            ` : ''}
          </div>
          
          <!-- Linha com Editar, Quantidade, Prazo e Carrinho -->
          <div style="margin-top:auto;display:flex;flex-wrap:wrap;gap:6px;align-items:stretch;">
            <!-- Botão Editar -->
            <button 
              onclick="abrirModalEditarProduto('${produto.codigo}')" 
              title="Editar produto"
              style="
                width:32px;
                background:#fef3c7;
                color:#d97706;
                border:1px solid #fbbf24;
                padding:6px;
                border-radius:4px;
                cursor:pointer;
                font-size:14px;
                display:flex;
                align-items:center;
                justify-content:center;
                flex-shrink:0;
              "
              onmouseover="this.style.background='#fde68a'"
              onmouseout="this.style.background='#fef3c7'">
              <i class="fa-solid fa-pencil"></i>
            </button>

            <!-- Botão Últimas Compras -->
            <button 
              onclick="event.stopPropagation();abrirModalUltimasCompras('${produto.codigo_produto}', '${escapeHtml(produto.codigo)}', '${escapeHtml(produto.descricao.replace(/'/g, "\\'"))}')"
              title="Últimas compras"
              style="
                width:32px;
                background:#ede9fe;
                color:#7c3aed;
                border:1px solid #c4b5fd;
                padding:6px;
                border-radius:4px;
                cursor:pointer;
                font-size:14px;
                display:flex;
                align-items:center;
                justify-content:center;
                flex-shrink:0;
              "
              onmouseover="this.style.background='#ddd6fe'"
              onmouseout="this.style.background='#ede9fe'">
              <i class="fa-solid fa-receipt"></i>
            </button>

            <!-- Campo Quantidade -->
            <input 
              type="number" 
              id="catalogo-qtd-${produto.codigo}" 
              min="1" 
              value="1" 
              title="Quantidade"
              placeholder="Qtd"
              style="width:50px;padding:6px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;text-align:center;"
            />
            
            <!-- Botão Adicionar ao Carrinho -->
            <button 
              onclick="selecionarProdutoCatalogo('${produto.codigo}', '${escapeHtml(produto.descricao.replace(/'/g, "\\'"))}', event)"
              title="Adicionar ao carrinho"
              style="
                flex:1;
                min-width:32px;
                background:linear-gradient(135deg,#10b981 0%,#059669 100%);
                color:white;
                border:none;
                padding:6px;
                border-radius:4px;
                cursor:pointer;
                font-size:16px;
                display:flex;
                align-items:center;
                justify-content:center;
              "
              onmouseover="this.style.transform='scale(1.02)'"
              onmouseout="this.style.transform='scale(1)'">
              <i class="fa-solid fa-cart-plus"></i>
            </button>

            <!-- Botão Adicionar à Separação -->
            <button
              onclick="event.stopPropagation();abrirModalSeparacaoQtd('${produto.codigo}', '${escapeHtml(produto.descricao.replace(/'/g, "\\'"))}', '${escapeHtml((produto.unidade || 'UN').replace(/'/g, "\\'"))}')"
              title="Adicionar à separação"
              style="
                flex-shrink:0;
                background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);
                color:#1a1200;
                border:none;
                padding:6px 9px;
                border-radius:4px;
                cursor:pointer;
                font-size:15px;
                display:flex;
                align-items:center;
                justify-content:center;
              "
              onmouseover="this.style.transform='scale(1.02)'"
              onmouseout="this.style.transform='scale(1)'">
              <i class="fa-solid fa-clipboard-plus"></i>
            </button>

            <!-- Botão Movimentar Estoque -->
            <button 
              onclick="abrirModalMovimentacao('${produto.codigo}', '${escapeHtml(produto.descricao.replace(/'/g, "\\'"))}')"
              title="Movimentar estoque"
              style="
                flex-shrink:0;
                background:linear-gradient(135deg,#6366f1 0%,#4f46e5 100%);
                color:white;
                border:none;
                padding:6px 10px;
                border-radius:4px;
                cursor:pointer;
                font-size:16px;
                display:flex;
                align-items:center;
                justify-content:center;
              "
              onmouseover="this.style.transform='scale(1.02)'"
              onmouseout="this.style.transform='scale(1)'">
              <i class="fa-solid fa-arrows-rotate"></i>
            </button>
          </div>
          
          <!-- Campo Prazo (inicialmente oculto, linha separada abaixo) -->
          <div id="catalogo-prazo-container-${produto.codigo}" style="display:none;margin-top:6px;">
            <input 
              type="date" 
              id="catalogo-prazo-${produto.codigo}" 
              placeholder="Prazo de entrega"
              style="width:100%;padding:6px;border:1px solid #10b981;border-radius:4px;font-size:10px;background:#f0fdf4;"
            />
          </div>
        </div>
      </div>
    `;
  }).join('');

  if (append) {
    lista.insertAdjacentHTML('beforeend', html);
  } else {
    lista.innerHTML = html;
  }
  
  // Atualiza automaticamente todas as imagens expiradas em lote
  setTimeout(() => atualizarImagensExpiradasEmLote(), 100);

  // Carrega estoque por local para os cards
  setTimeout(() => carregarEstoqueCards(), 200);
}

// Carrega estoque por local para todos os cards visíveis
async function carregarEstoqueCards() {
  const placeholders = document.querySelectorAll('[id^="estoque-card-"]');
  if (!placeholders.length) return;

  const codigos = Array.from(placeholders).map(el => el.dataset.codigo).filter(Boolean);
  if (!codigos.length) return;

  try {
    const resp = await fetch('/api/logistica/estoque/batch?codigos=' + encodeURIComponent(codigos.join(',')));
    if (!resp.ok) return;
    const { dados, minimos } = await resp.json();

    placeholders.forEach(el => {
      const cod = el.dataset.codigo;
      const locais = dados[cod];
      if (!locais || locais.length === 0) {
        el.innerHTML = '<span style="font-size:9px;color:#9ca3af;">Sem estoque</span>';
        return;
      }
      el.innerHTML = locais.map(l =>
        `<div style="display:flex;justify-content:space-between;font-size:9px;color:#374151;line-height:1.4;">
          <span style="color:#6b7280;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:70%;">${l.local_nome || l.local_codigo}</span>
          <span style="font-weight:600;white-space:nowrap;">${Number(l.saldo).toLocaleString('pt-BR', {minimumFractionDigits:0, maximumFractionDigits:2})}${l.unidade ? ' ' + l.unidade : ''}</span>
        </div>`
      ).join('');
    });

    // Preenche badges de mínimo
    if (minimos) {
      document.querySelectorAll('[id^="min-badge-"]').forEach(badge => {
        const cod = badge.dataset.codigo;
        const info = minimos[cod];
        if (!info || info.min <= 0) return;
        const cor = info.abaixo ? '#dc2626' : '#16a34a';
        const bg  = info.abaixo ? '#fee2e2'  : '#dcfce7';
        badge.innerHTML = `<span style="background:${bg};color:${cor};padding:3px 6px;border-radius:4px;font-size:9px;font-weight:600;">Min. ${Number(info.min).toLocaleString('pt-BR', {minimumFractionDigits:0, maximumFractionDigits:2})}</span>`;
      });
    }
  } catch (e) {
    // silencia erros de rede
  }
}

// Disponibiliza para uso externo (ex.: lista de produtos)
window.renderizarCatalogoOmie = renderizarCatalogoOmie;

// ===================== MODAL SEPARAÇÃO =====================
(function() {
  let _sepCtx = null;

  // Cria o modal diretamente como filho de <body> para position:fixed funcionar
  // independente de transforms/backdrop-filter em containers pais
  const ov = document.createElement('div');
  ov.id = 'modalSeparacaoQtd';
  ov.style.cssText = 'display:none;position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.75);z-index:99999;align-items:center;justify-content:center;padding:16px;';
  ov.innerHTML = `
    <div style="width:min(420px,95%);background:#1c1c1c;border-radius:16px;padding:20px;box-shadow:0 18px 48px rgba(0,0,0,.55);display:flex;flex-direction:column;gap:14px;">
      <h3 id="sepQtyTitle" style="margin:0;font-size:1.05rem;color:#f0f0f0;">Quantidade para separação</h3>
      <div id="sepQtyProd" style="font-weight:700;font-size:.95rem;color:#e5e7eb;"></div>
      <div id="sepQtyUnit" style="display:inline-block;padding:10px 12px;border-radius:12px;background:#2a1b00;border:1px solid #ffb400;color:#ffda7a;font-weight:800;font-size:1.05rem;letter-spacing:.03em;"></div>
      <input id="sepQtyInput" type="number" min="0.001" step="0.001" value="1" style="width:100%;padding:12px;border:none;border-radius:12px;background:#2a2a2a;color:#fff;font-size:1rem;box-sizing:border-box;" />
      <div style="display:flex;gap:10px;">
        <button id="sepQtyCancel" type="button" style="flex:1;border:none;border-radius:12px;padding:12px;font-weight:700;cursor:pointer;background:#2a2a2a;color:#fff;font-size:14px;">Cancelar</button>
        <button id="sepQtyOk" type="button" style="flex:1;border:none;border-radius:12px;padding:12px;font-weight:700;cursor:pointer;background:#f59e0b;color:#1a1200;font-size:14px;">Confirmar</button>
      </div>
    </div>
  `;
  document.body.appendChild(ov);

  function fechar() {
    ov.style.display = 'none';
    _sepCtx = null;
  }

  async function confirmar() {
    if (!_sepCtx) return;
    const input = document.getElementById('sepQtyInput');
    const qty = Number(String(input?.value || '').replace(',', '.'));
    if (!Number.isFinite(qty) || qty <= 0) { input?.focus({ preventScroll: true }); return; }
    const { codigo, descricao, unidade } = _sepCtx;
    fechar();
    try {
      const resp = await fetch('/api/logistica/separacao', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ codigo, descricao, quantidade: qty, unidade })
      });
      const data = await resp.json();
      if (!data.ok) {
        alert('Erro ao registrar separação: ' + (data.error || 'tente novamente.'));
      } else {
        // Atualiza badge do botão de separações
        const badge = document.getElementById('listaSeparacaoCount');
        if (badge) {
          const atual = parseInt(badge.textContent) || 0;
          badge.textContent = atual + 1;
          badge.style.display = '';
        }
      }
    } catch (err) {
      console.error('[Separação] Erro:', err);
      alert('Erro ao conectar ao servidor.');
    }
  }

  // eventos do overlay
  ov.addEventListener('click', e => { if (e.target === ov) fechar(); });
  document.getElementById('sepQtyCancel').addEventListener('click', fechar);
  document.getElementById('sepQtyOk').addEventListener('click', confirmar);
  document.getElementById('sepQtyInput').addEventListener('keydown', e => {
    if (e.key === 'Enter') confirmar();
    if (e.key === 'Escape') fechar();
  });

  window.abrirModalSeparacaoQtd = function(codigo, descricao, unidade) {
    _sepCtx = { codigo, descricao, unidade: (unidade || 'UN').toUpperCase() };
    const el = id => document.getElementById(id);
    el('sepQtyTitle').textContent = 'Quantidade para separação';
    el('sepQtyProd').textContent  = descricao || codigo;
    el('sepQtyUnit').textContent  = 'SOLICITAR COMO: ' + _sepCtx.unidade;
    const inp = el('sepQtyInput'); if (inp) inp.value = 1;
    ov.style.display = 'flex';
    try { inp?.focus({ preventScroll: true }); } catch {}
  };
})();

// Atualiza automaticamente todas as imagens expiradas em lote (com controle de concorrência)
async function atualizarImagensExpiradasEmLote() {
  // Busca todos os containers de imagens expiradas
  const containersExpirados = document.querySelectorAll('[id^="img-expirada-"]');
  
  if (containersExpirados.length === 0) {
    console.log('[Catálogo] Nenhuma imagem expirada encontrada');
    return;
  }
  
  console.log(`[Catálogo] Iniciando atualização de ${containersExpirados.length} imagens expiradas em lotes...`);
  
  // Converte para array com dados necessários
  const imagensParaAtualizar = Array.from(containersExpirados).map(container => ({
    codigoProduto: container.dataset.codigoProduto,
    codigo: container.dataset.codigo,
    descricao: container.dataset.descricao
  }));
  
  // Configuração de processamento em lotes
  const TAMANHO_LOTE = 2; // Processa menos imagens por vez para reduzir rajadas na Omie
  const DELAY_ENTRE_LOTES = 1500; // Mais respiro entre lotes
  
  let totalSucesso = 0;
  let totalFalhas = 0;
  
  // Processa em lotes
  for (let i = 0; i < imagensParaAtualizar.length; i += TAMANHO_LOTE) {
    const lote = imagensParaAtualizar.slice(i, i + TAMANHO_LOTE);
    const numeroLote = Math.floor(i / TAMANHO_LOTE) + 1;
    const totalLotes = Math.ceil(imagensParaAtualizar.length / TAMANHO_LOTE);
    
    console.log(`[Catálogo] Processando lote ${numeroLote}/${totalLotes} (${lote.length} imagens)...`);
    
    // Processa o lote atual em paralelo
    const promessasLote = lote.map(img => 
      atualizarImagemExpirada(img.codigoProduto, img.codigo, img.descricao)
    );
    
    const resultadosLote = await Promise.allSettled(promessasLote);
    
    // Contabiliza resultados do lote
    const sucessoLote = resultadosLote.filter(r => r.status === 'fulfilled').length;
    const falhasLote = resultadosLote.filter(r => r.status === 'rejected').length;
    
    totalSucesso += sucessoLote;
    totalFalhas += falhasLote;
    
    console.log(`[Catálogo] Lote ${numeroLote}/${totalLotes}: ${sucessoLote} sucesso, ${falhasLote} falhas`);
    
    // Aguarda antes do próximo lote (exceto no último)
    if (i + TAMANHO_LOTE < imagensParaAtualizar.length) {
      await new Promise(resolve => setTimeout(resolve, DELAY_ENTRE_LOTES));
    }
  }
  
  console.log(`[Catálogo] Atualização concluída: ${totalSucesso} sucesso, ${totalFalhas} falhas de ${imagensParaAtualizar.length} total`);
}

// Atualiza uma única imagem expirada
async function atualizarImagemExpirada(codigoProduto, codigo, descricao) {
  const container = document.getElementById(`img-expirada-${codigoProduto}`);
  if (!container) return;
  
  try {
    const resp = await fetch(`/api/compras/imagem-fresca/${codigoProduto}`);
    
    if (!resp.ok) {
      // Se erro 500, não joga exceção - apenas registra
      if (resp.status === 500) {
        console.warn(`[Catálogo] Produto ${codigoProduto} sem imagem disponível na Omie`);
        container.innerHTML = `
          <i class="fa-solid fa-image" style="font-size:32px;color:#9ca3af;"></i>
          <span style="font-size:9px;color:#6b7280;">Sem imagem</span>
        `;
        return; // Retorna normalmente, não é erro crítico
      }
      throw new Error(`HTTP ${resp.status}`);
    }
    
    const data = await resp.json();
    
    if (data.url_imagem) {
      // Substitui o container pela imagem
      const infoTexto = `${codigo} - ${descricao}`;
      container.outerHTML = `
        <img 
          src="${data.url_imagem}" 
          alt="${escapeHtml(descricao)}"
          style="max-width:100%;max-height:100%;object-fit:contain;cursor:zoom-in;transition:transform 0.2s;"
          onclick='ampliarImagemProduto(${JSON.stringify(data.url_imagem)}, ${JSON.stringify(infoTexto)});event.stopPropagation();'
          onmouseover="this.style.transform='scale(1.05)'"
          onmouseout="this.style.transform='scale(1)'"
          onerror="this.style.display='none'"
        />
      `;
      
      // Atualiza o produto no cache
      const produtoIndex = window.produtosCatalogoOmie?.findIndex(p => p.codigo_produto === codigoProduto);
      if (produtoIndex >= 0 && window.produtosCatalogoOmie) {
        window.produtosCatalogoOmie[produtoIndex].url_imagem = data.url_imagem;
      }
    } else {
      // Produto sem imagem
      container.innerHTML = `
        <i class="fa-solid fa-image" style="font-size:32px;color:#9ca3af;"></i>
        <span style="font-size:9px;color:#6b7280;">Sem imagem</span>
      `;
    }
  } catch (err) {
    console.error(`[Catálogo] Erro ao atualizar imagem ${codigoProduto}:`, err);
    container.innerHTML = `
      <i class="fa-solid fa-exclamation-triangle" style="font-size:28px;color:#ef4444;"></i>
      <span style="font-size:9px;color:#dc2626;">Erro</span>
    `;
    throw err; // Re-lança para contabilizar como falha
  }
}

// Carrega departamentos no select global do catálogo
async function carregarDepartamentosCatalogo() {
  try {
    const resp = await fetch('/api/compras/departamentos');
    const data = await resp.json();
    
    if (data.ok && data.departamentos) {
      window.catalogoDepartamentos = data.departamentos;
      
      let valorAtual = ''; // Declarar no início da função
      
      // Atualiza o select global de departamento
      const selectGlobal = document.getElementById('catalogoDepartamentoGlobal');
      if (selectGlobal) {
        valorAtual = selectGlobal.value;
        selectGlobal.innerHTML = '<option value="">Selecione...</option>' +
          data.departamentos.map(d => 
            `<option value="${escapeHtml(d.nome)}">${escapeHtml(d.nome)}</option>`
          ).join('');
        if (valorAtual) selectGlobal.value = valorAtual;
        
        // Adiciona evento para atualizar categorias quando departamento mudar
        selectGlobal.removeEventListener('change', handleCatalogoDepartamentoChange);
        selectGlobal.addEventListener('change', handleCatalogoDepartamentoChange);
      }
      
      // Inicializa o select de categorias vazio
      const selectCategorias = document.getElementById('catalogoCentroCustoGlobal');
      if (selectCategorias && !valorAtual) {
        selectCategorias.innerHTML = '<option value="">Selecione departamento</option>';
      }
    }
  } catch (err) {
    console.error('[Catálogo] Erro ao carregar departamentos:', err);
  }
}

