// Variável global para ratrear o modo de visualização atual
let modoVisualizacaoKanban = true;

function atualizarOffsetCabecalhoListaCompras() {
  const wrapper = document.getElementById('minhasComprasWrapper');
  const toolbar = document.getElementById('comprasListaToolbar');
  if (!wrapper || !toolbar) return;

  const toolbarStyle = window.getComputedStyle(toolbar);
  if (toolbarStyle.display === 'none' || toolbarStyle.visibility === 'hidden') return;

  const marginBottom = parseFloat(toolbarStyle.marginBottom) || 0;
  const borderBottom = parseFloat(toolbarStyle.borderBottomWidth) || 0;
  const alturaToolbar = Math.ceil(toolbar.getBoundingClientRect().height + marginBottom + borderBottom);
  const offset = Math.max(0, alturaToolbar);
  wrapper.style.setProperty('--compras-lista-topo-offset', `${offset}px`);
}

// Objetivo: Alternar entre visualização Kanban e Lista
function toggleVisualizacao() {
  modoVisualizacaoKanban = !modoVisualizacaoKanban;
  
  if (modoVisualizacaoKanban) {
    mostrarVisualizacaoKanban();
  } else {
    mostrarVisualizacaoLista();
  }
}

// ============================================================
// Filtro de data por período para os kanbans de compras
// ============================================================
// Armazena o filtro de data ativo (null = sem filtro)
window._comprasFiltroDatas = null;

function abrirModalFiltrarData() {
  const modal = document.getElementById('modalFiltrarDataKanban');
  if (!modal) return;
  // Pré-preenche com valores do filtro ativo
  if (window._comprasFiltroDatas) {
    const inp1 = document.getElementById('filtrarDataInicio');
    const inp2 = document.getElementById('filtrarDataFim');
    if (inp1) inp1.value = window._comprasFiltroDatas.inicio || '';
    if (inp2) inp2.value = window._comprasFiltroDatas.fim || '';
  }
  modal.style.display = 'flex';
}

// Atalhos rápidos de período para o filtro do kanban de compras
function filtroDataRapido(periodo) {
  const fmt = d => d.toISOString().slice(0, 10);
  const hoje = new Date();
  let ini, fim;
  if (periodo === 'mes-atual') {
    ini = new Date(hoje.getFullYear(), hoje.getMonth(), 1);
    fim = new Date(hoje.getFullYear(), hoje.getMonth() + 1, 0);
  } else if (periodo === 'mes-anterior') {
    ini = new Date(hoje.getFullYear(), hoje.getMonth() - 1, 1);
    fim = new Date(hoje.getFullYear(), hoje.getMonth(), 0);
  } else if (periodo === 'trimestre') {
    ini = new Date(hoje.getFullYear(), hoje.getMonth() - 2, 1);
    fim = new Date(hoje.getFullYear(), hoje.getMonth() + 1, 0);
  }
  const inp1 = document.getElementById('filtrarDataInicio');
  const inp2 = document.getElementById('filtrarDataFim');
  if (inp1) inp1.value = fmt(ini);
  if (inp2) inp2.value = fmt(fim);
}
window.filtroDataRapido = filtroDataRapido;

function fecharModalFiltrarData() {
  const modal = document.getElementById('modalFiltrarDataKanban');
  if (modal) modal.style.display = 'none';
}

function limparFiltroData() {
  const inp1 = document.getElementById('filtrarDataInicio');
  const inp2 = document.getElementById('filtrarDataFim');
  if (inp1) inp1.value = '';
  if (inp2) inp2.value = '';
  window._comprasFiltroDatas = null;
  // Restaura cor original do botão
  const btn = document.getElementById('comprasFiltrarDataBtn');
  if (btn) {
    btn.style.background = 'linear-gradient(135deg,#ec4899 0%,#db2777 100%)';
    btn.title = 'Filtrar por Data';
  }
  fecharModalFiltrarData();
  if (typeof loadMinhasSolicitacoes === 'function') loadMinhasSolicitacoes();
}

function aplicarFiltroData() {
  const inicio = (document.getElementById('filtrarDataInicio')?.value || '').trim();
  const fim = (document.getElementById('filtrarDataFim')?.value || '').trim();
  if (!inicio && !fim) {
    limparFiltroData();
    return;
  }
  window._comprasFiltroDatas = { inicio, fim };
  // Destaca o botão para indicar filtro ativo (laranja)
  const btn = document.getElementById('comprasFiltrarDataBtn');
  if (btn) {
    btn.style.background = 'linear-gradient(135deg,#f97316 0%,#ea580c 100%)';
    btn.title = 'Filtro de data ativo — clique para alterar';
  }
  fecharModalFiltrarData();
  if (typeof loadMinhasSolicitacoes === 'function') loadMinhasSolicitacoes();
}

window.abrirModalFiltrarData = abrirModalFiltrarData;
window.fecharModalFiltrarData = fecharModalFiltrarData;
window.limparFiltroData = limparFiltroData;
window.aplicarFiltroData = aplicarFiltroData;

// ============================================================
// Gráfico de histórico de compras (Chart.js)
// ============================================================
let _graficoHistoricoInstance = null; // instância Chart.js ativa
let _modoGraficoAtivo = false;        // controla se o painel do gráfico está visível

// Objetivo: Alternar exibição do painel de gráfico
function toggleGraficoHistorico() {
  _modoGraficoAtivo = !_modoGraficoAtivo;
  const btn = document.getElementById('comprasGraficoBtn');
  const painel = document.getElementById('painelGraficoHistorico');
  const kanban = document.getElementById('kanbanMinhasSolicitacoes');
  const lista = document.getElementById('listaMinhasSolicitacoes');

  if (_modoGraficoAtivo) {
    // Oculta kanban e lista, mostra painel de gráfico
    if (kanban) kanban.style.display = 'none';
    if (lista)  lista.style.display  = 'none';
    if (painel) painel.style.display = 'block';
    if (btn) {
      btn.style.background = 'linear-gradient(135deg,#0369a1 0%,#075985 100%)';
      btn.title = 'Fechar gráfico';
    }
    // Define o período padrão: últimos 90 dias
    const hoje = new Date();
    const ini  = new Date(hoje); ini.setDate(ini.getDate() - 90);
    const fmt  = d => d.toISOString().slice(0, 10);
    const inpIni = document.getElementById('graficoDataInicio');
    const inpFim = document.getElementById('graficoDataFim');
    if (inpIni && !inpIni.value) inpIni.value = fmt(ini);
    if (inpFim && !inpFim.value) inpFim.value = fmt(hoje);
    carregarGraficoHistorico();
    carregarGraficoPizza();
  } else {
    // Fecha painel e restaura a view anterior
    if (painel) painel.style.display = 'none';
    if (btn) {
      btn.style.background = 'linear-gradient(135deg,#0ea5e9 0%,#0284c7 100%)';
      btn.title = 'Gráfico de Compras';
    }
    if (modoVisualizacaoKanban) {
      if (kanban) kanban.style.display = 'flex';
    } else {
      if (lista) lista.style.display = 'block';
    }
  }
}

// Objetivo: Buscar dados da API e renderizar o gráfico
async function carregarGraficoHistorico() {
  const loading = document.getElementById('graficoHistoricoLoading');
  const vazio   = document.getElementById('graficoHistoricoVazio');
  if (loading) { loading.style.display = 'flex'; loading.style.position = 'absolute'; }
  if (vazio)     vazio.style.display = 'none';

  try {
    const inicio = document.getElementById('graficoDataInicio')?.value || '';
    const fim    = document.getElementById('graficoDataFim')?.value || '';
    const params = new URLSearchParams();
    if (inicio) params.set('dataInicio', inicio);
    if (fim)    params.set('dataFim', fim);
    const qs = params.toString() ? `?${params.toString()}` : '';

    const resp = await fetch(`/api/compras/grafico-historico${qs}`, { credentials: 'include' });
    if (!resp.ok) throw new Error('Falha na requisição');
    const { dados } = await resp.json();

    if (loading) loading.style.display = 'none';

    if (!dados || dados.length === 0) {
      if (vazio) { vazio.style.display = 'flex'; vazio.style.position = 'absolute'; }
      if (_graficoHistoricoInstance) { _graficoHistoricoInstance.destroy(); _graficoHistoricoInstance = null; }
      return;
    }

    // Formata labels como DD/MM/AAAA
    const labels = dados.map(d => {
      const [ano, mes, dia] = String(d.data).slice(0,10).split('-');
      return `${dia}/${mes}/${ano}`;
    });
    const valores = dados.map(d => d.total);

    const canvas = document.getElementById('graficoHistoricoCanvas');
    if (!canvas) return;

    // Destrói instância anterior se existir
    if (_graficoHistoricoInstance) { _graficoHistoricoInstance.destroy(); _graficoHistoricoInstance = null; }

    _graficoHistoricoInstance = new Chart(canvas, {
      type: 'line',
      data: {
        labels,
        datasets: [{
          label: 'Valor de Pedidos (R$)',
          data: valores,
          fill: true,
          backgroundColor: 'rgba(14,165,233,0.12)',
          borderColor: '#0ea5e9',
          borderWidth: 2.5,
          pointBackgroundColor: '#0284c7',
          pointRadius: dados.length > 60 ? 2 : 5,
          pointHoverRadius: 7,
          tension: 0.35
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: true, position: 'top', labels: { font: { size: 13 }, color: '#374151' } },
          tooltip: {
            callbacks: {
              label: ctx => ` ${Number(ctx.parsed.y).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}`
            }
          }
        },
        scales: {
          x: {
            ticks: { font: { size: 11 }, color: '#6b7280', maxTicksLimit: 20, maxRotation: 45 },
            grid: { color: 'rgba(0,0,0,0.05)' }
          },
          y: {
            ticks: {
              font: { size: 11 }, color: '#6b7280',
              callback: v => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })
            },
            grid: { color: 'rgba(0,0,0,0.07)' }
          }
        }
      }
    });
  } catch (err) {
    console.error('[GraficoHistorico] Erro:', err);
    if (loading) loading.style.display = 'none';
  }
}

// Objetivo: Limpa os filtros e recarrega ambos os gráficos sem período
function limparFiltroGrafico() {
  const inpIni = document.getElementById('graficoDataInicio');
  const inpFim = document.getElementById('graficoDataFim');
  if (inpIni) inpIni.value = '';
  if (inpFim) inpFim.value = '';
  carregarGraficoHistorico();
  carregarGraficoPizza();
}

// Atalhos rápidos de período para os filtros do gráfico
function graficoPeriodoRapido(periodo) {
  const fmt = d => d.toISOString().slice(0, 10);
  const hoje = new Date();
  let ini, fim;
  if (periodo === 'mes-atual') {
    ini = new Date(hoje.getFullYear(), hoje.getMonth(), 1);
    fim = new Date(hoje.getFullYear(), hoje.getMonth() + 1, 0);
  } else if (periodo === 'mes-anterior') {
    ini = new Date(hoje.getFullYear(), hoje.getMonth() - 1, 1);
    fim = new Date(hoje.getFullYear(), hoje.getMonth(), 0);
  } else if (periodo === 'trimestre') {
    ini = new Date(hoje.getFullYear(), hoje.getMonth() - 2, 1);
    fim = new Date(hoje.getFullYear(), hoje.getMonth() + 1, 0);
  }
  const inpIni = document.getElementById('graficoDataInicio');
  const inpFim = document.getElementById('graficoDataFim');
  if (inpIni) inpIni.value = fmt(ini);
  if (inpFim) inpFim.value = fmt(fim);
  carregarAmboGraficos();
}

window.toggleGraficoHistorico = toggleGraficoHistorico;
window.carregarGraficoHistorico = carregarGraficoHistorico;
window.limparFiltroGrafico = limparFiltroGrafico;
window.graficoPeriodoRapido = graficoPeriodoRapido;

// ============================================================
// Gráfico de Pizza: Departamento / Centro de Custo
// ============================================================
let _graficoPizzaInstance = null;
let _graficoCategoriaInstance = null;
let _pizzaGrupoAtivo = 'departamento'; // 'departamento' | 'centro_custo'

// Objetivo: Gráfico de barras verticais por status de compra.
// "Compra realizada" é exibida como barra empilhada por Etapa_NF (camadas),
// usando logistica.etapas_recebimento_nfe como legenda. NULL = Aguardando recebimento.
// "Recebimento" é exibida como barra única.
async function carregarGraficoPizza(grupo) {
  const loading = document.getElementById('graficoPizzaLoading');
  const vazio   = document.getElementById('graficoPizzaVazio');
  if (loading) { loading.style.display = 'flex'; loading.style.position = 'absolute'; }
  if (vazio)     vazio.style.display = 'none';

  try {
    const inicio = document.getElementById('graficoDataInicio')?.value || '';
    const fim    = document.getElementById('graficoDataFim')?.value || '';
    const params = new URLSearchParams();
    if (inicio) params.set('dataInicio', inicio);
    if (fim)    params.set('dataFim', fim);

    const resp = await fetch(`/api/compras/grafico-pizza-dept-cc?${params.toString()}`, { credentials: 'include' });
    if (!resp.ok) throw new Error('Falha na requisição');
    const { dados } = await resp.json();

    if (loading) loading.style.display = 'none';

    if (!dados || dados.length === 0) {
      if (vazio) { vazio.style.display = 'flex'; vazio.style.position = 'absolute'; }
      if (_graficoPizzaInstance) { _graficoPizzaInstance.destroy(); _graficoPizzaInstance = null; }
      return;
    }

    // Separa etapas da "Compra realizada" e camadas do "Recebimento"
    const dadosCompra = dados.filter(d => d.status === 'Compra realizada');
    const dadosReceb  = dados.filter(d => d.status === 'Recebimento');

    // Labels fixos do eixo X
    const statusUnicos = [];
    if (dadosCompra.length > 0) statusUnicos.push('Compra realizada');
    if (dadosReceb.length > 0)  statusUnicos.push('Recebimento');

    // Totais por status (para cálculo de %)
    const totalCompra = dadosCompra.reduce((s, d) => s + d.total, 0);
    const totalReceb  = dadosReceb.reduce((s, d) => s + d.total, 0);
    const totalGeral  = totalCompra + totalReceb;

    // Paleta de azuis para as camadas de "Compra realizada"
    const PALETA_COMPRA = [
      '#bfdbfe', // blue 200  — Aguardando recebimento (NULL)
      '#60a5fa', // blue 400
      '#3b82f6', // blue 500
      '#2563eb', // blue 600
      '#1d4ed8', // blue 700
      '#1e40af', // blue 800
      '#6366f1', // indigo 500
      '#4f46e5', // indigo 600
    ];

    // Paleta de verdes para as camadas de "Recebimento" (por ano de compra)
    const PALETA_RECEB = [
      '#6ee7b7', // emerald 300
      '#34d399', // emerald 400
      '#10b981', // emerald 500
      '#059669', // emerald 600
      '#047857', // emerald 700
      '#d1fae5', // emerald 100 — Sem pedido vinculado
    ];

    // Um dataset por etapa de "Compra realizada" — todos no mesmo stack 'total'
    // para evitar que o Chart.js divida a largura da barra por grupos de stack
    const datasets = dadosCompra.map((etapa, i) => ({
      label:           etapa.etapa_descricao,
      data:            statusUnicos.map(st => st === 'Compra realizada' ? etapa.total : 0),
      backgroundColor: PALETA_COMPRA[i % PALETA_COMPRA.length],
      borderRadius:    4,
      borderWidth:     0,
      stack:           'total',
    }));

    // Um dataset por camada de "Recebimento" (por ano de compra + sem pedido)
    dadosReceb.forEach((camada, i) => {
      datasets.push({
        label:           camada.etapa_descricao,
        data:            statusUnicos.map(st => st === 'Recebimento' ? camada.total : 0),
        backgroundColor: PALETA_RECEB[i % PALETA_RECEB.length],
        borderRadius:    4,
        borderWidth:     0,
        stack:           'total',
      });
    });

    // Guarda dados no window para o click handler acessar
    window._graficoPizzaDados          = dados;
    window._graficoPizzaStatusUnicos   = statusUnicos;
    window._graficoPizzaTotalPorStatus = { 'Compra realizada': totalCompra, 'Recebimento': totalReceb };

    const canvas = document.getElementById('graficoPizzaCanvas');
    if (!canvas) return;
    if (_graficoPizzaInstance) { _graficoPizzaInstance.destroy(); _graficoPizzaInstance = null; }

    _graficoPizzaInstance = new Chart(canvas, {
      type: 'bar',
      data: { labels: statusUnicos, datasets },
      plugins: [{
        // Plugin inline: desenha o total acumulado de cada stack no topo da barra
        id: 'totalNaBarra',
        afterDatasetsDraw(chart) {
          const { ctx, data } = chart;
          const nBars = data.labels.length;
          ctx.save();
          ctx.font = 'bold 11px sans-serif';
          ctx.fillStyle = '#374151';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'bottom';
          for (let i = 0; i < nBars; i++) {
            const soma = data.datasets.reduce((acc, ds) => acc + (Number(ds.data[i]) || 0), 0);
            if (!soma) continue;
            // Encontra o elemento de barra mais alto (menor y) entre os datasets com valor > 0 nessa posição
            let minY = Infinity;
            let topoX = null;
            for (let d = 0; d < data.datasets.length; d++) {
              if (!Number(data.datasets[d].data[i])) continue;
              const meta = chart.getDatasetMeta(d);
              const bar  = meta.data[i];
              if (bar && bar.y < minY) { minY = bar.y; topoX = bar.x; }
            }
            if (topoX === null) continue;
            const txt = 'R$ ' + Math.round(soma).toLocaleString('pt-BR');
            ctx.fillText(txt, topoX, minY - 4);
          }
          ctx.restore();
        }
      }],
      options: {
        responsive: true,
        maintainAspectRatio: false,
        layout: { padding: { top: 28 } },
        interaction: { mode: 'index', intersect: false },
        onClick(event, elements) {
          if (!elements.length) return;
          const status = statusUnicos[elements[0].index];
          exibirDetalheGraficoBarra(status);
        },
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: ctx => {
                const val = Number(ctx.parsed.y);
                if (!val) return null;
                // Percentual relativo ao total da própria barra (compra ou recebimento)
                const isCompra = statusUnicos[ctx.dataIndex] === 'Compra realizada';
                const denom = isCompra ? totalCompra : totalReceb;
                const pct = denom > 0 ? ((val / denom) * 100).toFixed(1) : 0;
                const fmt = val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
                return ` ${ctx.dataset.label}: ${fmt} (${pct}%)`;
              }
            }
          }
        },
        scales: {
          x: {
            stacked: true,
            // barPercentage e categoryPercentage controlam a largura das barras e reduzem o espaço entre elas
            barPercentage: 0.95,
            categoryPercentage: 0.7,
            ticks: { color: '#374151', font: { size: 11 }, maxRotation: 0, autoSkip: false,
              callback: function(val) {
                const lbl = this.getLabelForValue(val);
                // Quebra em linhas de até ~14 chars sem cortar palavras
                const palavras = lbl.split(' ');
                const linhas = [];
                let atual = '';
                for (const p of palavras) {
                  if (atual && (atual + ' ' + p).length > 14) {
                    linhas.push(atual);
                    atual = p;
                  } else {
                    atual = atual ? atual + ' ' + p : p;
                  }
                }
                if (atual) linhas.push(atual);
                return linhas;
              }
            },
            grid: { display: false }
          },
          y: {
            stacked: true,
            ticks: {
              color: '#374151', font: { size: 11 },
              callback: v => 'R$ ' + (v >= 1000 ? (v / 1000).toFixed(0) + 'k' : v.toFixed(0))
            },
            grid: { color: '#e5e7eb' }
          }
        }
      }
    });
  } catch (err) {
    console.error('[GraficoBarras] Erro:', err);
    if (loading) loading.style.display = 'none';
  }
}

// Objetivo: Alternar visibilidade das sublinhas de um grupo da tabela de detalhes
function toggleGpiSub(subId) {
  const rows  = document.querySelectorAll(`.${subId}`);
  const ic    = document.getElementById(`${subId}_ic`);
  const aberto = rows.length > 0 && rows[0].style.display !== 'none';
  rows.forEach(r => r.style.display = aberto ? 'none' : 'table-row');
  if (ic) ic.className = aberto ? 'fa-solid fa-chevron-right' : 'fa-solid fa-chevron-down';
}

// Objetivo: Renderizar a tabela de itens, com filtro opcional por categoria (pai ou subcategoria exata)
async function _carregarItensTabela(statusClicado, categoriaCode, categoriaLabel) {
  const titulo = document.getElementById('graficoPizzaDetalheTitulo');
  const tbody  = document.getElementById('graficoPizzaDetalheTbody');
  if (!titulo || !tbody) return;

  tbody.innerHTML = `<tr><td colspan="3" style="padding:14px 12px;text-align:center;color:#7c3aed;font-size:13px;">
    <i class="fa-solid fa-spinner fa-spin" style="margin-right:6px;"></i>Filtrando itens...</td></tr>`;

  const inicio = document.getElementById('graficoDataInicio')?.value;
  const fim    = document.getElementById('graficoDataFim')?.value;
  const params = new URLSearchParams({ status: statusClicado });
  if (categoriaCode) params.set('categoria', categoriaCode);
  if (inicio) params.set('dataInicio', inicio);
  if (fim)    params.set('dataFim', fim);

  const fmtVal = v => 'R$ ' + Math.round(v).toLocaleString('pt-BR');
  const subTag = categoriaLabel
    ? ` <span style="color:#10b981;font-size:11px;background:#d1fae5;padding:2px 8px;border-radius:10px;font-weight:600;">${categoriaLabel}</span>`
    : '';

  try {
    const resp = await fetch(`/api/compras/grafico-pizza-itens?${params.toString()}`, { credentials: 'include' });
    if (!resp.ok) throw new Error('Falha');
    const { itens } = await resp.json();

    titulo.innerHTML = `<i class="fa-solid fa-table" style="margin-right:6px;color:#7c3aed;"></i>`
      + `Detalhes — <span style="color:#7c3aed;">${statusClicado}</span>${subTag}`;

    let html = '';
    let totalFiltrado = 0;
    (itens || []).forEach(item => {
      totalFiltrado += item.valor_item || 0;
      const fmtData = item.d_data ? item.d_data.split('-').reverse().join('/') : '—';
      const valHtml = `<span style="margin-left:auto;white-space:nowrap;font-weight:600;color:#059669;">${fmtVal(item.valor_item)}</span>`;
      const refLabel = item.referencia || item.h_id;
      const refHtml = item.chave_nfe
        ? `<a href="#" style="color:#38bdf8;text-decoration:underline;font-weight:700;"
             data-chave="${(item.chave_nfe || '').replace(/"/g,'&quot;')}"
             data-num="${(item.referencia || '').replace(/"/g,'&quot;')}"
             onclick="event.stopPropagation();if(window.abrirModalNfeOmieDetalhes)window.abrirModalNfeOmieDetalhes(this.dataset.chave,this.dataset.num,null,{ocultarComparacao:true});return false;"
           >${refLabel}</a>`
        : `<b>${refLabel}</b>`;
      html += `<tr style="background:#fff;border-bottom:1px solid #f3f4f6;">
        <td colspan="3" style="padding:7px 12px;">
          <span style="display:inline-flex;align-items:center;flex-wrap:wrap;gap:6px;font-size:12px;width:100%;">
            <span style="color:#9ca3af;">NF/Ped. ${refHtml}</span>
            <span style="color:#374151;">${item.fornecedor}</span>
            <span style="color:#6b7280;">Data: <b>${fmtData}</b></span>
            ${item.descricao ? `<span style="color:#6366f1;font-family:monospace;">${item.descricao}</span>` : ''}
            ${item.qtde ? `<span style="color:#6b7280;">Qtd: <b>${item.qtde}</b></span>` : ''}
            ${item.preco_unit ? `<span style="color:#6b7280;">Unit: <b>${fmtVal(item.preco_unit)}</b></span>` : ''}
            ${valHtml}
          </span>
        </td>
      </tr>`;
    });

    if (!html) {
      html = `<tr><td colspan="3" style="padding:14px 12px;text-align:center;color:#9ca3af;font-size:13px;">Nenhum item encontrado</td></tr>`;
    } else {
      html += `<tr style="background:#f0fdf4;border-top:2px solid #d1fae5;">
        <td style="padding:8px 12px;font-size:13px;font-weight:700;color:#111827;">Total</td>
        <td style="padding:8px 12px;font-size:13px;font-weight:700;color:#111827;text-align:right;">${fmtVal(totalFiltrado)}</td>
        <td></td>
      </tr>`;
    }
    tbody.innerHTML = html;

  } catch (err) {
    console.error('[CarregarItensTabela]', err);
    titulo.innerHTML = `<i class="fa-solid fa-circle-exclamation" style="margin-right:6px;color:#ef4444;"></i>Erro ao carregar itens`;
  }
}

// Objetivo: Handler unificado de clique em categoria (drill-down no pie + filtro de itens)
function _handleCatClick(status, codigo, label, isDrillDown) {
  if (_graficoCategoriaEstado.modo === 'meses') {
    if (isDrillDown) {
      _carregarGraficoCategorias(status, codigo, label, _graficoCategoriaEstado.mesCompra, 'meses');
    }
    if (_graficoCategoriaEstado.mesCompra) {
      _renderDetalheMeses(_graficoCategoriaEstado.mesCompra, codigo, label);
    }
    return;
  }
  if (isDrillDown) _carregarGraficoCategorias(status, codigo, label, null, 'periodo');
  _carregarItensTabela(status, codigo, label);
}

// Estado do drill-down de categorias
let _graficoCategoriaEstado = { status: null, pai: null, labelPai: null, mesCompra: null, modo: 'periodo' };

// Objetivo: Carregar (e re-carregar para drill-down) o gráfico de pizza por categoria
async function _carregarGraficoCategorias(statusClicado, pai, labelPai, mesCompra, modo = 'periodo') {
  const catSection = document.getElementById('graficoCategoriaSection');
  const catLoading = document.getElementById('graficoCategoriaLoading');
  const catLegenda = document.getElementById('graficoCategoriaLegenda');
  const breadcrumb = document.getElementById('graficoCatBreadcrumb');
  const btnVoltar  = document.getElementById('graficoCatVoltar');

  if (catSection) catSection.style.display = 'block';
  if (catLoading) catLoading.style.display = 'flex';

  // Salvar estado para o botão "Voltar"
  _graficoCategoriaEstado = { status: statusClicado, pai, labelPai, mesCompra, modo };

  // Breadcrumb e botão voltar
  if (pai) {
    if (breadcrumb) { breadcrumb.textContent = labelPai || pai; breadcrumb.style.display = 'inline-block'; }
    if (btnVoltar)  btnVoltar.style.display = 'inline-block';
  } else {
    if (breadcrumb) breadcrumb.style.display = 'none';
    if (btnVoltar)  btnVoltar.style.display = 'none';
  }

  const inicio = document.getElementById('graficoDataInicio')?.value;
  const fim    = document.getElementById('graficoDataFim')?.value;
  const catParams = new URLSearchParams({ status: statusClicado });
  if (pai)    catParams.set('pai', pai);
  if (inicio) catParams.set('dataInicio', inicio);
  if (fim)    catParams.set('dataFim', fim);
  if (mesCompra) catParams.set('mesCompra', mesCompra);

  try {
    const resp = await fetch(`/api/compras/grafico-categorias?${catParams.toString()}`, { credentials: 'include' });
    const { categorias } = await resp.json();
    if (catLoading) catLoading.style.display = 'none';

    const canvas = document.getElementById('graficoCategoriaCanvas');
    if (!canvas || !categorias || !categorias.length) {
      if (catLegenda) catLegenda.innerHTML = `<tr><td style="padding:10px;color:#9ca3af;font-size:12px;">Nenhuma categoria encontrada</td></tr>`;
      return;
    }

    // Destruir instância anterior
    if (_graficoCategoriaInstance) { _graficoCategoriaInstance.destroy(); _graficoCategoriaInstance = null; }

    const PALETA = [
      '#10b981','#3b82f6','#f59e0b','#ef4444','#8b5cf6',
      '#06b6d4','#84cc16','#f97316','#ec4899','#14b8a6',
      '#a78bfa','#fb923c','#34d399','#60a5fa','#fbbf24',
      '#f87171','#c084fc','#2dd4bf','#a3e635','#fb7185',
    ];
    const totalGeral = categorias.reduce((s, c) => s + c.total, 0);
    const cores      = categorias.map((_, i) => PALETA[i % PALETA.length]);
    const fmtVal     = v => 'R$ ' + Math.round(v).toLocaleString('pt-BR');
    const fmtPct     = v => totalGeral > 0 ? ((v / totalGeral) * 100).toFixed(1) + '%' : '0%';

    // Indicar que tem drill-down (nível 1 é clicável)
    const ehNivel1 = !pai;

    _graficoCategoriaInstance = new Chart(canvas, {
      type: 'pie',
      data: {
        labels: categorias.map(c => c.label),
        datasets: [{ data: categorias.map(c => c.total), backgroundColor: cores, borderWidth: 1, borderColor: '#fff' }],
      },
      options: {
        responsive: true,
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: ctx => {
                const suf = ehNivel1 ? ' (clique para detalhar)' : ' (clique para filtrar)';
                return ` ${fmtVal(ctx.raw)}  (${fmtPct(ctx.raw)})${suf}`;
              }
            }
          }
        },
        onClick: (evt, elements) => {
          if (!elements || !elements.length) return;
          const idx = elements[0].index;
          const cat = categorias[idx];
          if (ehNivel1) _carregarGraficoCategorias(statusClicado, cat.codigo, cat.label, mesCompra, modo);
          if (modo === 'periodo') {
            _carregarItensTabela(statusClicado, cat.codigo, cat.label);
          } else if (modo === 'meses') {
            _renderDetalheMeses(mesCompra, cat.codigo, cat.label);
          }
        },
        onHover: (evt, elements) => { canvas.style.cursor = elements.length ? 'pointer' : 'default'; },
      }
    });

    // Legenda lateral com código, descrição, valor, % e ícone de drill-down no nível 1
    if (catLegenda) {
      catLegenda.innerHTML = categorias.map((c, i) => `
        <tr style="border-bottom:1px solid #f3f4f6;cursor:pointer;"
            onclick="window._handleCatClick('${statusClicado.replace(/'/g,"\\'")}','${c.codigo}','${c.label.replace(/'/g,"\\'")}',${ehNivel1})">
          <td style="padding:4px 6px;">
            <span style="display:inline-block;width:10px;height:10px;border-radius:2px;background:${cores[i]};vertical-align:middle;"></span>
          </td>
          <td style="padding:4px 6px;font-size:11px;color:#374151;max-width:220px;">
            <div style="font-weight:600;line-height:1.3;">${c.label}${ehNivel1 ? ' <span style="color:#7c3aed;font-size:10px;">&#9656;</span>' : ''}</div>
            <div style="color:#9ca3af;font-size:10px;">${c.codigo}</div>
          </td>
          <td style="padding:4px 6px;text-align:right;white-space:nowrap;font-size:11px;color:#059669;font-weight:600;">${fmtVal(c.total)}</td>
          <td style="padding:4px 6px;text-align:right;white-space:nowrap;font-size:11px;color:#6b7280;">${fmtPct(c.total)}</td>
        </tr>`).join('');
    }
  } catch (err) {
    console.error('[GraficoCategorias]', err);
    if (catLoading) catLoading.style.display = 'none';
  }
}

// Objetivo: Voltar ao nível 1 do gráfico de categorias e resetar filtro da tabela
function _graficoCatVoltar() {
  if (_graficoCategoriaEstado.status) {
    _carregarGraficoCategorias(
      _graficoCategoriaEstado.status,
      null,
      null,
      _graficoCategoriaEstado.mesCompra,
      _graficoCategoriaEstado.modo
    );
    if (_graficoCategoriaEstado.modo === 'periodo') {
      _carregarItensTabela(_graficoCategoriaEstado.status, null, null);
    } else if (_graficoCategoriaEstado.modo === 'meses') {
      _renderDetalheMeses(_graficoCategoriaEstado.mesCompra);
    }
  }
}
window._carregarGraficoCategorias = _carregarGraficoCategorias;
window._carregarItensTabela       = _carregarItensTabela;
window._handleCatClick            = _handleCatClick;
window._graficoCatVoltar          = _graficoCatVoltar;

// Objetivo: Exibir tabela de detalhes com sublinhas ao clicar em uma barra do gráfico
async function exibirDetalheGraficoBarra(statusClicado) {
  const wrapper    = document.getElementById('graficoPizzaDetalheWrapper');
  const titulo     = document.getElementById('graficoPizzaDetalheTitulo');
  const tbody      = document.getElementById('graficoPizzaDetalheTbody');
  const catSection = document.getElementById('graficoCategoriaSection');
  if (!wrapper || !titulo || !tbody) return;

  titulo.innerHTML = `<i class="fa-solid fa-spinner fa-spin" style="margin-right:6px;color:#7c3aed;"></i>Carregando itens...`;
  tbody.innerHTML  = '';
  wrapper.style.display = 'block';
  wrapper.scrollIntoView({ behavior: 'smooth', block: 'nearest' });

  // Carregar gráfico de categorias e tabela de itens (sem filtro de categoria ao abrir)
  _carregarGraficoCategorias(statusClicado, null, null, null, 'periodo');
  _carregarItensTabela(statusClicado, null, null);
}

// Objetivo: Carregar os dois gráficos simultaneamente (botão Aplicar compartilhado)
function carregarAmboGraficos() {
  // Carrega apenas o gráfico ativo no momento
  if (_graficoAtivoModo === 'meses') {
    carregarGraficoMeses();
  } else {
    carregarGraficoHistorico();
    carregarGraficoPizza();
  }
}

// Controla qual gráfico está visível: 'periodo' ou 'meses'
let _graficoAtivoModo = 'periodo';

// Objetivo: Alternar entre o gráfico de Período e o de Meses
function alternarGrafico(modo) {
  _graficoAtivoModo = modo;
  const wrapperPizzaCard = document.getElementById('graficoPizzaCard');  // card inteiro do gráfico de barras
  const wrapperMeses     = document.getElementById('graficoMesesWrapper');
  const btnPeriodo       = document.getElementById('btnGraficoPeriodo');
  const btnMeses         = document.getElementById('btnGraficoMeses');

  if (modo === 'periodo') {
    if (wrapperPizzaCard)  wrapperPizzaCard.style.display = 'block';
    if (wrapperMeses)      wrapperMeses.style.display     = 'none';
    if (btnPeriodo) { btnPeriodo.style.background = 'linear-gradient(135deg,#7c3aed,#6d28d9)'; btnPeriodo.style.color = '#fff'; }
    if (btnMeses)   { btnMeses.style.background   = 'transparent';                             btnMeses.style.color   = '#6b7280'; }
    carregarGraficoHistorico();
    carregarGraficoPizza();
  } else {
    if (wrapperPizzaCard)  wrapperPizzaCard.style.display = 'none';
    if (wrapperMeses)      wrapperMeses.style.display     = 'block';
    if (btnPeriodo) { btnPeriodo.style.background = 'transparent';                             btnPeriodo.style.color = '#6b7280'; }
    if (btnMeses)   { btnMeses.style.background   = 'linear-gradient(135deg,#7c3aed,#6d28d9)'; btnMeses.style.color   = '#fff'; }
    carregarGraficoMeses();
  }
}

// Instância do gráfico de meses (para destruir e recriar ao atualizar)
let _graficoMesesInstance = null;

// Objetivo: Carregar o gráfico de barras Realizado x Recebido por Mês.
// Eixo X = mês de compra (d_inc_data). Barra azul = realizado.
// Barras verdes empilhadas = recebido dividido por mês de recebimento (d_rec).
async function carregarGraficoMeses() {
  const loading = document.getElementById('graficoMesesLoading');
  const vazio   = document.getElementById('graficoMesesVazio');
  if (loading) { loading.style.display = 'flex'; loading.style.position = 'absolute'; }
  if (vazio)     vazio.style.display = 'none';

  try {
    const inicio = document.getElementById('graficoDataInicio')?.value || '';
    const fim    = document.getElementById('graficoDataFim')?.value    || '';
    const params = new URLSearchParams();
    if (inicio) params.set('dataInicio', inicio);
    if (fim)    params.set('dataFim', fim);

    const resp = await fetch(`/api/compras/grafico-meses?${params.toString()}`, { credentials: 'include' });
    if (!resp.ok) throw new Error('Falha na requisição');
    const { labels, realizado, camadas_recebido } = await resp.json();

    if (loading) loading.style.display = 'none';

    if (!labels || labels.length === 0) {
      if (vazio) { vazio.style.display = 'flex'; vazio.style.position = 'absolute'; }
      if (_graficoMesesInstance) { _graficoMesesInstance.destroy(); _graficoMesesInstance = null; }
      return;
    }

    // Paleta de verdes para as camadas de recebimento por d_rec
    const PALETA_REC = [
      '#6ee7b7', // emerald 300
      '#34d399', // emerald 400
      '#10b981', // emerald 500
      '#059669', // emerald 600
      '#047857', // emerald 700
      '#065f46', // emerald 800
      '#d1fae5', // emerald 100
      '#a7f3d0', // emerald 200
    ];

    // Cálculo do "A receber" por mês = total comprado - total recebido (mín. 0).
    // Esse segmento cinza fica no topo da barra, mostrando o que ainda não foi recebido.
    const totalRecebido = labels.map((_, i) =>
      (camadas_recebido || []).reduce((s, c) => s + (c.valores[i] || 0), 0)
    );
    const aReceber = labels.map((_, i) => Math.max(0, realizado[i] - totalRecebido[i]));

    // Datasets: verdes empilhados (recebido por d_rec) + cinza no topo (a receber).
    // Todos no mesmo stack 'total' → UMA barra por mês.
    const datasets = [];

    // Segmentos verdes: recebido dividido por mês de recebimento (d_rec)
    (camadas_recebido || []).forEach((camada, i) => {
      datasets.push({
        label:           `Recebido em ${camada.mes_rec}`,
        data:            camada.valores,
        backgroundColor: PALETA_REC[i % PALETA_REC.length],
        borderRadius:    0,
        borderWidth:     0,
        stack:           'total',
        order:           1,
      });
    });

    // Segmento azul: saldo ainda não recebido (completa a barra até o total comprado)
    datasets.push({
      label:           'A receber',
      data:            aReceber,
      backgroundColor: '#3b82f6', // blue-500
      borderRadius:    4,
      borderWidth:     0,
      stack:           'total',
      order:           2,
    });

    const canvas = document.getElementById('graficoMesesCanvas');
    if (!canvas) return;
    if (_graficoMesesInstance) { _graficoMesesInstance.destroy(); _graficoMesesInstance = null; }

    _graficoMesesInstance = new Chart(canvas, {
      type: 'bar',
      data: { labels, datasets },
      plugins: [{
        id: 'totalNaBarraMeses',
        afterDatasetsDraw(chart) {
          const { ctx, data } = chart;
          ctx.save();
          ctx.font = 'bold 10px sans-serif';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'bottom';
          const nBars = data.labels.length;
          for (let i = 0; i < nBars; i++) {
            if (!realizado[i]) continue;
            // Topo da barra = topo do segmento "A receber" (último dataset)
            const lastDs = chart.getDatasetMeta(data.datasets.length - 1);
            const bar    = lastDs.data[i];
            if (!bar) continue;
            // Linha única no topo: "R$ 1.882.242 — 2% rec."
            const pct      = totalRecebido[i] > 0
              ? ` — ${((totalRecebido[i] / realizado[i]) * 100).toFixed(0)}% rec.`
              : '';
            ctx.fillStyle = '#374151';
            const txtTotal = 'R$ ' + Math.round(realizado[i]).toLocaleString('pt-BR') + pct;
            ctx.fillText(txtTotal, bar.x, bar.y - 3);
          }
          ctx.restore();
        }
      }],
      options: {
        responsive: true,
        maintainAspectRatio: false,
        layout: { padding: { top: 28 } },
        interaction: { mode: 'index', intersect: false },
        plugins: {
          legend: {
            display: false,   // legenda removida a pedido do usuário
          },
          tooltip: {
            callbacks: {
              label: ctx => {
                const val = Number(ctx.parsed.y);
                if (!val) return null;
                const fmt = val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
                return ` ${ctx.dataset.label}: ${fmt}`;
              },
              afterBody: ctx => {
                // Rodapé do tooltip: total comprado e % recebido do mês
                const i = ctx[0]?.dataIndex;
                if (i == null) return [];
                const comprado  = realizado[i]       || 0;
                const recebido  = totalRecebido[i]   || 0;
                const pct       = comprado > 0 ? ((recebido / comprado) * 100).toFixed(1) : '0.0';
                const fmtC = comprado.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
                return [`─────────────────`, ` Total comprado: ${fmtC}`, ` Recebido: ${pct}%`];
              }
            }
          }
        },
        scales: {
          x: {
            stacked: true,
            ticks: { color: '#374151', font: { size: 11 }, maxRotation: 45 },
            grid: { display: false }
          },
          y: {
            stacked: true,
            ticks: {
              color: '#374151', font: { size: 11 },
              callback: v => 'R$ ' + (v >= 1000 ? (v / 1000).toFixed(0) + 'k' : v.toFixed(0))
            },
            grid: { color: '#e5e7eb' }
          }
        },
        onClick(event, elements) {
          if (!elements.length) return;
          const idx    = elements[0].index;
          const mesCompra = labels[idx];
          // Busca os filtros de data originais (para repassar ao endpoint de detalhe)
          const inicio = document.getElementById('graficoDataInicio')?.value || '';
          const fim    = document.getElementById('graficoDataFim')?.value    || '';
          exibirDetalheMeses(mesCompra, inicio, fim);
        }
      }
    });
  } catch (err) {
    console.error('[GraficoMeses] Erro:', err);
    if (loading) loading.style.display = 'none';
  }
}

window.carregarGraficoPizza      = carregarGraficoPizza;
window.carregarAmboGraficos      = carregarAmboGraficos;
window.alternarGrafico           = alternarGrafico;
window.carregarGraficoMeses      = carregarGraficoMeses;
window.exibirDetalheGraficoBarra = exibirDetalheGraficoBarra;
window.exibirDetalheMeses        = exibirDetalheMeses;
window.toggleDetalheMeses        = toggleDetalheMeses;
window.toggleGpiSub              = toggleGpiSub;

// ========================================
// Detalhe do gráfico de Meses (painel existente graficoPizzaDetalheWrapper)
// ========================================
let _detalheMesesCache = null;

/**
 * Ao clicar em uma barra do gráfico de meses, exibe o painel de detalhe
 * com as NFs recebidas (c_numero + n_valor_nfe + itens) e os pedidos
 * ainda a receber (c_numero + n_valor + itens).
 */
async function exibirDetalheMeses(mesCompra, dataInicio, dataFim) {
  const wrapper    = document.getElementById('graficoPizzaDetalheWrapper');
  const titulo     = document.getElementById('graficoPizzaDetalheTitulo');
  const tbody      = document.getElementById('graficoPizzaDetalheTbody');
  const catSection = document.getElementById('graficoCategoriaSection');
  if (!wrapper || !titulo || !tbody) return;

  if (catSection) catSection.style.display = 'none';
  titulo.innerHTML = `<i class="fa-solid fa-spinner fa-spin" style="margin-right:6px;color:#7c3aed;"></i>Carregando pedidos de ${mesCompra}...`;
  tbody.innerHTML  = '';
  wrapper.style.display = 'block';
  wrapper.scrollIntoView({ behavior: 'smooth', block: 'nearest' });

  try {
    const params = new URLSearchParams({ mesCompra });
    if (dataInicio) params.set('dataInicio', dataInicio);
    if (dataFim)    params.set('dataFim', dataFim);
    const resp = await fetch(`/api/compras/grafico-meses-detalhe?${params}`, { credentials: 'include' });
    const data = await resp.json();
    const recebidos  = data.recebidos  || [];
    const a_receber  = data.a_receber  || [];

    _detalheMesesCache = { mesCompra, recebidos, a_receber };
    if (catSection) {
      _carregarGraficoCategorias('Compra realizada', null, null, mesCompra, 'meses');
    }
    _renderDetalheMeses(mesCompra);
  } catch (err) {
    console.error('[DetalheMeses] Erro:', err);
    titulo.innerHTML = `<i class="fa-solid fa-triangle-exclamation" style="color:#ef4444;margin-right:6px;"></i>Erro ao carregar`;
    tbody.innerHTML = '<tr><td colspan="3" style="padding:16px;color:#ef4444;">Erro ao carregar detalhes.</td></tr>';
  }
}

function _renderDetalheMeses(mesCompra, catCodigo = null, catLabel = null) {
  const wrapper = document.getElementById('graficoPizzaDetalheWrapper');
  const titulo  = document.getElementById('graficoPizzaDetalheTitulo');
  const tbody   = document.getElementById('graficoPizzaDetalheTbody');
  const catSection = document.getElementById('graficoCategoriaSection');
  if (!wrapper || !titulo || !tbody || !_detalheMesesCache) return;

  if (catSection) catSection.style.display = 'block';

  const normCod = v => String(v || '').replace(/^0+/, '') || '0';
  const filtroCod = catCodigo ? normCod(catCodigo) : null;
  const recebidosOrig = _detalheMesesCache.recebidos || [];
  const aReceberOrig  = _detalheMesesCache.a_receber || [];
  const recebidos = filtroCod
    ? recebidosOrig.filter(r => normCod(r.c_cod_categ) === filtroCod)
    : recebidosOrig;
  const a_receber = filtroCod
    ? aReceberOrig.filter(p => normCod(p.c_cod_categ) === filtroCod)
    : aReceberOrig;

  titulo.innerHTML = `<i class="fa-solid fa-calendar-check" style="margin-right:6px;color:#7c3aed;"></i>Pedidos de ${mesCompra}${catLabel ? ` — ${catLabel}` : ''}`;

  if (!recebidos.length && !a_receber.length) {
    tbody.innerHTML = '<tr><td colspan="3" style="padding:20px;color:#6b7280;text-align:center;">Nenhum pedido encontrado.</td></tr>';
    return;
  }

  const fmt = v => Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  let html = '';

  if (recebidos.length) {
    const totalRecebidos = recebidos.reduce((s, r) => s + (r.n_valor_nfe || 0), 0);
    html += `<tr><td colspan="3" style="padding:10px 8px 4px;font-weight:700;color:#059669;font-size:13px;background:#f0fdf4;border-top:2px solid #6ee7b7;">
      <i class="fa-solid fa-circle-check" style="margin-right:5px;"></i>Recebidos — ${recebidos.length} NF(s) — ${fmt(totalRecebidos)}
    </td></tr>`;
    recebidos.forEach((nf, idx) => {
      const parentKey = `rec-${idx}`;
      const dtRec = nf.d_rec ? nf.d_rec.split('-').reverse().join('/') : '';
      html += `<tr style="background:#f9fafb;">
        <td style="padding:7px 12px;font-weight:600;color:#111827;font-size:13px;">
          <i class="fa-solid fa-file-invoice" style="color:#059669;margin-right:5px;"></i>Pedido ${nf.c_numero || '—'}
        </td>
        <td style="padding:7px 8px;color:#374151;font-size:12px;">Recebido: ${dtRec}</td>
        <td style="padding:7px 8px;text-align:right;color:#059669;font-weight:600;font-size:13px;">
          ${fmt(nf.n_valor_nfe)}
          <button onclick="toggleDetalheMeses('${parentKey}')" style="margin-left:8px;background:#e5e7eb;border:1px solid #d1d5db;border-radius:6px;padding:2px 8px;font-size:11px;color:#374151;cursor:pointer;">Expandir</button>
        </td>
      </tr>`;
      for (const item of (nf.itens || [])) {
        html += `<tr data-parent="${parentKey}" style="background:#fff;display:none;">
          <td style="padding:3px 8px 3px 28px;color:#6b7280;font-size:12px;" colspan="2">
            <span style="color:#374151;font-weight:500;">${item.c_codigo_produto || ''}</span>
            ${item.c_descricao_produto ? ` — ${item.c_descricao_produto}` : ''}
          </td>
          <td style="padding:3px 8px;text-align:right;color:#374151;font-size:12px;">${fmt(item.n_preco_unit)} × ${item.n_qtde_nfe || 1}</td>
        </tr>`;
      }
    });
  }

  if (a_receber.length) {
    const totalAReceber = a_receber.reduce((s, r) => s + (r.n_valor || 0), 0);
    html += `<tr><td colspan="3" style="padding:10px 8px 4px;font-weight:700;color:#3b82f6;font-size:13px;background:#eff6ff;border-top:2px solid #93c5fd;">
      <i class="fa-solid fa-clock" style="margin-right:5px;"></i>A receber — ${a_receber.length} pedido(s) — ${fmt(totalAReceber)}
    </td></tr>`;
    a_receber.forEach((ped, idx) => {
      const parentKey = `ped-${idx}`;
      const btnExpandir = `<button onclick="toggleDetalheMeses('${parentKey}', '${ped.c_numero || ''}')" style="margin-left:8px;background:#e5e7eb;border:1px solid #d1d5db;border-radius:6px;padding:2px 8px;font-size:11px;color:#374151;cursor:pointer;">Expandir</button>`;
      html += `<tr id="row-${parentKey}" style="background:#f9fafb;">
        <td style="padding:7px 12px;font-weight:600;color:#111827;font-size:13px;" colspan="2">
          <i class="fa-solid fa-cart-shopping" style="color:#3b82f6;margin-right:5px;"></i>Pedido ${ped.c_numero || '—'}
        </td>
        <td style="padding:7px 8px;text-align:right;color:#3b82f6;font-weight:600;font-size:13px;">
          ${fmt(ped.n_valor)}
          ${btnExpandir}
        </td>
      </tr>`;
    });
  }

  tbody.innerHTML = html;
}

async function toggleDetalheMeses(parentKey, cNumero) {
  const rows = document.querySelectorAll(`#graficoPizzaDetalheTbody tr[data-parent="${parentKey}"]`);
  if (rows.length) {
    const isHidden = rows[0].style.display === 'none';
    rows.forEach(row => { row.style.display = isHidden ? 'table-row' : 'none'; });
    const btn = document.querySelector(`button[onclick="toggleDetalheMeses('${parentKey}', '${cNumero || ''}')"]`);
    if (btn) btn.textContent = isHidden ? 'Ocultar' : 'Expandir';
    return;
  }

  if (!cNumero) return;
  const btn = document.querySelector(`button[onclick="toggleDetalheMeses('${parentKey}', '${cNumero}')"]`);
  if (btn) btn.textContent = 'Carregando...';

  try {
    const resp = await fetch(`/api/compras/pedido-omie-itens?cNumero=${encodeURIComponent(cNumero)}`, { credentials: 'include' });
    const data = await resp.json();
    const itens = data.itens || [];

    const parentRow = document.getElementById(`row-${parentKey}`);
    if (!parentRow) return;

    if (!itens.length) {
      const emptyRow = document.createElement('tr');
      emptyRow.setAttribute('data-parent', parentKey);
      emptyRow.style.background = '#fff';
      emptyRow.innerHTML = '<td colspan="3" style="padding:4px 8px 4px 28px;color:#9ca3af;font-size:12px;">Sem itens retornados pela Omie.</td>';
      parentRow.insertAdjacentElement('afterend', emptyRow);
    } else {
      const fmt = v => Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
      const rowsHtml = itens.map((item) => {
        const unidade = item.c_unidade ? ` ${item.c_unidade}` : '';
        return `
          <tr data-parent="${parentKey}" style="background:#fff;display:none;">
            <td style="padding:3px 8px 3px 28px;color:#6b7280;font-size:12px;" colspan="2">
              <span style="color:#374151;font-weight:500;">${item.c_produto || 'Item sem codigo'}</span>
              ${item.c_descricao ? ` — ${item.c_descricao}` : ''}
            </td>
            <td style="padding:3px 8px;text-align:right;color:#374151;font-size:12px;">
              ${fmt(item.n_val_unit)} × ${item.n_qtde || 1}${unidade}
            </td>
          </tr>
        `;
      }).join('');
      parentRow.insertAdjacentHTML('afterend', rowsHtml);
    }

    const newRows = document.querySelectorAll(`#graficoPizzaDetalheTbody tr[data-parent="${parentKey}"]`);
    newRows.forEach(row => { row.style.display = 'table-row'; });
    if (btn) btn.textContent = 'Ocultar';
  } catch (err) {
    console.error('[DetalheMeses/AReceber] Erro:', err);
    if (btn) btn.textContent = 'Expandir';
  }
}

// Objetivo: Exibir visualização em Kanban (padrão)
function mostrarVisualizacaoKanban() {
  // Não sobrescreve o painel de gráfico quando ele está ativo
  if (_modoGraficoAtivo) return;
  const kanbanContainer = document.getElementById('kanbanMinhasSolicitacoes');
  const listaContainer = document.getElementById('listaMinhasSolicitacoes');
  const botaoAlternar = document.getElementById('comprasAlternarVisualizacaoBtn');
  
  if (kanbanContainer) kanbanContainer.style.display = 'flex';
  if (listaContainer) listaContainer.style.display = 'none';
  if (botaoAlternar) {
    botaoAlternar.style.background = 'linear-gradient(135deg,#f59e0b 0%,#d97706 100%)';
    botaoAlternar.title = 'Alternar para Visualização em Lista';
    const icone = botaoAlternar.querySelector('i');
    if (icone) icone.className = 'fa-solid fa-columns';
  }
  // Recalcula altura após o display:flex ser renderizado
  requestAnimationFrame(() => {
    ajustarAlturaKanban();
    atualizarOffsetCabecalhoListaCompras();
  });
}

// Objetivo: Exibir visualização em Lista (tabela)
function mostrarVisualizacaoLista() {
  const kanbanContainer = document.getElementById('kanbanMinhasSolicitacoes');
  const listaContainer = document.getElementById('listaMinhasSolicitacoes');
  const botaoAlternar = document.getElementById('comprasAlternarVisualizacaoBtn');
  
  if (kanbanContainer) {
    kanbanContainer.style.display = 'none';
    // Remove height fixo para não reservar espaço quando o kanban estiver oculto
    kanbanContainer.style.height = '';
  }
  if (listaContainer) listaContainer.style.display = 'block';
  requestAnimationFrame(() => atualizarOffsetCabecalhoListaCompras());
  if (botaoAlternar) {
    botaoAlternar.style.background = 'linear-gradient(135deg,#8b5cf6 0%,#7c3aed 100%)';
    botaoAlternar.title = 'Alternar para Visualização em Kanban';
    const icone = botaoAlternar.querySelector('i');
    if (icone) icone.className = 'fa-solid fa-table';
  }
  
  // Renderiza a lista com dados dos kanbans
  renderizarLista();
  inicializarFiltroStatusColunaLista();
  inicializarFiltroSolicitanteColunaLista();
  requestAnimationFrame(() => atualizarOffsetCabecalhoListaCompras());
}

function normalizarTextoFluxoCompras(valor) {
  return String(valor || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ');
}

function normalizarRetornoSemCadastro(valor) {
  return normalizarTextoFluxoCompras(valor)
    .replace(/^🛒\s*/u, '')
    .trim();
}

const RETORNO_SEM_VALORES_NORMALIZADO = normalizarTextoFluxoCompras('Apenas realizar compra sem retorno de valores ou caracteristica');

const STATUS_PARA_ETAPA_COMPRAS = {
  'aguardando aprovacao da requisicao': 'Aprovação',
  'solicitado revisao': 'Revisão',
  retificar: 'Revisão',
  'aguardando cotacao': 'Cotação',
  'cotado aguardando escolha': 'Cotado',
  cotado: 'Cotado',
  'analise de cadastro': 'Organizando requisição',
  'aguardando compra preparacao': 'Requisições',
  requisicao: 'Requisições',
  'aguardando compra': 'Pedido de compra',
  'compra realizada': 'Compra realizada',
  'faturada pelo fornecedor': 'Faturado',
  recebido: 'Recebido',
  concluido: 'Concluído'
};

const FLUXOS_ETAPAS_COMPRAS = {
  solicitacao_requisicao: [
    'Aprovação',
    'Revisão',
    'Requisições',
    'Pedido de compra',
    'Compra realizada',
    'Faturado',
    'Recebido',
    'Concluído'
  ],
  solicitacao_cotacao: [
    'Aprovação',
    'Revisão',
    'Cotação',
    'Cotado',
    'Requisições',
    'Pedido de compra',
    'Compra realizada',
    'Faturado',
    'Recebido',
    'Concluído'
  ],
  sem_cadastro_analise: [
    'Aprovação',
    'Revisão',
    'Organizando requisição',
    'Requisições',
    'Pedido de compra',
    'Compra realizada',
    'Faturado',
    'Recebido',
    'Concluído'
  ],
  sem_cadastro_cotacao: [
    'Aprovação',
    'Revisão',
    'Cotação',
    'Cotado',
    'Organizando requisição',
    'Requisições',
    'Pedido de compra',
    'Compra realizada',
    'Faturado',
    'Recebido',
    'Concluído'
  ]
};

function retornoCotacaoIndicaCotacao(valor, tableSource = 'solicitacao_compras') {
  const sourceNormalizado = normalizarTextoFluxoCompras(tableSource);
  const retornoNormalizado = normalizarRetornoSemCadastro(valor);

  if (sourceNormalizado === 'compras_sem_cadastro') {
    return retornoNormalizado !== RETORNO_SEM_VALORES_NORMALIZADO;
  }

  return ['s', 'sim', 'yes', 'true', '1'].includes(retornoNormalizado);
}

function mapearStatusParaEtapaCompras(statusAtual) {
  const statusNormalizado = normalizarTextoFluxoCompras(statusAtual);
  return STATUS_PARA_ETAPA_COMPRAS[statusNormalizado] || null;
}

function inferirFluxoStatusCompras(statusAtual, itensRelacionados = []) {
  const statusNormalizado = normalizarTextoFluxoCompras(statusAtual);
  const temSemCadastro = itensRelacionados.some(
    item => normalizarTextoFluxoCompras(item?.table_source) === 'compras_sem_cadastro'
  );
  const retornoCotacaoValor = itensRelacionados
    .map(item => item?.retorno_cotacao)
    .find(valor => String(valor ?? '').trim() !== '') || '';
  const tableSourceReferencia = temSemCadastro ? 'compras_sem_cadastro' : 'solicitacao_compras';
  const retornoVaiParaCotacao = retornoCotacaoIndicaCotacao(retornoCotacaoValor, tableSourceReferencia);

  if (statusNormalizado === 'analise de cadastro') {
    return retornoVaiParaCotacao ? 'sem_cadastro_cotacao' : 'sem_cadastro_analise';
  }

  if (statusNormalizado === 'aguardando cotacao' || statusNormalizado === 'cotado aguardando escolha' || statusNormalizado === 'cotado') {
    return temSemCadastro ? 'sem_cadastro_cotacao' : 'solicitacao_cotacao';
  }

  if (temSemCadastro) {
    return retornoVaiParaCotacao ? 'sem_cadastro_cotacao' : 'sem_cadastro_analise';
  }

  return retornoVaiParaCotacao ? 'solicitacao_cotacao' : 'solicitacao_requisicao';
}

function obterItensRelacionadosLinhaLista(linha) {
  const cacheItens = Array.isArray(window.kanbanMinhasItens) ? window.kanbanMinhasItens : [];
  if (!cacheItens.length) return [];

  const idsRelacionados = String(linha?.todosIds || linha?.itemId || '')
    .split(',')
    .map(id => String(id || '').trim())
    .filter(Boolean);

  if (!idsRelacionados.length) return [];

  const itensRelacionados = cacheItens.filter(item => idsRelacionados.includes(String(item?.id)));
  if (itensRelacionados.length) return itensRelacionados;

  const itemUnico = cacheItens.find(item => String(item?.id) === String(linha?.itemId));
  return itemUnico ? [itemUnico] : [];
}

function renderizarFluxoStatusCompras(statusAtual, itensRelacionados = []) {
  const fluxo = inferirFluxoStatusCompras(statusAtual, itensRelacionados);
  const etapas = FLUXOS_ETAPAS_COMPRAS[fluxo] || FLUXOS_ETAPAS_COMPRAS.solicitacao_requisicao;
  const etapaAtual = mapearStatusParaEtapaCompras(statusAtual);
  const indiceAtual = etapaAtual
    ? etapas.findIndex(etapa => normalizarTextoFluxoCompras(etapa) === normalizarTextoFluxoCompras(etapaAtual))
    : -1;

  return `
    <div style="display:flex;align-items:center;gap:6px;overflow-x:auto;padding:2px 0 4px;max-width:100%;">
      ${etapas.map((etapa, idx) => {
        const concluida = indiceAtual >= 0 && idx < indiceAtual;
        const atual = idx === indiceAtual;
        const corFundo = concluida ? '#dcfce7' : (atual ? '#dbeafe' : '#f8fafc');
        const corTexto = concluida ? '#166534' : (atual ? '#1d4ed8' : '#64748b');
        const corBorda = concluida ? '#86efac' : (atual ? '#93c5fd' : '#d7dee8');
        const corDot = concluida ? '#16a34a' : (atual ? '#2563eb' : '#94a3b8');
        const corConector = indiceAtual >= 0 && idx < indiceAtual ? '#16a34a' : '#d1d5db';

        return `
          <span style="display:inline-flex;align-items:center;gap:6px;min-width:max-content;">
            <span style="display:inline-flex;align-items:center;gap:4px;padding:3px 8px;border-radius:999px;border:1px solid ${corBorda};background:${corFundo};color:${corTexto};font-size:10px;font-weight:${atual ? '700' : '600'};line-height:1;white-space:nowrap;box-shadow:${atual ? '0 0 0 2px rgba(37,99,235,0.12)' : 'none'};">
              <span style="width:8px;height:8px;border-radius:50%;background:${corDot};display:inline-block;flex-shrink:0;"></span>
              ${escapeHtml(etapa)}
            </span>
            ${idx < etapas.length - 1 ? `<span style="width:16px;height:2px;background:${corConector};border-radius:999px;display:inline-block;"></span>` : ''}
          </span>
        `;
      }).join('')}
    </div>
  `;
}

function obterMapaLinksNfeLista() {
  if (!(window.__comprasNfePdfCache instanceof Map)) {
    window.__comprasNfePdfCache = new Map();
  }
  return window.__comprasNfePdfCache;
}

function obterSetPendentesLinksNfeLista() {
  if (!(window.__comprasNfePdfPendentes instanceof Set)) {
    window.__comprasNfePdfPendentes = new Set();
  }
  return window.__comprasNfePdfPendentes;
}

function gerarChaveLinkNfeLista(numeroPedido, valorTotalNum) {
  const numero = String(numeroPedido || '').trim();
  const valorNum = Number(valorTotalNum);
  if (!/^\d+$/.test(numero)) return '';
  if (!Number.isFinite(valorNum) || valorNum <= 0) return '';
  return `${numero}|${valorNum.toFixed(2)}`;
}

function montarValorTotalComLinkNfe(linha) {
  const href = String(linha?.linkNfePdf || '').trim();
  const hrefSeguro = /^(https?:\/\/|\/)/i.test(href) ? href : '';
  if (!hrefSeguro) return linha?.valorTotal || '-';

  const tituloLink = linha?.linkNfeTitulo
    ? String(linha.linkNfeTitulo)
    : 'Abrir PDF da NF-e';

  return `
    <div style="display:inline-flex;align-items:center;justify-content:flex-end;gap:8px;width:100%;">
      <span>${linha.valorTotal || '-'}</span>
      <a
        href="${hrefSeguro}"
        target="_blank"
        rel="noopener"
        onclick="event.stopPropagation();"
        title="${escapeHtml(tituloLink)}"
        style="display:inline-flex;align-items:center;justify-content:center;width:22px;height:22px;border-radius:999px;border:1px solid #bfdbfe;background:#eff6ff;color:#2563eb;cursor:pointer;text-decoration:none;">
        <i class="fa-solid fa-link" style="font-size:10px;"></i>
      </a>
    </div>
  `;
}

function obterModalAssociarPedidoNfeEl() {
  return document.getElementById('modalAssociarPedidoNfe');
}

function fecharModalAssociarPedidoNfe() {
  const modal = obterModalAssociarPedidoNfeEl();
  if (!modal) return;
  modal.style.display = 'none';
}

function setStatusModalAssociarPedidoNfe(mensagem, tipo = 'info') {
  const statusEl = document.getElementById('modalAssociarPedidoNfeStatus');
  if (!statusEl) return;

  const estilos = {
    info: { bg: '#eff6ff', border: '#bfdbfe', color: '#1e40af' },
    sucesso: { bg: '#ecfdf5', border: '#bbf7d0', color: '#166534' },
    erro: { bg: '#fef2f2', border: '#fecaca', color: '#b91c1c' }
  };
  const tema = estilos[tipo] || estilos.info;

  statusEl.style.display = mensagem ? 'block' : 'none';
  statusEl.style.background = tema.bg;
  statusEl.style.border = `1px solid ${tema.border}`;
  statusEl.style.color = tema.color;
  statusEl.textContent = mensagem || '';
}

function limparEtapaPedidoModalAssociarNfe() {
  const blocoPedido = document.getElementById('modalAssociarPedidoNfeBlocoPedido');
  const pedidoInput = document.getElementById('modalAssociarPedidoNumeroInput');
  const previewWrap = document.getElementById('modalAssociarPedidoNfePreviewWrap');
  const previewConteudo = document.getElementById('modalAssociarPedidoNfePreviewConteudo');
  const btnAssociar = document.getElementById('modalAssociarPedidoBtnConfirmar');
  if (blocoPedido) blocoPedido.style.display = 'none';
  if (pedidoInput) pedidoInput.value = '';
  if (previewWrap) previewWrap.style.display = 'none';
  if (previewConteudo) previewConteudo.innerHTML = '';
  if (btnAssociar) btnAssociar.disabled = true;
  if (window.__associarNfeRecebimentoAtual) {
    window.__associarNfeRecebimentoAtual = null;
  }
  if (window.__associarNfePreviewAtual) {
    window.__associarNfePreviewAtual = null;
  }
}

function renderPreviewAssociacaoPedidoNfe(preview) {
  const previewWrap = document.getElementById('modalAssociarPedidoNfePreviewWrap');
  const previewConteudo = document.getElementById('modalAssociarPedidoNfePreviewConteudo');
  if (!previewWrap || !previewConteudo) return;

  const itens = Array.isArray(preview?.itens) ? preview.itens : [];
  const resumoHtml = `
    <div style="display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:8px;margin-bottom:10px;">
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:8px;">
        <div style="font-size:11px;color:#64748b;">NF-e</div>
        <div style="font-size:13px;font-weight:700;color:#0f172a;">${escapeHtml(String(preview?.numero_nfe || '-'))}</div>
      </div>
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:8px;">
        <div style="font-size:11px;color:#64748b;">Pedido</div>
        <div style="font-size:13px;font-weight:700;color:#0f172a;">${escapeHtml(String(preview?.c_numero_pedido || preview?.n_cod_ped || '-'))}</div>
      </div>
      <div style="background:#ecfdf5;border:1px solid #bbf7d0;border-radius:8px;padding:8px;">
        <div style="font-size:11px;color:#166534;">Itens com match</div>
        <div style="font-size:13px;font-weight:700;color:#166534;">${Number(preview?.itens_match_total || 0)}</div>
      </div>
      <div style="background:#fef2f2;border:1px solid #fecaca;border-radius:8px;padding:8px;">
        <div style="font-size:11px;color:#991b1b;">Itens sem match</div>
        <div style="font-size:13px;font-weight:700;color:#991b1b;">${Number(preview?.itens_sem_match_total || 0)}</div>
      </div>
    </div>
  `;

  const linhasHtml = itens.length
    ? itens.map((item) => {
        const encontrou = !!item?.pedido_item_encontrado;
        const criterio = item?.criterio_match === 'id_produto'
          ? 'ID produto'
          : (item?.criterio_match === 'codigo_produto' ? 'Código produto' : 'Sem match');
        return `
          <tr style="border-bottom:1px solid #e2e8f0;background:${encontrou ? '#f8fafc' : '#fff7ed'};">
            <td style="padding:6px 8px;font-size:11px;color:#0f172a;text-align:center;">${Number(item?.n_sequencia || 0) || '-'}</td>
            <td style="padding:6px 8px;font-size:11px;color:#0f172a;">${escapeHtml(String(item?.nf_codigo_produto || '-'))}</td>
            <td style="padding:6px 8px;font-size:11px;color:#0f172a;max-width:220px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;" title="${escapeHtml(String(item?.nf_descricao_produto || '-'))}">${escapeHtml(String(item?.nf_descricao_produto || '-'))}</td>
            <td style="padding:6px 8px;font-size:11px;color:#0f172a;">${escapeHtml(String(item?.pedido_codigo_produto || '-'))}</td>
            <td style="padding:6px 8px;font-size:11px;color:#0f172a;max-width:220px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;" title="${escapeHtml(String(item?.pedido_descricao_produto || '-'))}">${escapeHtml(String(item?.pedido_descricao_produto || '-'))}</td>
            <td style="padding:6px 8px;font-size:11px;text-align:center;color:${encontrou ? '#166534' : '#9a3412'};font-weight:700;">${escapeHtml(criterio)}</td>
          </tr>
        `;
      }).join('')
    : '<tr><td colspan="6" style="padding:8px;font-size:11px;color:#64748b;text-align:center;">Sem itens para pré-visualização.</td></tr>';

  previewConteudo.innerHTML = `
    ${resumoHtml}
    <div style="max-height:210px;overflow:auto;border:1px solid #e2e8f0;border-radius:8px;">
      <table style="width:100%;border-collapse:collapse;">
        <thead>
          <tr style="position:sticky;top:0;background:#f8fafc;border-bottom:1px solid #e2e8f0;">
            <th style="padding:6px 8px;font-size:11px;color:#334155;text-align:center;">Seq</th>
            <th style="padding:6px 8px;font-size:11px;color:#334155;text-align:left;">Código NF</th>
            <th style="padding:6px 8px;font-size:11px;color:#334155;text-align:left;">Descrição NF</th>
            <th style="padding:6px 8px;font-size:11px;color:#334155;text-align:left;">Código Pedido</th>
            <th style="padding:6px 8px;font-size:11px;color:#334155;text-align:left;">Descrição Pedido</th>
            <th style="padding:6px 8px;font-size:11px;color:#334155;text-align:center;">Match</th>
          </tr>
        </thead>
        <tbody>${linhasHtml}</tbody>
      </table>
    </div>
  `;

  previewWrap.style.display = 'block';
}

async function previsualizarAssociacaoPedidoNfeOmie() {
  const nfeInput = document.getElementById('modalAssociarNfeNumeroInput');
  const pedidoInput = document.getElementById('modalAssociarPedidoNumeroInput');
  const btnPreview = document.getElementById('modalAssociarPedidoBtnPreview');
  const btnAssociar = document.getElementById('modalAssociarPedidoBtnConfirmar');

  if (!nfeInput || !pedidoInput || !btnPreview || !btnAssociar) return;

  const numeroNfe = String(nfeInput.value || '').trim();
  const numeroPedido = String(pedidoInput.value || '').trim();

  if (!numeroNfe) {
    setStatusModalAssociarPedidoNfe('Informe o número da NF-e.', 'erro');
    return;
  }
  if (!numeroPedido) {
    setStatusModalAssociarPedidoNfe('Informe o número do pedido para gerar a prévia.', 'erro');
    return;
  }

  const textoOriginal = btnPreview.innerHTML;
  btnPreview.disabled = true;
  btnAssociar.disabled = true;
  btnPreview.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';
  setStatusModalAssociarPedidoNfe('Gerando prévia dos itens da NF-e e do pedido...', 'info');

  try {
    const resp = await fetch('/api/compras/pedidos-omie/nfe-associar-pedido/preview', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        numero_nfe: numeroNfe,
        numero_pedido: numeroPedido
      })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data?.ok) {
      throw new Error(data?.error || `Falha ao gerar prévia (HTTP ${resp.status})`);
    }

    window.__associarNfePreviewAtual = {
      numeroNfe,
      numeroPedido,
      preview: data.preview
    };

    renderPreviewAssociacaoPedidoNfe(data.preview);

    if (Number(data?.preview?.itens_sem_match_total || 0) > 0) {
      setStatusModalAssociarPedidoNfe('Prévia gerada. Existem itens sem match; revise antes de confirmar.', 'erro');
    } else {
      setStatusModalAssociarPedidoNfe('Prévia gerada. Itens prontos para associação.', 'sucesso');
    }

    btnAssociar.disabled = false;
  } catch (err) {
    setStatusModalAssociarPedidoNfe(err?.message || 'Erro ao gerar prévia de associação.', 'erro');
  } finally {
    btnPreview.disabled = false;
    btnPreview.innerHTML = textoOriginal;
  }
}

async function localizarNfeParaAssociacaoOmie() {
  const nfeInput = document.getElementById('modalAssociarNfeNumeroInput');
  const btnLocalizar = document.getElementById('modalAssociarNfeBtnLocalizar');
  const blocoPedido = document.getElementById('modalAssociarPedidoNfeBlocoPedido');

  if (!nfeInput || !btnLocalizar || !blocoPedido) return;

  const numeroNfe = String(nfeInput.value || '').trim();
  if (!numeroNfe) {
    setStatusModalAssociarPedidoNfe('Informe o número da NF-e para localizar.', 'erro');
    return;
  }

  limparEtapaPedidoModalAssociarNfe();
  setStatusModalAssociarPedidoNfe('Localizando NF-e na Omie...', 'info');

  const textoOriginal = btnLocalizar.innerHTML;
  btnLocalizar.disabled = true;
  btnLocalizar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';

  try {
    const resp = await fetch('/api/compras/pedidos-omie/nfe-associar-pedido/consultar', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ numero_nfe: numeroNfe })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data?.ok) {
      throw new Error(data?.error || `Falha ao consultar NF-e (HTTP ${resp.status})`);
    }

    window.__associarNfeRecebimentoAtual = data?.recebimento || null;
    blocoPedido.style.display = 'block';

    const numeroNfeEncontrada = data?.recebimento?.c_numero_nfe || numeroNfe;
    const pedidosJaVinculados = Array.isArray(data?.recebimento?.pedidos_vinculados)
      ? data.recebimento.pedidos_vinculados.filter(Boolean)
      : [];

    if (pedidosJaVinculados.length > 0) {
      setStatusModalAssociarPedidoNfe(
        `NF-e ${numeroNfeEncontrada} localizada. Já vinculada aos pedidos: ${pedidosJaVinculados.join(', ')}.`,
        'info'
      );
    } else {
      setStatusModalAssociarPedidoNfe(`NF-e ${numeroNfeEncontrada} localizada. Informe o pedido para associar.`, 'sucesso');
    }

    const pedidoInput = document.getElementById('modalAssociarPedidoNumeroInput');
    if (pedidoInput) pedidoInput.focus();
  } catch (err) {
    setStatusModalAssociarPedidoNfe(err?.message || 'Erro ao localizar NF-e na Omie.', 'erro');
  } finally {
    btnLocalizar.disabled = false;
    btnLocalizar.innerHTML = textoOriginal;
  }
}

async function confirmarAssociacaoPedidoNfeOmie() {
  const nfeInput = document.getElementById('modalAssociarNfeNumeroInput');
  const pedidoInput = document.getElementById('modalAssociarPedidoNumeroInput');
  const btnAssociar = document.getElementById('modalAssociarPedidoBtnConfirmar');

  if (!nfeInput || !pedidoInput || !btnAssociar) return;

  const numeroNfe = String(nfeInput.value || '').trim();
  const numeroPedido = String(pedidoInput.value || '').trim();

  if (!numeroNfe) {
    setStatusModalAssociarPedidoNfe('Informe o número da NF-e.', 'erro');
    return;
  }
  if (!numeroPedido) {
    setStatusModalAssociarPedidoNfe('Informe o número do pedido para associar.', 'erro');
    return;
  }

  const previewAtual = window.__associarNfePreviewAtual;
  const previewValida = !!previewAtual
    && String(previewAtual.numeroNfe || '').trim() === numeroNfe
    && String(previewAtual.numeroPedido || '').trim() === numeroPedido;

  if (!previewValida) {
    setStatusModalAssociarPedidoNfe('Gere a prévia atualizada antes de confirmar a associação.', 'erro');
    await previsualizarAssociacaoPedidoNfeOmie();
    return;
  }

  const confirmar = window.confirm(`Confirma associar a NF-e ${numeroNfe} ao pedido ${numeroPedido} na Omie após revisar a prévia?`);
  if (!confirmar) return;

  const textoOriginal = btnAssociar.innerHTML;
  btnAssociar.disabled = true;
  btnAssociar.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';
  setStatusModalAssociarPedidoNfe('Associando NF-e ao pedido na Omie...', 'info');

  try {
    const resp = await fetch('/api/compras/pedidos-omie/nfe-associar-pedido', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        numero_nfe: numeroNfe,
        numero_pedido: numeroPedido
      })
    });

    const data = await resp.json().catch(() => ({}));
    if (!resp.ok || !data?.ok) {
      throw new Error(data?.error || `Falha ao associar NF-e (HTTP ${resp.status})`);
    }

    setStatusModalAssociarPedidoNfe(
      data?.message || `NF-e ${numeroNfe} associada com sucesso ao pedido ${numeroPedido}.`,
      'sucesso'
    );
  } catch (err) {
    setStatusModalAssociarPedidoNfe(err?.message || 'Erro ao associar NF-e ao pedido.', 'erro');
  } finally {
    btnAssociar.disabled = false;
    btnAssociar.innerHTML = textoOriginal;
  }
}

