        'compra realizada': { ...paletaKanbanAzul, icon: 'fa-check-circle' },
        'faturada pelo fornecedor': { ...paletaKanbanAzul, icon: 'fa-file-invoice-dollar' },
        'recebido': { ...paletaKanbanAzul, icon: 'fa-box-open' },
