async function loadEngenhariaLista() {
  const tbody = document.getElementById('engTbody');
  const spinner = document.getElementById('engSpinner');
  if (!tbody) return;
  try {
    if (spinner) spinner.style.display = 'block';
    tbody.innerHTML = '<tr><td colspan="5" style="padding:20px 12px;text-align:center;color:#6b7280;">Carregando...</td></tr>';
    const resp = await fetch('/api/engenharia/em-criacao', { credentials: 'include' });
    if (!resp.ok) throw new Error('Falha ao buscar lista');
    const data = await resp.json();
    const itens = Array.isArray(data.itens) ? data.itens : [];
    if (!itens.length) {
      tbody.innerHTML = '<tr><td colspan="5" style="padding:28px 12px;text-align:center;color:#6b7280;">Nenhum produto em criação encontrado.</td></tr>';
      return;
    }
    tbody.innerHTML = '';
    itens.forEach(p => {
      const tr = document.createElement('tr');
      tr.dataset.codigo = p.codigo;
      
      // GRÁFICO CIRCULAR (CADASTRO): Usa dados de COMPLETUDE (campos obrigatórios)
      const pctCompletude = Number(p.completude_percentual) || 0;
      const totalCompletude = Number(p.completude_total) || 0;
      const concluidasCompletude = Number(p.completude_concluidas) || 0;
      
      // BARRA DE PROGRESSO (TAREFAS): Usa dados de ENGENHARIA (atividades Check-Proj)
      const pctEng = Number(p.eng_percentual) || 0;
      const totalEng = Number(p.eng_total) || 0;
      const concluidasEng = Number(p.eng_concluidas) || 0;
      
      // BARRA DE PROGRESSO (COMPRAS): Usa dados de COMPRAS (atividades Check-Compras)
      const pctCompras = Number(p.compras_percentual) || 0;
      const totalCompras = Number(p.compras_total) || 0;
      const concluidasCompras = Number(p.compras_concluidas) || 0;
      
      // Cor do círculo baseada na completude
      let corCirculo = '#dc2626'; // vermelho
      let corTextoCirculo = '#dc2626';
      if (pctCompletude === 100) {
        corCirculo = '#16a34a'; // verde escuro
        corTextoCirculo = '#16a34a';
      } else if (pctCompletude >= 70) {
        corCirculo = '#22c55e'; // verde claro
        corTextoCirculo = '#16a34a';
      } else if (pctCompletude >= 40) {
        corCirculo = '#f59e0b'; // amarelo
        corTextoCirculo = '#d97706';
      }
      
      // Cor da barra baseada nas atividades de engenharia
      let corBarra = '#dc2626'; // vermelho
      let corTextoBarra = '#dc2626';
      if (pctEng === 100) {
        corBarra = '#16a34a'; // verde escuro
        corTextoBarra = '#16a34a';
      } else if (pctEng >= 70) {
        corBarra = '#22c55e'; // verde claro
        corTextoBarra = '#16a34a';
      } else if (pctEng >= 40) {
        corBarra = '#f59e0b'; // amarelo
        corTextoBarra = '#d97706';
      }
      
      // Cor da barra de compras
      let corBarraCompras = '#dc2626'; // vermelho
      let corTextoBarraCompras = '#dc2626';
      if (pctCompras === 100) {
        corBarraCompras = '#16a34a'; // verde escuro
        corTextoBarraCompras = '#16a34a';
      } else if (pctCompras >= 70) {
        corBarraCompras = '#22c55e'; // verde claro
        corTextoBarraCompras = '#16a34a';
      } else if (pctCompras >= 40) {
        corBarraCompras = '#f59e0b'; // amarelo
        corTextoBarraCompras = '#d97706';
      }
      
      // Cálculo do stroke-dashoffset para o círculo (circunferência = 2πr = 125.6 para r=20)
      const circumference = 125.6;
      const offset = circumference - (pctCompletude / 100) * circumference;
      
      // HTML da coluna CADASTRO (gráfico circular + botão expandir)
      const cadastroHtml = totalCompletude > 0 ? `
        <div style="display:flex;justify-content:center;align-items:center;gap:8px;">
          <svg width="50" height="50" viewBox="0 0 50 50" title="Completude: ${concluidasCompletude}/${totalCompletude} campos (${pctCompletude}%)">
            <circle cx="25" cy="25" r="20" fill="none" stroke="#e5e7eb" stroke-width="4"/>
            <circle cx="25" cy="25" r="20" fill="none" 
                    stroke="${corCirculo}" stroke-width="4" stroke-linecap="round"
                    stroke-dasharray="125.6" stroke-dashoffset="${offset}"
                    transform="rotate(-90 25 25)"
                    style="transition: stroke-dashoffset 0.5s ease;"/>
            <text x="25" y="29" text-anchor="middle" 
                  font-size="11" font-weight="bold" fill="${corTextoCirculo}">${pctCompletude}%</text>
          </svg>
          <button class="btn-expand-cadastro" data-codigo="${p.codigo}" style="background:none;border:none;cursor:pointer;padding:4px;color:#6b7280;font-size:16px;" title="Expandir detalhes">
            <i class="fa-solid fa-chevron-down"></i>
          </button>
        </div>
      ` : '<span style="font-size:12px;color:#9ca3af;">-</span>';
      
      // HTML da coluna ENGENHARIA (barra de progresso + botão expandir)
      const tarefasHtml = totalEng > 0 ? `
        <div style="display:flex;align-items:center;gap:8px;">
          <div style="flex:1;background:#e5e7eb;height:8px;border-radius:4px;overflow:hidden;" title="Check-Proj: ${concluidasEng}/${totalEng} atividades (${pctEng}%)">
            <div style="width:${pctEng}%;height:100%;background:${corBarra};transition:width 0.3s;"></div>
          </div>
          <span style="font-size:12px;font-weight:600;color:${corTextoBarra};min-width:70px;text-align:right;">${concluidasEng}/${totalEng} (${pctEng}%)</span>
          <button class="btn-expand-engenharia" data-codigo="${p.codigo}" style="background:none;border:none;cursor:pointer;padding:4px;color:#6b7280;font-size:16px;" title="Expandir detalhes">
            <i class="fa-solid fa-chevron-down"></i>
          </button>
        </div>
      ` : '<span style="font-size:12px;color:#9ca3af;">Sem atividades</span>';
      
      // HTML da coluna COMPRAS (barra de progresso + botão expandir)
      const comprasHtml = totalCompras > 0 ? `
        <div style="display:flex;align-items:center;gap:8px;">
          <div style="flex:1;background:#e5e7eb;height:8px;border-radius:4px;overflow:hidden;" title="Check-Compras: ${concluidasCompras}/${totalCompras} atividades (${pctCompras}%)">
            <div style="width:${pctCompras}%;height:100%;background:${corBarraCompras};transition:width 0.3s;"></div>
          </div>
          <span style="font-size:12px;font-weight:600;color:${corTextoBarraCompras};min-width:70px;text-align:right;">${concluidasCompras}/${totalCompras} (${pctCompras}%)</span>
          <button class="btn-expand-compras" data-codigo="${p.codigo}" style="background:none;border:none;cursor:pointer;padding:4px;color:#6b7280;font-size:16px;" title="Expandir detalhes">
            <i class="fa-solid fa-chevron-down"></i>
          </button>
        </div>
      ` : '<span style="font-size:12px;color:#9ca3af;">Sem atividades</span>';
      
      tr.innerHTML = `
        <td class="td-clickable" data-codigo="${p.codigo}" style="padding:8px 12px;border-bottom:1px solid var(--border-color);font-size:13px;white-space:nowrap;cursor:pointer;">${p.codigo}</td>
        <td class="td-clickable" data-codigo="${p.codigo}" style="padding:8px 12px;border-bottom:1px solid var(--border-color);font-size:13px;cursor:pointer;">${p.descricao}</td>
        <td style="padding:8px 12px;border-bottom:1px solid var(--border-color);text-align:center;">${cadastroHtml}</td>
        <td style="padding:8px 12px;border-bottom:1px solid var(--border-color);">${tarefasHtml}</td>
        <td style="padding:8px 12px;border-bottom:1px solid var(--border-color);">${comprasHtml}</td>
      `;
      tr.dataset.codigo = p.codigo;
      tbody.appendChild(tr);
    });
    
    // Event handlers para células clicáveis (código e descrição)
    tbody.querySelectorAll('.td-clickable').forEach(td => {
      td.addEventListener('click', (e) => {
        e.stopPropagation();
        const codigo = td.dataset.codigo;
        if (codigo) window.openProdutoPorCodigo(codigo);
      });
    });
    
    // Event handlers para botões de expandir
    tbody.querySelectorAll('.btn-expand-cadastro').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        await toggleExpandCadastro(btn);
      });
    });
    
    tbody.querySelectorAll('.btn-expand-engenharia').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        await toggleExpandEngenharia(btn);
      });
    });
    
    tbody.querySelectorAll('.btn-expand-compras').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        await toggleExpandCompras(btn);
      });
    });
    
  } catch (err) {
    console.error('[Engenharia] Erro ao carregar lista:', err);
    tbody.innerHTML = '<tr><td colspan="5" style="padding:28px 12px;text-align:center;color:#dc2626;">Erro ao carregar lista.</td></tr>';
  } finally {
    if (spinner) spinner.style.display = 'none';
  }
}

// Handler clique da guia Engenharia
function openEngenharia() {
  // Remove active de outros links top
  document.querySelectorAll('.header .menu-link').forEach(a=>a.classList.remove('is-active'));
  const link = document.getElementById('menu-engenharia');
  if (link) link.classList.add('is-active');

  // Esconde inicio e produtoTabs se estiverem visíveis
  const inicioPane = document.getElementById('paginaInicio');
  if (inicioPane) inicioPane.style.display = 'none';
  const prodTabs = document.getElementById('produtoTabs');
  if (prodTabs) prodTabs.style.display = 'none';

  // Esconde qualquer .tab-pane aberto
  document.querySelectorAll('.tab-pane').forEach(p => p.style.display = 'none');

  // Mostra engenharia
  const pane = document.getElementById('engenhariaPane');
  if (pane) pane.style.display = 'block';
  // Atualiza hash para evitar scripts que reabrem produto
  try { location.hash = '#engenharia'; } catch(_){}

  // SEMPRE recarrega a lista para garantir dados atualizados
  loadEngenhariaLista();
}

const engLink = document.getElementById('menu-engenharia');
engLink?.addEventListener('click', (e) => {
  e.preventDefault();
  e.stopPropagation(); // evita outros handlers abrirem produto
  openEngenharia();
}, true); // captura primeiro

// Expor para outros módulos se necessário
window.openEngenharia = openEngenharia;

// ========== Interceptar navegadores antigos para "Início" ==========
(function interceptarNavigateToDetalhes() {
  const prev = window.navigateToDetalhes;
  window.navigateToDetalhes = function patchedNavigateToDetalhes(target, codigo) {
    // se vierem pedindo "iniciar" com código, redireciona para Produto
    if (codigo && (String(target).toLowerCase() === 'iniciar' || String(target).toLowerCase() === 'inicio')) {
      return window.openProdutoPorCodigo(codigo);
    }
    if (typeof prev === 'function') return prev(target, codigo);
  };
})();

// ─────────────────────────────────────────────────────────────────────────────
// Gerenciamento de grupos de Operação na Estrutura de Produto
// Botão + (mover itens selecionados) e ✏️ (renomear toda operação)
// ─────────────────────────────────────────────────────────────────────────────
function _wireOpGroupButtons(ul, paiCodigo) {
  // esc local para uso dentro desta função (não herda escopo de loadEstruturaProduto)
  const esc = s => String(s ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#x27;'}[c]));

  // Cache de operações (carregado uma vez por sessão de visualização)
  let _opCache = null;
  async function _fetchOps() {
    if (_opCache) return _opCache;
    try {
      const r = await fetch('/api/pcp/operacoes');
      const j = await r.json();
      // Filtra entradas com caracter de substituição (encoding corrompido no banco)
      _opCache = Array.isArray(j.operacoes)
        ? j.operacoes.filter(o => !o.includes('\uFFFD'))
        : [];
    } catch { _opCache = []; }
    return _opCache;
  }

  // Constrói e posiciona um dropdown de operações perto do botão clicado
  function _mostrarDropdownOp(anchorEl, opcoes, onSelect) {
    // remove dropdown anterior se houver
    document.getElementById('_op-dropdown')?.remove();

    const dd = document.createElement('div');
    dd.id = '_op-dropdown';
    dd.style.cssText = `
      position:fixed; z-index:9999; background:#fff; border:1px solid #d1d5db;
      border-radius:8px; box-shadow:0 4px 16px rgba(0,0,0,.18); min-width:220px;
      max-height:280px; overflow-y:auto; padding:4px 0; font-size:13px;
      color:#1f2937;
    `;

    opcoes.forEach(op => {
      const it = document.createElement('div');
      it.style.cssText = 'padding:8px 14px; cursor:pointer; white-space:nowrap; color:#1f2937;';
      it.textContent = op;
      it.addEventListener('mouseenter', () => { it.style.background = '#f3f4f6'; it.style.color = '#111827'; });
      it.addEventListener('mouseleave', () => { it.style.background = ''; it.style.color = '#1f2937'; });
      it.addEventListener('click', () => { dd.remove(); onSelect(op); });
      dd.appendChild(it);
    });

    // Posiciona próximo ao âncora
    document.body.appendChild(dd);
    const rect = anchorEl.getBoundingClientRect();
    const ddH = Math.min(280, opcoes.length * 37 + 8);
    const top = rect.bottom + 4 + ddH > window.innerHeight
      ? rect.top - ddH - 4
      : rect.bottom + 4;
    dd.style.top  = top + 'px';
    dd.style.left = Math.min(rect.left, window.innerWidth - 240) + 'px';

    // fecha ao clicar fora
    const close = (e) => { if (!dd.contains(e.target)) { dd.remove(); document.removeEventListener('mousedown', close); } };
    setTimeout(() => document.addEventListener('mousedown', close), 50);
  }

  // Retorna todos os <li> de itens que pertencem a um grupo de operação
  function _getItensDoGrupo(opGrupo) {
    return Array.from(ul.querySelectorAll(`li[data-op-grupo="${CSS.escape(opGrupo)}"]`));
  }

  // Entra no modo de seleção de checkboxes para o grupo
  function _entrarModoSelecao(opGrupo, opSelecionada) {
    // Mostra checkboxes nos itens do grupo
    const itens = _getItensDoGrupo(opGrupo);
    itens.forEach(li => {
      const chk = li.querySelector('.item-chk');
      if (chk) { chk.style.display = 'inline-block'; }
    });

    // Insere barra de ação (Selecionar tudo / Salvar / Cancelar) na cat-header
    const catHeader = ul.querySelector(`li.category-header[data-op-grupo="${CSS.escape(opGrupo)}"]`);
    if (!catHeader) return;

    // Remove barra anterior se existir
    catHeader.querySelector('.cat-op-bar')?.remove();

    const SVG_OK     = `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg>`;
    const SVG_CANCEL = `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" aria-hidden="true"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>`;
    const SVG_SPIN   = `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" style="animation:_spin .7s linear infinite;display:block"><circle cx="12" cy="12" r="9" stroke-opacity=".25"/><path d="M12 3a9 9 0 0 1 9 9"/></svg>`;

    const bar = document.createElement('div');
    bar.className = 'cat-op-bar';
    bar.style.cssText = 'display:flex; gap:6px; align-items:center; margin-top:4px; width:100%; flex-wrap:wrap;';
    bar.innerHTML = `
      <label style="display:flex;align-items:center;gap:4px;font-size:12px;cursor:pointer;">
        <input type="checkbox" id="_chk-all-${CSS.escape(opGrupo)}" style="margin:0"> Todos
      </label>
      <span style="font-size:11px;color:#9ca3af;flex:1">→ <strong style="color:#e5e7eb">${esc(opSelecionada)}</strong></span>
      <button type="button" class="cat-btn cat-btn-salvar" title="Salvar" aria-label="Salvar" style="background:#15803d;color:#fff;width:26px;height:26px;border-radius:6px;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;padding:0;">${SVG_OK}</button>
      <button type="button" class="cat-btn cat-btn-cancelar" title="Cancelar" aria-label="Cancelar" style="background:#374151;color:#e5e7eb;width:26px;height:26px;border-radius:6px;border:1px solid rgba(255,255,255,.12);cursor:pointer;display:flex;align-items:center;justify-content:center;padding:0;">${SVG_CANCEL}</button>
    `;
    catHeader.appendChild(bar);

    // "Todos" checkbox
    const chkAll = bar.querySelector(`#_chk-all-${CSS.escape(opGrupo)}`);
    chkAll?.addEventListener('change', () => {
      itens.forEach(li => {
        const c = li.querySelector('.item-chk');
        if (c) c.checked = chkAll.checked;
      });
    });

    // Cancelar
    bar.querySelector('.cat-btn-cancelar')?.addEventListener('click', () => _sairModoSelecao(opGrupo));

    // Salvar
    bar.querySelector('.cat-btn-salvar')?.addEventListener('click', async () => {
      const selecionados = itens
        .filter(li => li.querySelector('.item-chk')?.checked)
        .map(li => li.dataset.comp)
        .filter(Boolean);

      if (!selecionados.length) {
        alert('Selecione ao menos um item.');
        return;
      }

      const salvarBtn = bar.querySelector('.cat-btn-salvar');
      salvarBtn.disabled = true;
      salvarBtn.innerHTML = SVG_SPIN;

      try {
        const resp = await fetch('/api/pcp/estrutura/operacao', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ pai_codigo: paiCodigo, codigos: selecionados, nova_operacao: opSelecionada })
        });
        const j = await resp.json();
        if (j.ok) {
          window.loadEstruturaProduto(paiCodigo);
        } else {
          alert('Erro ao salvar: ' + (j.error || 'desconhecido'));
          salvarBtn.disabled = false;
          salvarBtn.innerHTML = SVG_OK;
        }
      } catch (err) {
        alert('Falha na requisição: ' + err.message);
        salvarBtn.disabled = false;
        salvarBtn.innerHTML = SVG_OK;
      }
    });
  }

  function _sairModoSelecao(opGrupo) {
    // Esconde checkboxes em TODOS os itens (pode estar em modo "trazer")
    ul.querySelectorAll('li[data-op-grupo]').forEach(li => {
      const chk = li.querySelector('.item-chk');
      if (chk) { chk.style.display = 'none'; chk.checked = false; }
    });
    // Remove barras de ação de TODOS os headers (garante limpeza)
    ul.querySelectorAll('li.category-header .cat-op-bar').forEach(b => b.remove());
  }

  // Modo "Trazer itens": mostra checkboxes em TODOS os itens de TODOS os grupos
  function _entrarModoTrazer(opGrupoDestino, opDestinoRaw) {
    const SVG_OK     = `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg>`;
    const SVG_CANCEL = `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" aria-hidden="true"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>`;
    const SVG_SPIN   = `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" style="animation:_spin .7s linear infinite;display:block"><circle cx="12" cy="12" r="9" stroke-opacity=".25"/><path d="M12 3a9 9 0 0 1 9 9"/></svg>`;

    // Limpa qualquer modo anterior
    _sairModoSelecao(opGrupoDestino);

    // Mostra checkboxes em TODOS os itens de TODOS os grupos (exceto o grupo destino)
    ul.querySelectorAll('li[data-op-grupo]').forEach(li => {
      if (li.dataset.opGrupo === opGrupoDestino) return; // não mostra no próprio grupo destino
      const chk = li.querySelector('.item-chk');
      if (chk) chk.style.display = 'inline-block';
    });

    // Barra de ação no header do grupo destino
    const catHeader = ul.querySelector(`li.category-header[data-op-grupo="${CSS.escape(opGrupoDestino)}"]`);
    if (!catHeader) return;
    catHeader.querySelector('.cat-op-bar')?.remove();

    const bar = document.createElement('div');
    bar.className = 'cat-op-bar';
    bar.style.cssText = 'display:flex; gap:6px; align-items:center; margin-top:4px; width:100%; flex-wrap:wrap;';
    bar.innerHTML = `
      <label style="display:flex;align-items:center;gap:4px;font-size:12px;cursor:pointer;">
        <input type="checkbox" id="_chk-trazer-all" style="margin:0"> Todos
      </label>
      <span style="font-size:11px;color:#9ca3af;flex:1">→ <strong style="color:#e5e7eb">${esc(opGrupoDestino)}</strong></span>
      <button type="button" class="cat-btn cat-btn-salvar" title="Mover para cá" aria-label="Mover para cá" style="background:#15803d;color:#fff;width:26px;height:26px;border-radius:6px;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;padding:0;">${SVG_OK}</button>
      <button type="button" class="cat-btn cat-btn-cancelar" title="Cancelar" aria-label="Cancelar" style="background:#374151;color:#e5e7eb;width:26px;height:26px;border-radius:6px;border:1px solid rgba(255,255,255,.12);cursor:pointer;display:flex;align-items:center;justify-content:center;padding:0;">${SVG_CANCEL}</button>
    `;
    catHeader.appendChild(bar);

    // Todos
    bar.querySelector('#_chk-trazer-all')?.addEventListener('change', (ev) => {
      ul.querySelectorAll('li[data-op-grupo]').forEach(li => {
        if (li.dataset.opGrupo === opGrupoDestino) return;
        const c = li.querySelector('.item-chk');
        if (c) c.checked = ev.target.checked;
      });
    });

    // Cancelar
    bar.querySelector('.cat-btn-cancelar')?.addEventListener('click', () => _sairModoSelecao(opGrupoDestino));

    // Salvar
    bar.querySelector('.cat-btn-salvar')?.addEventListener('click', async () => {
      const selecionados = Array.from(ul.querySelectorAll('li[data-op-grupo] .item-chk:checked'))
        .map(chk => chk.closest('li[data-op-grupo]')?.dataset.comp)
        .filter(Boolean);

      if (!selecionados.length) { alert('Selecione ao menos um item.'); return; }

      const salvarBtn = bar.querySelector('.cat-btn-salvar');
      salvarBtn.disabled = true;
      salvarBtn.innerHTML = SVG_SPIN;

      try {
        const resp = await fetch('/api/pcp/estrutura/operacao', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ pai_codigo: paiCodigo, codigos: selecionados, nova_operacao: opDestinoRaw })
        });
        const j = await resp.json();
        if (j.ok) {
          window.loadEstruturaProduto(paiCodigo);
        } else {
          alert('Erro ao mover: ' + (j.error || 'desconhecido'));
          salvarBtn.disabled = false; salvarBtn.innerHTML = SVG_OK;
        }
      } catch (err) {
        alert('Falha na requisição: ' + err.message);
        salvarBtn.disabled = false; salvarBtn.innerHTML = SVG_OK;
      }
    });
  }

  // Delegação de cliques nos botões dos category-headers
  ul.addEventListener('click', async (e) => {
    const btnMover  = e.target.closest('.cat-btn-mover');
    const btnRename = e.target.closest('.cat-btn-rename');
    const btnTrazer = e.target.closest('.cat-btn-trazer');
    if (!btnMover && !btnRename && !btnTrazer) return;

    const catHeader = e.target.closest('.category-header');
    if (!catHeader) return;

    const opGrupo = catHeader.dataset.opGrupo || '';  // label exibido
    const opRaw   = catHeader.dataset.opRaw || null;   // valor no banco (null = SEM OPERAÇÃO)

    if (btnTrazer) {
      // Modo trazer: mostra checkboxes em todos os outros grupos
      _entrarModoTrazer(opGrupo, opRaw);
      return;
    }

    // Spinner: troca ícone do botão clicado por animação de loading
    const btnClicado = btnMover || btnRename;
    const svgOriginal = btnClicado.innerHTML;
    btnClicado.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" style="animation:_spin .7s linear infinite;display:block"><circle cx="12" cy="12" r="9" stroke-opacity=".25"/><path d="M12 3a9 9 0 0 1 9 9"/></svg>';
    btnClicado.disabled = true;

    const ops = await _fetchOps();

    // Restaura o botão
    btnClicado.innerHTML = svgOriginal;
    btnClicado.disabled = false;

    // Remove a operação atual da lista de opções (não faz sentido mover para si mesmo)
    const opcoesFiltradas = ops.filter(o => o !== (opRaw || ''));

    if (btnMover) {
      // Abre dropdown → ao selecionar entra em modo seleção
      _mostrarDropdownOp(btnMover, opcoesFiltradas, (opSelecionada) => {
        _entrarModoSelecao(opGrupo, opSelecionada);
      });

    } else if (btnRename) {
      // Abre dropdown → ao selecionar renomeia todos os itens do grupo
      _mostrarDropdownOp(btnRename, opcoesFiltradas, async (opSelecionada) => {
        const qtd = _getItensDoGrupo(opGrupo).length;
        const confirmar = await _fichaModal({
          titulo: 'Renomear operação',
          tipo: 'confirmar',
          html: `<p>Deseja mover <strong>todos os ${qtd} item(ns)</strong> de <em>${esc(opGrupo)}</em> para <strong>${esc(opSelecionada)}</strong>?</p>`,
          botoes: [
            { texto: 'Confirmar', valor: 'ok', cor: '#16a34a' },
            { texto: 'Cancelar', valor: 'cancel', cor: '#6b7280' }
          ]
        });
        if (confirmar !== 'ok') return;

        const opAtualParaAPI = (opGrupo === 'SEM OPERAÇÃO') ? null : opGrupo;

        const btnR = btnRename;
        const svgR = btnR.innerHTML;
        btnR.innerHTML = '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" style="animation:_spin .7s linear infinite;display:block"><circle cx="12" cy="12" r="9" stroke-opacity=".25"/><path d="M12 3a9 9 0 0 1 9 9"/></svg>';
        btnR.disabled = true;

        try {
          const resp = await fetch('/api/pcp/estrutura/renomear-grupo', {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ pai_codigo: paiCodigo, operacao_atual: opAtualParaAPI, nova_operacao: opSelecionada })
          });
          const j = await resp.json();
          if (j.ok) {
            window.loadEstruturaProduto(paiCodigo);
          } else {
            btnR.innerHTML = svgR; btnR.disabled = false;
            await _fichaModal({ titulo: 'Erro', tipo: 'erro', html: `<p>${esc(j.error || 'Erro ao renomear.')}</p>` });
          }
        } catch (err) {
          btnR.innerHTML = svgR; btnR.disabled = false;
          await _fichaModal({ titulo: 'Erro', tipo: 'erro', html: `<p>${esc(err.message)}</p>` });
        }
      });
    }
  }, { signal: ul._opGroupAbort?.signal });
}

// ─────────────────────────────────────────────────────────────────────────────
// Estrutura de produto (render por grupos de Operação)
// - Busca a estrutura via API (/api/pcp/estrutura)
// - Agrupa por comp_operacao e renderiza blocos (categoria) com contador
// - A COLUNA "Operação" foi REMOVIDA da grade (fica só no título do grupo)
// - Atualiza "Estrutura de produto (x)" só dentro de #estruturaProduto (sem varrer a página)
// ─────────────────────────────────────────────────────────────────────────────
window.loadEstruturaProduto = async function loadEstruturaProduto(codigo) {
  const ul = document.querySelector('#estruturaProduto #malha');
  if (!ul) return;

  const cod = (codigo || window.codigoSelecionado || '').trim();
  let metaForPreselect = null;

  const esc = s => String(s ?? '')
    .replace(/&/g,'&amp;').replace(/</g,'&lt;')
    .replace(/>/g,'&gt;').replace(/"/g,'&quot;');

  // Atualiza o contador "Estrutura de produto (x)" SOMENTE dentro de #estruturaProduto
  const setEstruturaCount = (n) => {
    const root = document.getElementById('estruturaProduto') || document.querySelector('#estruturaProduto');
    if (!root) return;

    // 1) Elemento dedicado (se existir)
    const badge = root.querySelector('[data-estrutura-count], #estruturaCount, .estrutura-count');
    if (badge) { badge.textContent = String(n); return; }

    // 2) Algum heading DENTRO da seção com o texto "Estrutura de produto"
    const heads = root.querySelectorAll('h1,h2,h3,.section-title,.titulo,.header-title');
    for (const el of heads) {
      const txt = (el.textContent || '').trim();
      if (!/estrutura de produto/i.test(txt)) continue;

      if (/\(\s*\d+\s*\)$/.test(txt)) {
        const base = txt.replace(/\s*\(\s*\d+\s*\)\s*$/, '');
        el.textContent = `${base} (${n})`;
      } else {
        const span = document.createElement('span');
        span.className = 'estrutura-count';
        span.style.marginLeft = '6px';
        span.textContent = `(${n})`;
        el.appendChild(span);
      }
      return;
    }

    // 3) Sem fallback fora da seção para não destruir a página
    console.debug('[Estrutura][count] Sem alvo dedicado para mostrar o número.');
  };

  // header inicial (SEM coluna "Operação")
  ul.innerHTML = `
  <li class="header-row">
    <div>Código</div><div>Descrição</div><div>QTD</div>
    <div>Unidade</div><div>Custo real</div><div>Ações</div>
  </li>
    <li><div style="opacity:.7">${cod ? `Carregando estrutura de ${esc(cod)}…` : 'Selecione um produto.'}</div></li>
  `;
  if (!cod) { setEstruturaCount(0); return; }

  // Atualiza badges de versão/modificador após exibir placeholder
  if (typeof pcpUpdateVersaoBadges === 'function') {
    try {
      const meta = await pcpFetchEstruturaMetaByCod(cod);
      metaForPreselect = meta;
      pcpUpdateVersaoBadges(meta);
    } catch (metaErr) {
      console.warn('[Estrutura] Não foi possível carregar meta (versão/modificador):', metaErr);
      pcpUpdateVersaoBadges(null);
    }
  }

  // Preenche o listbox "Local de produção." com operações do SQL (public.omie_operacao)
  try { await ensureLocalProducaoSelectOptions(); } catch (e) { console.warn('[Estrutura] Falha ao carregar locais de produção:', e); }

  // Pré-seleciona o valor salvo (se existir)
  try {
    const sel = document.getElementById('estruturaLocalProducao');
    if (sel) {
      let saved = metaForPreselect?.local_producao || null;
      if (!saved) {
        // fallback: buscar meta de novo (caso badge tenha sido pulado)
        try {
          const meta = await pcpFetchEstruturaMetaByCod(cod);
          saved = meta?.local_producao || null;
        } catch {}
      }
      if (saved) {
        // tenta seleção por label exata
        const opt = Array.from(sel.options).find(o => (o.value || '').trim() === String(saved).trim());
        if (opt) sel.value = opt.value;
      }
    }
  } catch (e) {
    console.warn('[Estrutura] Pré-seleção de Local de produção falhou:', e);
  }

  const norm = (s) => (s ?? '').toString().trim();
  const labelOper = (s) => (norm(s) || 'SEM OPERAÇÃO');

  try {
    // busca a estrutura (API já devolve comp_operacao)
    const r = await fetch('/api/pcp/estrutura?pai_codigo=' + encodeURIComponent(cod), {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: '{}'
    });
    const j = await r.json();
    const dados = Array.isArray(j?.dados) ? j.dados : [];

    const frag = document.createDocumentFragment();

    // cabeçalho fixo (SEM "Operação")
    const head = document.createElement('li');
    head.className = 'header-row';
    head.innerHTML = `
      <div>Código</div><div>Descrição</div><div>QTD</div>
      <div>Unidade</div><div>Custo real</div><div>Ações</div>`;
    frag.appendChild(head);

    if (!dados.length) {
      const li = document.createElement('li');
      li.innerHTML = `<div style="opacity:.7">Estrutura de produto (${esc(cod)}) vazia.</div>`;
      frag.appendChild(li);
      setEstruturaCount(0);
    } else {
      // — agrupa por Operação —
      const grupos = new Map();
      for (const r of dados) {
        const key = labelOper(r.comp_operacao);
        if (!grupos.has(key)) grupos.set(key, []);
        grupos.get(key).push(r);
      }

      // — ordena grupos: BASE e HIGIENIZAÇÃO primeiro; SEM OPERAÇÃO por último; resto alfabético —
      const prio = new Map([['BASE', -2], ['HIGIENIZAÇÃO', -1], ['HIGIENIZACAO', -1], ['SEM OPERAÇÃO', 999]]);
      const opsOrdenadas = Array.from(grupos.keys()).sort((a,b) => {
        const pa = prio.get(a.toUpperCase()) ?? 0;
        const pb = prio.get(b.toUpperCase()) ?? 0;
        if (pa !== pb) return pa - pb;
        return a.localeCompare(b, 'pt-BR');
      });

      // — render: cabeçalho de grupo + linhas (6 colunas) —
      for (const opNome of opsOrdenadas) {
        const arr = grupos.get(opNome);
        // opRaw: null para "SEM OPERAÇÃO", senão o nome real
        const opRaw = (opNome === 'SEM OPERAÇÃO') ? null : opNome;

        // cabeçalho do grupo
        const cat = document.createElement('li');
        cat.className = 'category-header';
        cat.dataset.opGrupo = opNome;        // label exibido (ex: "BASE")
        cat.dataset.opRaw   = opRaw ?? '';   // valor real no banco (vazio = null)
        cat.innerHTML = `
          <div class="cat-header-top">
            <div class="left">
              ${esc(opNome)} <span class="badge">(${arr.length})</span>
            </div>
            <div class="right cat-op-actions">
              <button type="button" class="cat-btn cat-btn-rename" title="Renomear esta operação" aria-label="Renomear">
                <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
                  <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/>
                  <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/>
                </svg>
              </button>
              <button type="button" class="cat-btn cat-btn-mover" title="Mover itens para outra operação" aria-label="Mover itens">
                <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" aria-hidden="true">
                  <line x1="12" y1="4" x2="12" y2="20"/><line x1="4" y1="12" x2="20" y2="12"/>
                </svg>
              </button>
              <button type="button" class="cat-btn cat-btn-trazer" title="Trazer itens de outros grupos para cá" aria-label="Trazer itens">
                <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
                  <polyline points="11 17 6 12 11 7"/><line x1="6" y1="12" x2="18" y2="12"/>
                </svg>
              </button>
            </div>
          </div>
        `;
        frag.appendChild(cat);

        // linhas do grupo
        for (const row of arr) {
          const li = document.createElement('li');
          li.dataset.comp    = row.comp_codigo || '';
          li.dataset.opGrupo = opNome; // facilita seleção por grupo
          li.innerHTML = `
            <div class="col-codigo">
              <input type="checkbox" class="item-chk" style="display:none;margin-right:5px;width:14px;height:14px;cursor:pointer;accent-color:#4ade80;vertical-align:middle;" aria-label="Selecionar item">
              <span class="col-codigo-text">${esc(row.comp_codigo || '')}</span>
            </div>
            <div class="desc" title="${esc(row.comp_descricao || '')}">${esc(row.comp_descricao || '')}</div>
            <div>${Number(row.comp_qtd || 0)}</div>
            <div>${esc(row.comp_unid || '')}</div>
            <div>—</div>
            <div class="acoes">
              <!-- Trocar -->
              <button type="button" class="icon-btn" data-action="trocar" title="Trocar" aria-label="Trocar">
                <svg viewBox="0 0 24 24" width="16" height="16"><path d="M7 7h10"></path><path d="M14 4l3 3-3 3"></path><path d="M17 17H7"></path><path d="M10 20l-3-3 3-3"></path></svg>
              </button>
              <!-- Abrir -->
              <button type="button" class="icon-btn" data-action="abrir" title="Abrir" aria-label="Abrir">
                <svg viewBox="0 0 24 24" width="16" height="16"><path d="M21 3L10 14"></path><path d="M5 7v12h12"></path></svg>
              </button>
              <!-- Estrutura -->
              <button type="button" class="icon-btn" data-action="estrutura" title="Estrutura" aria-label="Estrutura">
                <svg viewBox="0 0 24 24" width="16" height="16">
                  <circle cx="6"  cy="6"  r="2"></circle>
                  <circle cx="18" cy="6"  r="2"></circle>
                  <circle cx="18" cy="12" r="2"></circle>
                  <circle cx="18" cy="18" r="2"></circle>
                  <path d="M8 6h8"></path><path d="M8 6v12"></path>
                  <path d="M14 12h4"></path><path d="M14 18h4"></path>
                </svg>
              </button>
            </div>`;
          frag.appendChild(li);
        }
      }

      // total de itens (todas as linhas)
      setEstruturaCount(dados.length);
    }

    ul.replaceChildren(frag);

    // ── Lógica dos botões de operação nos category-headers ──
    _wireOpGroupButtons(ul, cod);

    // mantém delegações existentes e marca ícones "Estrutura" quando houver filhos
    ensureEstruturaDelegation();
    await markEstruturaButtons(ul);

  } catch (e) {
    console.error('[loadEstruturaProduto]', e);
    ul.innerHTML = `
      <li class="header-row">
        <div>Código</div><div>Descrição</div><div>QTD</div>
        <div>Unidade</div><div>Custo real</div><div>Ações</div>
      </li>
      <li><div style="color:#ef4444">Falha ao carregar estrutura.</div></li>`;
    setEstruturaCount(0);
  }
};




