let agendaMesReferencia = new Date();
let agendaDataSelecionada = null;
let agendaTipoReservaSelecionado = null;
let agendaUsuariosAtivosCache = [];
let agendaParticipantesDisponiveis = [];
let agendaParticipantesSelecionadosLista = [];
let agendaParticipantesOriginaisReserva = []; // cópia dos participantes ao abrir a reserva
let agendaReservasPorDia = {};
let agendaLembretesPorDia = {};
let agendaMostrarSomenteMinhas = false;
let agendaFiltroUsuarioSelecionado = '';   // username para filtro sidebar
let agendaAnexoPendente = null;            // { file, nome } antes do upload
let agendaAnexoUrlAtual = null;            // URL já salva na reserva
let agendaAnexoNomeAtual = null;
let agendaReservaIdParaAta = null;         // reserva_id ao abrir modal de ata
let agendaLembreteDestinatariosDisponiveis = [];
let agendaLembreteDestinatariosSelecionados = [];
let agendaLembreteVisualizandoId = null;
let agendaLembreteVisualizandoCriadoPor = null;
let agendaReservaEditandoId = null;
let agendaReservaEditandoData = null;
let agendaReservaEditandoRepetir = false;
let agendaPodeEditarAtual = true;
let agendaUiInicializada = false;
let agendaProcessandoContador = 0;
let agendaObserverUsuarioInicializado = false;
// Destinatários do lembrete no modal unificado
let agendaUnifLembreteDestinDisponiveis = [];
let agendaUnifLembreteDestinSelecionados = [];
let agendaGoogleCalendarStatus = {
  configured: false,
  connected: false,
  email: null,
  carregado: false
};

function obterNomeUsuarioHeaderAgenda() {
  return String(document.getElementById('userNameDisplay')?.textContent || '').trim();
}

function nomeUsuarioValidoAgenda(nome) {
  const valor = String(nome || '').trim();
  if (!valor) return false;
  const normalizado = valor.toLowerCase();
  if (['usuário', 'usuario', 'user', '-', '—', '--', '...'].includes(normalizado)) return false;
  if (!/[a-z0-9]/i.test(valor)) return false;
  return true;
}

function agendaSetProcessando(ativo) {
  const overlay = document.getElementById('agendaProcessingOverlay');
  if (!overlay) return;

  if (ativo) {
    agendaProcessandoContador += 1;
  } else {
    agendaProcessandoContador = Math.max(0, agendaProcessandoContador - 1);
  }

  overlay.style.display = agendaProcessandoContador > 0 ? 'flex' : 'none';
}

function formatarDataIso(dateObj) {
  if (!(dateObj instanceof Date)) return '';
  const ano = dateObj.getFullYear();
  const mes = String(dateObj.getMonth() + 1).padStart(2, '0');
  const dia = String(dateObj.getDate()).padStart(2, '0');
  return `${ano}-${mes}-${dia}`;
}

function formatarDataExibicaoPtBr(dataIso) {
  if (!dataIso) return '-';
  const data = new Date(`${dataIso}T00:00:00`);
  if (Number.isNaN(data.getTime())) return dataIso;
  return data.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric' });
}

function montarTituloAgendaMensal(dateRef) {
  try {
    return dateRef.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })
      .replace(/(^\w)/, (match) => match.toUpperCase());
  } catch (_err) {
    return '-';
  }
}

function obterUsuarioLogadoAgenda() {
  const nomeTela = (document.getElementById('userNameDisplay')?.textContent || '').trim();
  const nomeSessao = String(window.__sessionUser?.username || '').trim();
  return nomeTela || nomeSessao;
}

function atualizarUiGoogleCalendarAgenda() {
  const statusEl = document.getElementById('agendaGoogleCalendarStatus');
  const checkbox = document.getElementById('agendaGoogleCalendarCheckbox');

  if (!statusEl || !checkbox) return;

  if (!agendaGoogleCalendarStatus.carregado) {
    statusEl.textContent = 'Verificando conexão com Google...';
    checkbox.disabled = true;
    return;
  }

  if (!agendaGoogleCalendarStatus.configured) {
    statusEl.textContent = 'Integração Google não configurada no servidor.';
    checkbox.checked = false;
    checkbox.disabled = true;
    return;
  }

  checkbox.disabled = false;
  if (agendaGoogleCalendarStatus.connected) {
    statusEl.textContent = agendaGoogleCalendarStatus.email
      ? `Conectado como ${agendaGoogleCalendarStatus.email}`
      : 'Conta Google conectada.';
    return;
  }

  statusEl.textContent = 'Conta Google não conectada. Faça a conexão no Perfil.';
}

async function carregarStatusGoogleCalendarAgenda(force = false) {
  if (agendaGoogleCalendarStatus.carregado && !force) {
    atualizarUiGoogleCalendarAgenda();
    return agendaGoogleCalendarStatus;
  }

  try {
    const resp = await fetch('/api/google-calendar/status', { credentials: 'include' });
    if (!resp.ok) {
      throw new Error(`Falha ao consultar Google Calendar (${resp.status})`);
    }
    const payload = await resp.json();
    agendaGoogleCalendarStatus = {
      configured: payload?.configured !== false,
      connected: !!payload?.connected,
      email: payload?.email || null,
      carregado: true
    };
  } catch (err) {
    console.warn('[AGENDA] Não foi possível consultar status do Google Calendar:', err);
    agendaGoogleCalendarStatus = {
      configured: false,
      connected: false,
      email: null,
      carregado: false
    };
  }

  atualizarUiGoogleCalendarAgenda();
  return agendaGoogleCalendarStatus;
}

function iniciarConexaoGoogleCalendarAgenda() {
  const returnTo = window.location.pathname + window.location.search + window.location.hash;
  window.location.href = `/api/google-calendar/connect?returnTo=${encodeURIComponent(returnTo)}`;
}

async function desconectarGoogleCalendarAgenda() {
  if (!confirm('Deseja desconectar a conta Google deste usuário?')) return;

  try {
    const resp = await fetch('/api/google-calendar/disconnect', {
      method: 'POST',
      credentials: 'include'
    });
    if (!resp.ok) {
      const payload = await resp.json().catch(() => ({}));
      throw new Error(payload?.error || `Erro ao desconectar (${resp.status})`);
    }

    agendaGoogleCalendarStatus = {
      configured: true,
      connected: false,
      email: null,
      carregado: true
    };

    const googleCheckbox = document.getElementById('agendaGoogleCalendarCheckbox');
    if (googleCheckbox) googleCheckbox.checked = false;
    atualizarUiGoogleCalendarAgenda();
    alert('Conta Google desconectada com sucesso.');
  } catch (err) {
    alert(`Não foi possível desconectar a conta Google: ${err.message}`);
  }
}

function tratarRetornoConexaoGoogleCalendarAgenda() {
  try {
    const url = new URL(window.location.href);
    if (!url.searchParams.has('google_calendar_connected')) return;
    const conectado = url.searchParams.get('google_calendar_connected') === '1';
    alert(conectado
      ? 'Google Agenda conectado com sucesso.'
      : 'Não foi possível concluir a conexão com o Google Agenda.');

    url.searchParams.delete('google_calendar_connected');
    const novo = `${url.pathname}${url.search}${url.hash}`;
    window.history.replaceState({}, document.title, novo);
    carregarStatusGoogleCalendarAgenda(true).catch(() => {});
  } catch (_err) {
    // ignora
  }
}

function usuarioAutenticadoAgenda() {
  const nomeTela = obterNomeUsuarioHeaderAgenda();
  return nomeUsuarioValidoAgenda(nomeTela);
}

function gerarIdReservaAgenda() {
  return `res_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

async function carregarReservasMesAgenda() {
  const ano = agendaMesReferencia.getFullYear();
  const mes = agendaMesReferencia.getMonth() + 1;
  const resp = await fetch(`/api/rh/reservas?ano=${ano}&mes=${mes}`, { credentials: 'include' });
  if (!resp.ok) {
    throw new Error(`Falha ao carregar reservas (${resp.status})`);
  }
  const data = await resp.json();
  const reservas = Array.isArray(data?.reservas) ? data.reservas : [];

  agendaReservasPorDia = {};
  reservas.forEach((reserva) => {
    const dataIso = String(reserva?.data || '').slice(0, 10);
    if (!dataIso) return;
    if (!Array.isArray(agendaReservasPorDia[dataIso])) agendaReservasPorDia[dataIso] = [];
    agendaReservasPorDia[dataIso].push({
      id: reserva.id,
      criadoPor: reserva.criadoPor,
      tipo: reserva.tipo,
      inicio: reserva.inicio,
      fim: reserva.fim,
      tema: reserva.tema,
      cafe: !!reserva.cafe,
      googleAgendado: !!reserva.googleAgendado,
      googleEventId: reserva.googleEventId || null,
      googleEventLink: reserva.googleEventLink || null,
      podeEditar: reserva.podeEditar === true,
      participantes: Array.isArray(reserva.participantes) ? reserva.participantes : [],
      repetir: !!reserva.repetir,
      repetirTodosMeses: !!reserva.repetirTodosMeses,
      diasSemana: Array.isArray(reserva.diasSemana) ? reserva.diasSemana : [],
      realizada: !!reserva.realizada
    });
  });
}

async function carregarLembretesMesAgenda() {
  const ano = agendaMesReferencia.getFullYear();
  const mes = agendaMesReferencia.getMonth() + 1;
  const usuarioHeader = obterNomeUsuarioHeaderAgenda();
  if (!nomeUsuarioValidoAgenda(usuarioHeader)) {
    agendaLembretesPorDia = {};
    return;
  }
  const usuarioHint = encodeURIComponent(usuarioHeader);
  const resp = await fetch(`/api/rh/lembretes?ano=${ano}&mes=${mes}&user=${usuarioHint}`, { credentials: 'include' });
  if (!resp.ok) {
    throw new Error(`Falha ao carregar lembretes (${resp.status})`);
  }
  const data = await resp.json();
  const lembretes = Array.isArray(data?.lembretes) ? data.lembretes : [];

  agendaLembretesPorDia = {};
  lembretes.forEach((lembrete) => {
    const dataIso = String(lembrete?.data || '').slice(0, 10);
    if (!dataIso) return;
    if (!Array.isArray(agendaLembretesPorDia[dataIso])) agendaLembretesPorDia[dataIso] = [];
    agendaLembretesPorDia[dataIso].push({
      id: lembrete.id,
      texto: String(lembrete.texto || ''),
      criadoPor: String(lembrete.criadoPor || ''),
      destinatarios: Array.isArray(lembrete.destinatarios) ? lembrete.destinatarios : []
    });
  });
}

function iniciarObserverUsuarioAgenda() {
  if (agendaObserverUsuarioInicializado) return;

  const elUsuario = document.getElementById('userNameDisplay');
  if (!elUsuario) return;
  agendaObserverUsuarioInicializado = true;

  let ultimoNome = obterNomeUsuarioHeaderAgenda();
  const observer = new MutationObserver(async () => {
    const nomeAtual = obterNomeUsuarioHeaderAgenda();
    if (!nomeUsuarioValidoAgenda(nomeAtual) || nomeAtual === ultimoNome || !agendaUiInicializada) return;
    ultimoNome = nomeAtual;
    agendaSetProcessando(true);
    try {
      await carregarAgendaMesCompleto();
      renderAgendaCalendarioMensal();
    } catch (err) {
      console.error('[AGENDA] Falha ao recarregar após identificar usuário:', err);
    } finally {
      agendaSetProcessando(false);
    }
  });

  observer.observe(elUsuario, { childList: true, characterData: true, subtree: true });
}

async function carregarAgendaMesCompleto() {
  await Promise.all([
    carregarReservasMesAgenda(),
    carregarLembretesMesAgenda()
  ]);
}

function isConflitoHorarioAgenda(inicioA, fimA, inicioB, fimB) {
  return inicioA < fimB && fimA > inicioB;
}

function buscarConflitoReservaAgenda({ dataIso, tipoReservaTexto, horarioInicio, horarioFim, ignorarReservaId = null }) {
  const reservasDia = Array.isArray(agendaReservasPorDia[dataIso]) ? agendaReservasPorDia[dataIso] : [];
  return reservasDia.find((reserva) => {
    if (!reserva || typeof reserva !== 'object') return false;
    if (ignorarReservaId && String(reserva.id) === String(ignorarReservaId)) return false;
    if (String(reserva.tipo || '') !== String(tipoReservaTexto || '')) return false;
    const ini = String(reserva.inicio || '').trim();
    const fim = String(reserva.fim || '').trim();
    if (!ini || !fim) return false;
    return isConflitoHorarioAgenda(horarioInicio, horarioFim, ini, fim);
  }) || null;
}

function atualizarPermissaoEdicaoAgenda(podeEditar) {
  agendaPodeEditarAtual = !!podeEditar;

  const temaInput = document.getElementById('agendaTemaReuniao');
  const repetirSelect = document.getElementById('agendaRepetirReuniao');
  const inicioInput = document.getElementById('agendaHorarioInicio');
  const duracaoSelect = document.getElementById('agendaDuracaoHoras');
  const participantesSelect = document.getElementById('agendaParticipantesSelect');
  const cafeCheckbox = document.getElementById('agendaCafeCheckbox');
  const btnSalvar = document.getElementById('agendaSalvarReserva');
  const semanaChecks = document.querySelectorAll('#agendaSemanaRepeticao input[type="checkbox"]');

  if (temaInput) temaInput.disabled = !agendaPodeEditarAtual;
  if (repetirSelect) repetirSelect.disabled = !agendaPodeEditarAtual;
  if (inicioInput) inicioInput.disabled = !agendaPodeEditarAtual;
  if (duracaoSelect) duracaoSelect.disabled = !agendaPodeEditarAtual;
  if (participantesSelect) participantesSelect.disabled = !agendaPodeEditarAtual;
  if (cafeCheckbox) cafeCheckbox.disabled = !agendaPodeEditarAtual;
  semanaChecks.forEach((checkbox) => { checkbox.disabled = !agendaPodeEditarAtual; });

  if (btnSalvar) {
    if (agendaPodeEditarAtual) {
      btnSalvar.style.display = '';
      btnSalvar.disabled = false;
      btnSalvar.textContent = agendaReservaEditandoId ? 'Salvar alteração' : 'Reservar';
    } else {
      btnSalvar.style.display = 'none';
    }
  }

  // Botão Excluir: visível somente quando é uma edição e o usuário pode editar
  const btnExcluir = document.getElementById('agendaExcluirReserva');
  if (btnExcluir) {
    btnExcluir.style.display = (agendaPodeEditarAtual && agendaReservaEditandoId) ? '' : 'none';
  }
}

function renderAgendaCalendarioMensal() {
  const grid = document.getElementById('agendaCalendarioGrid');
  const titulo = document.getElementById('agendaMesTitulo');
  if (!grid) return;
  const isMobileView = window.matchMedia('(max-width: 640px)').matches;

  const dataRef = new Date(agendaMesReferencia.getFullYear(), agendaMesReferencia.getMonth(), 1);
  const hoje = new Date();
  hoje.setHours(0, 0, 0, 0);
  const usuarioLogado = obterUsuarioLogadoAgenda().toLowerCase();

  if (titulo) {
    titulo.textContent = montarTituloAgendaMensal(dataRef);
  }

  const primeiroDiaSemana = new Date(dataRef.getFullYear(), dataRef.getMonth(), 1).getDay();
  const totalDiasMes = new Date(dataRef.getFullYear(), dataRef.getMonth() + 1, 0).getDate();
  const diasMesAnterior = new Date(dataRef.getFullYear(), dataRef.getMonth(), 0).getDate();
  const diaInicialCalendario = primeiroDiaSemana;
  const totalSlots = Math.ceil((diaInicialCalendario + totalDiasMes) / 7) * 7;
  const hojeDiaSemana = hoje.getDay();
  const inicioSemanaAtual = new Date(hoje);
  inicioSemanaAtual.setDate(hoje.getDate() - hojeDiaSemana);
  const fimSemanaAtual = new Date(inicioSemanaAtual);
  fimSemanaAtual.setDate(inicioSemanaAtual.getDate() + 6);

  const nomesDia = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
  const htmlCabecalho = nomesDia
    .map((nomeDia) => `<div class="agenda-cal-head">${nomeDia}</div>`)
    .join('');

  let htmlDias = '';
  for (let indice = 0; indice < totalSlots; indice++) {
    let dataCelula;
    let diaExibicao;
    let foraDoMes = false;

    if (indice < diaInicialCalendario) {
      const diaPrev = diasMesAnterior - (diaInicialCalendario - indice - 1);
      dataCelula = new Date(dataRef.getFullYear(), dataRef.getMonth() - 1, diaPrev);
      diaExibicao = diaPrev;
      foraDoMes = true;
    } else if (indice >= (diaInicialCalendario + totalDiasMes)) {
      const diaNext = indice - (diaInicialCalendario + totalDiasMes) + 1;
      dataCelula = new Date(dataRef.getFullYear(), dataRef.getMonth() + 1, diaNext);
      diaExibicao = diaNext;
      foraDoMes = true;
    } else {
      const diaAtual = indice - diaInicialCalendario + 1;
      dataCelula = new Date(dataRef.getFullYear(), dataRef.getMonth(), diaAtual);
      diaExibicao = diaAtual;
    }

    const dataIso = formatarDataIso(dataCelula);
    if (isMobileView && (dataCelula < inicioSemanaAtual || dataCelula > fimSemanaAtual)) {
      continue;
    }
    const isHoje = formatarDataIso(dataCelula) === formatarDataIso(hoje);
    const classes = ['agenda-cal-day'];
    if (foraDoMes) classes.push('is-out');
    if (isHoje) classes.push('is-today');

    // Hora atual no formato "HH:MM" para comparar com hora_fim no dia de hoje
    const agoraHHMM = `${String(hoje.getHours()).padStart(2, '0')}:${String(hoje.getMinutes()).padStart(2, '0')}`;
    const isDiaPast = dataCelula < hoje; // dias anteriores ao dia de hoje

    const reservasDiaRaw = Array.isArray(agendaReservasPorDia[dataIso]) ? agendaReservasPorDia[dataIso] : [];
    const reservasDia = agendaMostrarSomenteMinhas
      ? reservasDiaRaw.filter((reserva) => {
          const participantesReserva = Array.isArray(reserva?.participantes)
            ? reserva.participantes.map((nome) => String(nome || '').trim().toLowerCase()).filter(Boolean)
            : [];
          const criador = String(reserva?.criadoPor || '').trim().toLowerCase();
          return (Boolean(usuarioLogado) && participantesReserva.includes(usuarioLogado)) || (Boolean(usuarioLogado) && criador === usuarioLogado);
        })
      : reservasDiaRaw.filter((reserva) => {
          if (!agendaFiltroUsuarioSelecionado) return true;
          const filtroNorm = agendaFiltroUsuarioSelecionado.toLowerCase();
          const partic = Array.isArray(reserva?.participantes)
            ? reserva.participantes.map((u) => String(u || '').toLowerCase())
            : [];
          const criador = String(reserva?.criadoPor || '').toLowerCase();
          return partic.includes(filtroNorm) || criador === filtroNorm;
        });

    const lembretesDia = Array.isArray(agendaLembretesPorDia[dataIso]) ? agendaLembretesPorDia[dataIso] : [];

    // Determina se uma reserva "já passou": dia anterior OU (hoje E hora_fim <= agora)
    const reservaJaPassou = (reserva) => {
      if (isDiaPast) return true;
      if (isHoje) return String(reserva?.fim || '').slice(0, 5) <= agoraHHMM;
      return false;
    };

    const MAX_CHIPS = 4;
    const MAX_LEMBRETES = 2;

    // Helper: ícone + classe de cor por tipo
    const infoTipo = (tipoNorm) => {
      if (tipoNorm.includes('audit'))  return { cls: 'is-auditorio', icon: 'fa-chalkboard-user',  title: 'Auditório' };
      if (tipoNorm.includes('online')) return { cls: 'is-online',    icon: 'fa-laptop',            title: 'Reunião online' };
      if (tipoNorm === 'visita')       return { cls: 'is-visita',     icon: 'fa-building',          title: 'Visita' };
      if (tipoNorm === 'evento')       return { cls: 'is-evento',     icon: 'fa-champagne-glasses', title: 'Evento' };
      return                                  { cls: 'is-sala',       icon: 'fa-handshake',         title: 'Sala de reunião' };
    };

    // Chips de reservas
    const chipsReservas = reservasDia.slice(0, MAX_CHIPS).map((reserva) => {
      const tipoNorm = String(reserva?.tipo || '').toLowerCase();
      const { cls, icon, title } = infoTipo(tipoNorm);
      const tituloChip = escapeHtml(`${reserva.tipo} ${reserva.inicio}–${reserva.fim}`);
      const idAttr = `data-agenda-reserva-id="${escapeHtml(String(reserva.id || ''))}" data-agenda-reserva-date="${escapeHtml(dataIso)}"`;

      const participantesReserva = Array.isArray(reserva?.participantes)
        ? reserva.participantes.map((nome) => String(nome || '').trim().toLowerCase()).filter(Boolean)
        : [];
      const horaInicio = String(reserva?.inicio || '').slice(0, 5);
      const usuarioConvocado = Boolean(usuarioLogado) && participantesReserva.includes(usuarioLogado);
      const convocadoHtml = usuarioConvocado
        ? '<i class="fa-solid fa-calendar-check agenda-chip-convocado-icon" title="Você está convocado"></i>'
        : '';

      if (isMobileView) {
        const clsMobile = reservaJaPassou(reserva)
          ? `agenda-cal-reserva-item ${cls} is-mobile-min is-mobile-stack is-past-chip${!reserva.realizada ? ' is-nao-realizada' : ''}`
          : `agenda-cal-reserva-item ${cls} is-mobile-min is-mobile-stack`;
        return `<div class="${clsMobile}" ${idAttr} title="${tituloChip}">
          ${horaInicio ? `<span class="agenda-chip-hora">${escapeHtml(horaInicio)}</span>` : ''}
          ${convocadoHtml}
        </div>`;
      }

      if (reservaJaPassou(reserva)) {
        if (reserva.realizada) {
          // Realizada: só ícone, cor normal, sem opacidade
          return `<div class="agenda-cal-reserva-item ${cls} is-past-chip" style="opacity:1;" ${idAttr} title="${tituloChip}">
            <i class="fa-solid ${icon} agenda-chip-room-icon" title="${title}"></i>
          </div>`;
        }
        // Não realizada: ícone vermelho
        return `<div class="agenda-cal-reserva-item ${cls} is-past-chip is-nao-realizada" ${idAttr} title="${tituloChip}">
          <i class="fa-solid ${icon} agenda-chip-room-icon"></i>
        </div>`;
      }

      // Ainda ativa: chip completo
      const horaFim = String(reserva?.fim || '').slice(0, 5);
      const horaFaixa = (horaInicio && horaFim)
        ? `${horaInicio}-${horaFim}`
        : (horaInicio || horaFim || '');
      const cafeHtml      = reserva?.cafe      ? '<i class="fa-solid fa-mug-hot agenda-chip-cafe-icon" title="Com café"></i>' : '';
      return `<div class="agenda-cal-reserva-item ${cls}" ${idAttr} title="${tituloChip}">
          <i class="fa-solid ${icon} agenda-chip-room-icon" title="${title}"></i>
          ${horaFaixa ? `<span class="agenda-chip-hora agenda-chip-hora-desktop">${escapeHtml(horaFaixa)}</span>` : ''}
          ${horaInicio ? `<span class="agenda-chip-hora agenda-chip-hora-mobile">${escapeHtml(horaInicio)}</span>` : ''}
          ${cafeHtml}${convocadoHtml}
        </div>`;
    }).filter(Boolean);

    // Chips de lembretes
    const chipsLembretes = isMobileView ? [] : lembretesDia.slice(0, MAX_LEMBRETES).map((lembrete) => `
      <div class="agenda-cal-reserva-item is-lembrete"
           data-agenda-lembrete-id="${escapeHtml(String(lembrete.id || ''))}"
           data-agenda-lembrete-date="${escapeHtml(dataIso)}"
           title="${escapeHtml(lembrete.texto || 'Lembrete')}">
        <i class="fa-solid fa-note-sticky agenda-chip-room-icon"></i>
        <span class="agenda-chip-hora lembrete-texto">${escapeHtml((lembrete.texto || 'Lembrete').slice(0, 14))}</span>
      </div>
    `);

    const totalExtras = Math.max(0, reservasDia.length - MAX_CHIPS) + Math.max(0, lembretesDia.length - MAX_LEMBRETES);

    // Separa chips: ativos (futuro + realizados que passaram = chip completo) e ícones-passados (não realizados)
    const chipsPassados = chipsReservas.filter((_, i) => reservaJaPassou(reservasDia[i]) && !reservasDia[i].realizada);
    const chipsAtivos   = chipsReservas.filter((_, i) => !reservaJaPassou(reservasDia[i]) || reservasDia[i].realizada);

    const reservasHtml = (chipsReservas.length > 0 || chipsLembretes.length > 0)
      ? `
        <div class="agenda-cal-reservas">
          ${chipsAtivos.join('')}
          ${chipsLembretes.join('')}
          ${totalExtras > 0 ? `<div class="agenda-cal-meta">+${totalExtras}</div>` : ''}
          ${chipsPassados.length > 0 ? `<div class="agenda-cal-past-row">${chipsPassados.join('')}</div>` : ''}
        </div>
      `
      : (isMobileView ? '' : '<div class="agenda-cal-meta">Clique para reservar</div>');

    const lembretesHtml = '';

    htmlDias += `
      <button type="button" class="${classes.join(' ')}" data-agenda-date="${dataIso}">
        <div class="agenda-cal-num">${diaExibicao}</div>
        ${reservasHtml}
        ${lembretesHtml}
      </button>
    `;
  }

  grid.innerHTML = `${htmlCabecalho}${htmlDias}`;
}

async function carregarUsuariosAtivosAgenda() {
  if (Array.isArray(agendaUsuariosAtivosCache) && agendaUsuariosAtivosCache.length > 0) {
    return agendaUsuariosAtivosCache;
  }

  const tentarCarregar = async (url) => {
    const resposta = await fetch(url, { credentials: 'include' });
    if (!resposta.ok) {
      throw new Error(`HTTP ${resposta.status}`);
    }
    const payload = await resposta.json();
    if (Array.isArray(payload?.users)) {
      return payload.users.map((username) => String(username || '').trim()).filter(Boolean);
    }
    if (Array.isArray(payload?.usuarios)) {
      return payload.usuarios.map((registro) => String(registro?.username || '').trim()).filter(Boolean);
    }
    return [];
  };

  let usuarios = [];
  try {
    usuarios = await tentarCarregar('/api/users/ativos');
  } catch (_erroUsersAtivos) {
    usuarios = await tentarCarregar('/api/usuarios/ativos');
  }

  agendaUsuariosAtivosCache = Array.from(new Set(usuarios)).sort((nomeA, nomeB) => nomeA.localeCompare(nomeB, 'pt-BR'));
  return agendaUsuariosAtivosCache;
}

